import { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { 
  doc, 
  onSnapshot, 
  setDoc, 
  updateDoc, 
  arrayUnion, 
  getDoc,
  collection,
  addDoc
} from 'firebase/firestore';
import { ScrapRecord } from '../../types/appTypes';

export const useScrapWeighing = () => {
  const [actualScrap, setActualScrap] = useState<ScrapRecord[]>([]);
  const [scrapSanons, setScrapSanons] = useState<any[]>([]);

  useEffect(() => {
    // Sledovanie aktuálneho zoznamu vážení
    const unsubActual = onSnapshot(doc(db, 'scrap', 'actualscrap'), (s) => {
      setActualScrap(s.exists() ? (s.data().items || []) : []);
    });

    // Sledovanie archívnych šanónov
    const unsubSanons = onSnapshot(collection(db, 'scrap_archives'), (s) => {
      setScrapSanons(s.docs.map(d => ({ id: d.id, ...d.data() })));
    });

    return () => { unsubActual(); unsubSanons(); };
  }, []);

  const onAddScrapRecord = async (record: ScrapRecord) => {
    await setDoc(doc(db, 'scrap', 'actualscrap'), { 
      items: arrayUnion(record) 
    }, { merge: true });
  };

  const onDeleteScrapRecord = async (id: string) => {
    const ref = doc(db, 'scrap', 'actualscrap');
    const snap = await getDoc(ref);
    if (snap.exists()) {
      const items = (snap.data().items || []) as ScrapRecord[];
      await updateDoc(ref, { items: items.filter(i => i.id !== id) });
    }
  };

  const onFinalizeScrapArchive = async (dispatchDate: string, worker: string) => {
      if (actualScrap.length === 0) return;

      const dateStr = dispatchDate.split('-').reverse().join('');
      const sanonId = `scrap_sanon_${dateStr}_${Date.now().toString().slice(-4)}`;

      const archiveDoc = {
          id: sanonId,
          dispatchDate,
          items: actualScrap,
          finalizedBy: worker,
          finalizedAt: Date.now()
      };

      // 1. Uložiť do archívu
      await setDoc(doc(db, 'scrap_archives', sanonId), archiveDoc);

      // 2. Vymazať aktuálny zoznam
      await updateDoc(doc(db, 'scrap', 'actualscrap'), { items: [] });

      return sanonId;
  };

  return {
    actualScrap, scrapSanons,
    onAddScrapRecord, onDeleteScrapRecord, onFinalizeScrapArchive
  };
};

import { useRef, useCallback, useEffect } from 'react';
import { useSystemData } from './data/useSystemData';
import { useMasterData } from './data/useMasterData';
import { useOperationsData } from './data/useOperationsData';
import { useTaskData } from './data/useTaskData';
import { useScrapData } from './data/useScrapData';
import { useScrapWeighing } from './data/useScrapWeighing';
import { Role } from '../types/appTypes';

export const useFirestoreData = (isAuthenticated: boolean, currentUserRole: string) => {

  // 1. SYSTEM DATA (Users, Roles, Notifications)
  const systemData = useSystemData();
  const { roles, onAddNotification } = systemData;

  // 2. MASTER DATA (Parts, BOM, Workplaces, Sectors, Logistics)
  const masterData = useMasterData();

  // 3. OPERATIONS DATA (Breaks, Reasons)
  const operationsData = useOperationsData();

  // 4. SCRAP DATA & WEIGHING
  const scrapData = useScrapData();
  const scrapWeighing = useScrapWeighing();

  // 5. PERMISSION HELPER (Needed for Task Data Sound Logic)
  const rolesRef = useRef<Role[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  // Optimalizovaný check priamo z objektu Role (žiadne extra čítania)
  const checkPermissionRef = useCallback((permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN') return true;

      const r = rolesRef.current.find(ro => ro.name === currentRole);
      if (!r) return false;

      // Kontrola v poli permissions (ak existuje)
      return r.permissions ? r.permissions.includes(permName) : false;
  }, []);

  // 6. TASK DATA (Depends on Auth & Permissions)
  const taskData = useTaskData(isAuthenticated, checkPermissionRef, onAddNotification);

  // 7. COMPOSE & RETURN
  return {
    ...systemData,
    ...masterData,
    ...operationsData,
    ...scrapData,
    ...scrapWeighing,
    ...taskData,
  };
};

