const ScrapWeighingTab: React.FC<ScrapWeighingTabProps> = (props) => {
  const { t, language } = useLanguage();

  // Form State
  const [selectedMetal, setSelectedMetal] = useState('');
  const [selectedBin, setSelectedBin] = useState('');
  const [gross, setGross] = useState('');
  const [tara, setTara] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Export State
  const [isExportModalOpen, setIsExportModalOpen] = useState(false);
  const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);

  // Prepočet Netto
  const netto = useMemo(() => {
    const g = parseFloat(gross) || 0;
    return Math.max(g - tara, 0);
  }, [gross, tara]);

  const handleBinChange = (binId: string) => {
    setSelectedBin(binId);
    const bin = props.bins.find(b => b.id === binId);
    setTara(bin ? bin.tara : 0);
  };

  const handleWeigh = async () => {
    if (!selectedMetal || !selectedBin || !gross) {
      alert(t('fill_all_fields'));
      return;
    }

    setIsSubmitting(true);
    try {
      // 1. Vytvoriť systémovú úlohu pre KPI (Typ: Production, Názov: Váženie šrotu)
      const metal = props.metals.find(m => m.id === selectedMetal);
      const bin = props.bins.find(b => b.id === selectedBin);

      const taskId = `scrap_${Date.now()}`;
      await props.onAddTask(
        `VÁŽENIE: ${metal?.type || 'ŠROT'}`,
        'VÁHA ŠROTU',
        netto.toString(),
        'kg',
        'NORMAL',
        false,
        `Kontajner: ${bin?.name}`,
        true
