      // 2. Uložiť záznam o vážení
      const newRecord: ScrapRecord = {
        id: crypto.randomUUID(),
        metalId: selectedMetal,
        binId: selectedBin,
        gross: parseFloat(gross),
        tara: tara,
        netto: netto,
        timestamp: Date.now(),
        worker: props.currentUser,
        taskId: taskId
      };

      await props.onAddScrapRecord(newRecord);

      // 3. Reset form
      setGross('');
      setSelectedBin('');
      setSelectedMetal('');
      setTara(0);

    } catch (e) { console.error(e); }
    finally { setIsSubmitting(false); }
  };

  const handleFinalize = async () => {
      if (!dispatchDate) return;
      const sanonId = await props.onFinalizeArchive(dispatchDate, props.currentUser);
      if (sanonId) {
