  const handleRawExport = () => {
    if (typeof XLSX === 'undefined' || props.actualScrap.length === 0) return;

    const data = props.actualScrap.map(r => {
        const metal = props.metals.find(m => m.id === r.metalId);
        const bin = props.bins.find(b => b.id === r.binId);
        return {
            "Dátum": new Date(r.timestamp).toLocaleDateString('sk-SK'),
            "Čas": new Date(r.timestamp).toLocaleTimeString('sk-SK'),
            "Skladník": props.resolveName(r.worker),
            "Typ kovu": metal?.type || '?',
            "Kontajner": bin?.name || '?',
            "Brutto (kg)": r.gross,
            "Tara (kg)": r.tara,
            "Netto (kg)": r.netto
        };
    });

    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Raw_Scrap_Data");
    XLSX.writeFile(wb, `Srot_Export_${new Date().toISOString().slice(0, 10)}.xlsx`);
