import { useState, useEffect } from 'react';
import { db } from '../../firebase';
import { 
  doc, 
  onSnapshot, 
  setDoc, 
  updateDoc, 
  arrayUnion, 
  getDoc,
  collection
} from 'firebase/firestore';
import { ScrapRecord } from '../../types/appTypes';

export const useScrapWeighing = () => {
  const [actualScrap, setActualScrap] = useState<ScrapRecord[]>([]);
  const [scrapSanons, setScrapSanons] = useState<any[]>([]);

  useEffect(() => {
    // Sledovanie archívnych šanónov
    const unsubSanons = onSnapshot(collection(db, 'scrap_archives'), (s) => {
      setScrapSanons(s.docs.map(d => ({ id: d.id, ...d.data() })));
    });

    // Sledovanie aktuálneho skladu šrotu
    const unsubActual = onSnapshot(doc(db, 'scrap', 'actualscrap'), (s) => {
      if (s.exists()) setActualScrap(s.data().items || []);
      else setActualScrap([]);
    });

    return () => { unsubSanons(); unsubActual(); };
  }, []);

  // Pridanie jedného záznamu (legacy/debug)
  const onAddScrapRecord = async (record: ScrapRecord) => {
    await setDoc(doc(db, 'scrap', 'actualscrap'), { 
      items: arrayUnion(record) 
    }, { merge: true });
  };

  // Hromadné pridanie záznamov z ukončenej relácie
  const onBulkAddScrapRecords = async (records: ScrapRecord[]) => {
    if (records.length === 0) return;
    await setDoc(doc(db, 'scrap', 'actualscrap'), { 
      items: arrayUnion(...records) 
    }, { merge: true });
  };

  const onDeleteScrapRecord = async (id: string) => {
    const ref = doc(db, 'scrap', 'actualscrap');
    const snap = await getDoc(ref);
    if (snap.exists()) {
      const items = (snap.data().items || []) as ScrapRecord[];
      await updateDoc(ref, { items: items.filter(i => i.id !== id) });
    }
  };

  const onUpdateScrapRecord = async (id: string, updates: Partial<ScrapRecord>) => {
    const ref = doc(db, 'scrap', 'actualscrap');
    const snap = await getDoc(ref);
    if (snap.exists()) {
        const items = (snap.data().items || []) as ScrapRecord[];
        const newItems = items.map(i => i.id === id ? { ...i, ...updates } : i);
        await updateDoc(ref, { items: newItems });
    }
  };

  const onUpdateArchivedScrapItem = async (sanonId: string, itemId: string, updates: Partial<ScrapRecord>) => {
    const ref = doc(db, 'scrap_archives', sanonId);
    const snap = await getDoc(ref);
    if (snap.exists()) {
        const items = (snap.data().items || []) as ScrapRecord[];
        const newItems = items.map(i => i.id === itemId ? { ...i, ...updates } : i);
        await updateDoc(ref, { items: newItems });
    }
  };

  const onExpediteScrap = async (worker: string, dispatchDate?: string) => {
      if (actualScrap.length === 0) return;

      const dateObj = dispatchDate ? new Date(dispatchDate) : new Date();
      const dd = String(dateObj.getDate()).padStart(2, '0');
      const mm = String(dateObj.getMonth() + 1).padStart(2, '0');
      const yyyy = dateObj.getFullYear();
      const timestamp = Date.now();

      // ID sanonu teraz obsahuje zvolený dátum expedície
      const sanonId = `SCRAP_SANON_${dd}${mm}${yyyy}_${String(timestamp).slice(-4)}`;

      const archiveDoc = {
          id: sanonId,
          dispatchDate: dispatchDate || dateObj.toISOString().split('T')[0],
          items: actualScrap,
          finalizedBy: worker,
          finalizedAt: timestamp
      };

      // 1. Uložiť do archívu
      await setDoc(doc(db, 'scrap_archives', sanonId), archiveDoc);

      // 2. Vymazať aktuálny sklad
      await updateDoc(doc(db, 'scrap', 'actualscrap'), { items: [] });

      return sanonId;
  };

  const onFinalizeScrapArchive = async (dispatchDate: string, worker: string, records: ScrapRecord[]) => {
      if (records.length === 0) return;

      const dateStr = dispatchDate.split('-').reverse().join('');
      const sanonId = `scrap_sanon_${dateStr}_${Date.now().toString().slice(-4)}`;

      const archiveDoc = {
          id: sanonId,
          dispatchDate,
          items: records,
          finalizedBy: worker,
          finalizedAt: Date.now()
      };

      await setDoc(doc(db, 'scrap_archives', sanonId), archiveDoc);
      return sanonId;
  };

  return {
    actualScrap, scrapSanons,
    onAddScrapRecord, onBulkAddScrapRecords, onDeleteScrapRecord, onUpdateScrapRecord, onExpediteScrap, onFinalizeScrapArchive, onUpdateArchivedScrapItem
  };
};

import React, { useState, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { ScrapRecord, ScrapBin, ScrapMetal } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

interface ScrapArchiveTabProps {
    scrapArchives: any[];
    bins: ScrapBin[];
    metals: ScrapMetal[];
    onUpdateArchivedItem: (sanonId: string, itemId: string, updates: Partial<ScrapRecord>) => Promise<void>;
    resolveName: (username?: string | null) => string;
    hasPermission: (perm: string) => boolean;
}

const Icons = {
    Archive: () => <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" /></svg>,
    Edit: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>,
    ChevronDown: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>,
    Calendar: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
};

const ScrapArchiveTab: React.FC<ScrapArchiveTabProps> = (props) => {
    const { t } = useLanguage();
    const [expandedSanonId, setExpandedSanonId] = useState<string | null>(null);
    const [editingItem, setEditingItem] = useState<{ sanonId: string, item: ScrapRecord } | null>(null);
    const [editGross, setEditGross] = useState('');
    const [editMetalId, setEditMetalId] = useState('');
    const [editBinId, setEditBinId] = useState('');

    const sortedArchives = useMemo(() => {
        return [...props.scrapArchives].sort((a, b) => {
            const dateA = new Date(a.dispatchDate).getTime();
            const dateB = new Date(b.dispatchDate).getTime();
            return dateB - dateA;
        });
    }, [props.scrapArchives]);

    const handleOpenEdit = (sanonId: string, item: ScrapRecord) => {
        setEditingItem({ sanonId, item });
        setEditGross(String(item.gross));
        setEditMetalId(item.metalId);
        setEditBinId(item.binId);
    };

    const handleSaveEdit = async () => {
        if (!editingItem) return;
        const bin = props.bins.find(b => b.id === editBinId);
        const grossVal = parseFloat(editGross) || 0;
        const taraVal = bin ? bin.tara : 0;

        await props.onUpdateArchivedItem(editingItem.sanonId, editingItem.item.id, {
            metalId: editMetalId,
            binId: editBinId,
            gross: grossVal,
            tara: taraVal,
            netto: Math.max(grossVal - taraVal, 0)
        });
        setEditingItem(null);
    };

    const labelClass = "block text-[10px] font-black text-slate-500 uppercase tracking-[0.25em] mb-2";
    const inputClass = "w-full h-14 bg-slate-900/80 border-2 border-slate-700 rounded-xl px-4 text-white text-lg font-black focus:outline-none focus:border-teal-500/50 transition-all font-mono uppercase text-center";

    return (
        <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in">
            <div className="flex items-center gap-4 mb-10">
                <div className="p-4 bg-indigo-500/20 rounded-2xl border border-indigo-500/30 text-indigo-400">
                    <Icons.Archive />
                </div>
                <div>
                    <h1 className="text-3xl font-black text-white uppercase tracking-tighter leading-none">{t('scrap_archive_title')}</h1>
                    <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-2">História expedícií a vývozov</p>
                </div>
            </div>

            <div className="space-y-4">
                {sortedArchives.length > 0 ? (
                    sortedArchives.map(archive => {
                        const isExpanded = expandedSanonId === archive.id;
                        const totalWeight = (archive.items || []).reduce((acc: number, curr: ScrapRecord) => acc + curr.netto, 0);

                        return (
                            <div key={archive.id} className="bg-slate-900/60 border border-slate-800 rounded-3xl overflow-hidden transition-all shadow-xl">
                                <button 
                                    onClick={() => setExpandedSanonId(isExpanded ? null : archive.id)}
                                    className="w-full p-6 flex flex-col md:flex-row justify-between items-center gap-6 hover:bg-white/[0.02] transition-colors"
                                >
                                    <div className="flex items-center gap-6">
                                        <div className="p-3 bg-slate-800 rounded-xl text-slate-400">
                                            <Icons.Calendar />
                                        </div>
                                        <div className="text-left">
                                            <p className="text-lg font-black text-white uppercase tracking-tight">{new Date(archive.dispatchDate).toLocaleDateString('sk-SK', { day: '2-digit', month: '2-digit', year: 'numeric' })}</p>
                                            <p className="text-[10px] font-mono text-slate-500 uppercase tracking-widest">{archive.id}</p>
                                        </div>
                                    </div>

                                    <div className="flex items-center gap-10">
                                        <div className="text-center">
                                            <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-1">HMOTNOSŤ</p>
                                            <p className="text-xl font-black text-teal-400 font-mono">{totalWeight} <span className="text-xs font-normal text-slate-600">kg</span></p>
                                        </div>
                                        <div className="text-center">
                                            <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-1">VYSTAVIL</p>
                                            <p className="text-xs font-bold text-slate-300 uppercase">{props.resolveName(archive.finalizedBy)}</p>
                                        </div>
                                        <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-teal-500' : 'text-slate-600'}`}>
                                            <Icons.ChevronDown />
                                        </div>
                                    </div>
                                </button>

                                {isExpanded && (
                                    <div className="p-6 pt-0 border-t border-slate-800/50 animate-fade-in bg-slate-950/20">
                                        <div className="overflow-x-auto custom-scrollbar">
                                            <table className="w-full text-left border-collapse">
                                                <thead>
                                                    <tr className="text-[9px] font-black text-slate-600 uppercase tracking-widest border-b border-slate-800">
                                                        <th className="py-4 px-4">Čas váženia</th>
                                                        <th className="py-4 px-4">Materiál</th>
                                                        <th className="py-4 px-4">Kontajner</th>
                                                        <th className="py-4 px-4 text-right">Netto (kg)</th>
                                                        {props.hasPermission('perm_scrap_edit') && <th className="py-4 px-4"></th>}
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-slate-800/30">
                                                    {(archive.items || []).map((item: ScrapRecord) => {
                                                        const metal = props.metals.find(m => m.id === item.metalId);
                                                        const bin = props.bins.find(b => b.id === item.binId);
                                                        return (
                                                            <tr key={item.id} className="text-sm hover:bg-white/[0.01]">
                                                                <td className="py-4 px-4 text-slate-500 font-mono">{new Date(item.timestamp).toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' })}</td>
                                                                <td className="py-4 px-4 font-bold text-slate-300 uppercase">{metal?.type || '???'}</td>
                                                                <td className="py-4 px-4 text-slate-500 uppercase">{bin?.name || '???'}</td>
                                                                <td className="py-4 px-4 text-right font-black text-white font-mono">{item.netto} kg</td>
                                                                {props.hasPermission('perm_scrap_edit') && (
                                                                    <td className="py-4 px-4 text-right">
                                                                        <button 
                                                                            onClick={() => handleOpenEdit(archive.id, item)}
                                                                            className="p-2 bg-slate-800 text-teal-500 hover:text-white hover:bg-teal-600 rounded-lg transition-all"
                                                                        >
                                                                            <Icons.Edit />
                                                                        </button>
                                                                    </td>
                                                                )}
                                                            </tr>
                                                        );
                                                    })}
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })
                ) : (
                    <div className="py-32 text-center bg-slate-900/20 rounded-[3rem] border-2 border-dashed border-slate-800">
                        <Icons.Archive />
                        <p className="mt-4 text-slate-600 font-black uppercase tracking-[0.3em] text-sm">{t('scrap_archive_empty')}</p>
                    </div>
                )}
            </div>

            {/* EDIT MODAL */}
            {editingItem && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in" onClick={() => setEditingItem(null)}>
                    <div className="bg-slate-900 border-2 border-teal-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden" onClick={e => e.stopPropagation()}>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-8 flex items-center gap-3">
                            <Icons.Edit /> UPRAVIŤ ARCHÍV
                        </h3>

                        <div className="space-y-6 mb-10">
                            <div>
                                <label className={labelClass}>{t('scrap_metal_select')}</label>
                                <select value={editMetalId} onChange={e => setEditMetalId(e.target.value)} className={inputClass}>
                                    {props.metals.map(m => <option key={m.id} value={m.id}>{m.type}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={labelClass}>{t('scrap_bin_select')}</label>
                                <select value={editBinId} onChange={e => setEditBinId(e.target.value)} className={inputClass}>
                                    {props.bins.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={labelClass}>{t('scrap_gross')}</label>
                                <input type="number" value={editGross} onChange={e => setEditGross(e.target.value)} className={`${inputClass} !text-3xl text-teal-400`} />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setEditingItem(null)} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                            <button onClick={handleSaveEdit} className="h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-xl transition-all active:scale-95">ULOŽIŤ ZMENY</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default ScrapArchiveTab;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { useLanguage } from './LanguageContext';
import AppHeader from './AppHeader';
import TabNavigator from './TabNavigator';
import ProductionEntry from './tabs/ProductionEntry';
import TaskList from './tabs/TaskList';
import BOMScreen from './tabs/BOMScreen';
import MissingItemsTab from './tabs/MissingItemsTab';
import InventoryTab from './tabs/InventoryTab';
import LogisticsCenterTab from './tabs/LogisticsCenterTab';
import MapVisualizationTab from './tabs/MapVisualizationTab';
import TransactionLogTab from './tabs/TransactionLogTab';
import ERPBlockageTab from './tabs/ERPBlockageTab';
import AnalyticsTab from './tabs/Analytics/AnalyticsTab';
import SettingsTab from './settings/SettingsTab';
import PermissionsTab from './tabs/PermissionsTab';
import PartCatalogTab from './tabs/PartCatalogTab';
import ScrapWeighingTab from './tabs/ScrapWeighingTab';
import ScrapWarehouseTab from './tabs/ScrapWarehouseTab';
import ScrapArchiveTab from './tabs/ScrapArchiveTab';
import { Task, PriorityLevel, DBItem, Role, SystemConfig, MapSector, MapObstacle, BOMComponent, PartRequest, BOMRequest, AdminNote, ERPBlockage, ScrapBin, ScrapMetal, ScrapPrice, ScrapRecord } from '../types/appTypes';

// --- MAIN DASHBOARD COMPONENT ---
interface PartSearchScreenProps {
    tasks: Task[];
    draftTasks: Task[];
    users: any[];
    roles: Role[];
    workplaces: DBItem[];
    parts: { id: string; value: string; description?: string }[];
    missingReasons: DBItem[];
    logisticsOperations: DBItem[];
    mapSectors: MapSector[];
    mapObstacles: MapObstacle[];
    bomMap: Record<string, BOMComponent[]>;
    partRequests: PartRequest[];
    bomRequests: BOMRequest[];
    adminNotes: AdminNote[];
    erpBlockages: ERPBlockage[];
    systemConfig: SystemConfig;
    isBreakActive: boolean;

    // Scrap Data
    scrapBins: ScrapBin[];
    scrapMetals: ScrapMetal[];
    scrapPrices: ScrapPrice[];
    actualScrap: ScrapRecord[];
    scrapSanons: any[];
    onAddScrapRecord: (record: ScrapRecord) => Promise<void>;
    onBulkAddScrapRecords: (records: ScrapRecord[]) => Promise<void>;
    onDeleteScrapRecord: (id: string) => Promise<void>;
    onUpdateScrapRecord: (id: string, updates: Partial<ScrapRecord>) => Promise<void>;
    onUpdateArchivedScrapItem: (sanonId: string, itemId: string, updates: Partial<ScrapRecord>) => Promise<void>;
    onExpediteScrap: (worker: string, dispatchDate: string) => Promise<string | undefined>;
    onFinalizeScrapArchive: (date: string, worker: string, items: ScrapRecord[]) => Promise<string | undefined>;

    currentUser: string;
    currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
    onLogout: () => void;

    // Task Actions
    onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean, noteOrPlate?: string, isProduction?: boolean, sourceSectorId?: string | null, targetSectorId?: string | null) => Promise<void>;
    onUpdateTask: (id: string, updates: Partial<Task>) => Promise<void>;
    onDeleteTask: (id: string) => Promise<void>;
    onToggleTask: (id: string, sectorId?: string) => Promise<void>;
    onSetInProgress: (id: string) => Promise<void>;
    onToggleBlock: (id: string) => Promise<void>;
    onToggleManualBlock: (id: string) => Promise<void>;
    onExhaustSearch: (id: string) => Promise<void>;
    onMarkAsIncorrect: (id: string) => Promise<void>;
    onAddNote: (id: string, note: string) => Promise<void>;
    onReleaseTask: (id: string) => Promise<void>;
    onStartAudit: (id: string) => Promise<void>;
    onFinishAudit: (id: string, result: 'found' | 'missing', note: string) => Promise<void>;
    onToggleMissing: (id: string, reason?: string) => Promise<void>;
    onDeleteMissingItem: (id: string) => Promise<void>;

    // User & Permission Management
    onUpdatePermission: (permissionName: string, roleName: string, hasPermission: boolean) => Promise<void>;
    onUpdateUserRole: (username: string, newRole: string) => Promise<void>;
    onAddRole: (name: string, parentId?: string, rank?: number) => Promise<void>;
    onDeleteRole: (id: string) => Promise<void>;

    // System Settings
    onUpdateSystemConfig: (config: Partial<SystemConfig>) => Promise<void>;
    onUpdateAdminKey: (oldKey: string, newKey: string) => Promise<void>;
    onToggleAdminLock: (val: boolean) => void;

    // Database Management
    onAddPart: (value: string, description?: string) => Promise<void>;
    onBatchAddParts: (vals: string[]) => Promise<void>;
    onDeletePart: (val: string) => Promise<void>;
    onDeleteAllParts: () => Promise<void>;

    onAddWorkplace: (val: string, time?: number, x?: number, y?: number) => Promise<void>;
    onUpdateWorkplace: (id: string, updates: Partial<DBItem>) => Promise<void>;
    onBatchAddWorkplaces: (vals: string[]) => Promise<void>;
    onDeleteWorkplace: (id: string) => Promise<void>;
    onDeleteAllWorkplaces: () => Promise<void>;

    onAddLogisticsOperation: (val: string, time?: number, dist?: number, x?: number, y?: number, defaultSource?: string, defaultTarget?: string) => Promise<void>;
    onUpdateLogisticsOperation: (id: string, updates: Partial<DBItem>) => Promise<void>;
    onDeleteLogisticsOperation: (id: string) => Promise<void>;
    onDeleteAllLogisticsOperations: () => Promise<void>;

    onAddMapSector: (name: string, x: number, y: number, color?: string) => Promise<void>;
    onUpdateMapSector: (id: string, updates: Partial<MapSector>) => Promise<void>;
    onDeleteMapSector: (id: string) => Promise<void>;

    onAddMapObstacle: (obs: Omit<MapObstacle, 'id'>) => Promise<void>;
    onDeleteMapObstacle: (id: string) => Promise<void>;

    onAddBOMItem: (parent: string, child: string, qty: number) => Promise<void>;
    onBatchAddBOMItems: (vals: string[]) => Promise<void>;
    onDeleteBOMItem: (parent: string, child: string) => Promise<void>;
    onDeleteAllBOMItems: () => Promise<void>;

    onAddMissingReason: (val: string) => Promise<void>;
    onDeleteMissingReason: (id: string) => Promise<void>;
    onAddBreakSchedule: (start: string, end: string) => Promise<void>;
    onDeleteBreakSchedule: (id: string) => Promise<void>;

    onAddAdminNote: (text: string, author: string) => Promise<void>;
    onDeleteAdminNote: (id: string) => Promise<void>;
    onClearAdminNotes: () => Promise<void>;

    // Maintenance & Data
    onDailyClosing: () => Promise<{ success: boolean; count: number }>;
    onWeeklyClosing: () => Promise<{ success: boolean; count: number; sanon: string }>;
    onPurgeOldTasks: () => Promise<number>;
    onExportTasksJSON: () => Promise<void>;
    onGetDocCount: () => Promise<number>;
    fetchSanons: () => Promise<any[]>;
    onRequestPart: (part: string) => Promise<boolean>;
    onRequestBOM: (parent: string) => Promise<boolean>;
    onVerifyAdminPassword: (password: string) => boolean;

    installPrompt: any;
    onInstallApp: () => void;
}

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
    const { t, language, setLanguage } = useLanguage();
    const [activeTab, setActiveTab] = useState('entry');
    const [mode, setMode] = useState<'production' | 'logistics'>('production');
    const [isFullscreen, setIsFullscreen] = useState(false);

    // Form states for adding new tasks
    const [selectedPart, setSelectedPart] = useState<string | null>(null);
    const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
    const [quantity, setQuantity] = useState('');
    const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
    const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
    const [logisticsRef, setLogisticsRef] = useState('');
    const [logisticsPlate, setLogisticsPlate] = useState('');
    const [logisticsOp, setLogisticsOp] = useState('');
    const [sourceSector, setSourceSector] = useState<string | null>(null);
    const [targetSector, setTargetSector] = useState<string | null>(null);

    // Fullscreen handling
    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen().then(() => setIsFullscreen(true)).catch(err => console.error(err));
        } else {
            if (document.exitFullscreen) {
                document.exitFullscreen().then(() => setIsFullscreen(false)).catch(err => console.error(err));
            }
        }
    };

    // Permission check memoized for children
    const hasPermission = useCallback((permName: string) => {
        if (props.currentUserRole === 'ADMIN') return true;
        const roleObj = props.roles.find(r => r.name === props.currentUserRole);
        if (!roleObj) return false;
        return roleObj.permissions ? roleObj.permissions.includes(permName) : false;
    }, [props.roles, props.currentUserRole]);

    // Name resolution memoized for performance
    const resolveName = useCallback((username?: string | null) => {
        if (!username) return '-';
        const u = props.users.find(x => x.username === username);
        return (u?.nickname || username).toUpperCase();
    }, [props.users]);

    const resetEntry = () => {
        setSelectedPart(null);
        setSelectedWorkplace(null);
        setQuantity('');
        setQuantityUnit('pcs');
        setPriority('NORMAL');
        setLogisticsRef('');
        setLogisticsPlate('');
        setLogisticsOp('');
        setSourceSector(null);
        setTargetSector(null);
    };

    const handleAddTask = async () => {
        if (mode === 'production') {
            if (!selectedPart || !selectedWorkplace || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                selectedPart,
                selectedWorkplace,
                quantity,
                quantityUnit,
                priority,
                false,
                '',
                true
            );
            resetEntry();
        } else {
            if (!logisticsRef || !logisticsOp || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                logisticsRef,
                logisticsOp,
                quantity,
                'pallet',
                priority,
                true,
                logisticsPlate,
                false,
                sourceSector,
                targetSector
            );
            resetEntry();
        }
    };

    const counts = useMemo(() => ({
        tasks: props.tasks.filter(t => !t.isDone).length,
        pendingRequests: props.partRequests.length + props.bomRequests.length,
        erpBlockages: (props.erpBlockages || []).filter(b => b.status !== 'ready').length
    }), [props.tasks, props.partRequests, props.bomRequests, props.erpBlockages]);

    return (
        <div className="flex flex-col h-screen overflow-hidden bg-gray-900">
            {/* Top UI Bar */}
            <AppHeader 
                currentUser={props.currentUser}
                currentUserRole={props.currentUserRole}
                users={props.users}
                onLogout={props.onLogout}
                language={language as any}
                setLanguage={setLanguage as any}
                t={t}
                isFullscreen={isFullscreen}
                onToggleFullscreen={toggleFullscreen}
                installPrompt={props.installPrompt}
                onInstallApp={props.onInstallApp}
                hasPermission={hasPermission}
                resolveName={resolveName}
                isBreakActive={props.isBreakActive}
            />

            {/* Application Tab Selector */}
            <TabNavigator 
                activeTab={activeTab}
                setActiveTab={setActiveTab}
                hasPermission={hasPermission}
                t={t}
                counts={counts}
                currentUserRole={props.currentUserRole}
                systemConfig={props.systemConfig}
            />

            {/* Main Application Container */}
            <main className="flex-grow overflow-y-auto custom-scrollbar p-4 sm:p-6">
                <div className="max-w-7xl mx-auto h-full">
                    {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
                        <ProductionEntry 
                            mode={mode}
                            setMode={setMode}
                            selectedPart={selectedPart}
                            setSelectedPart={setSelectedPart}
                            selectedWorkplace={selectedWorkplace}
                            setSelectedWorkplace={setSelectedWorkplace}
                            logisticsRef={logisticsRef}
                            setLogisticsRef={setLogisticsRef}
                            logisticsPlate={logisticsPlate}
                            setLogisticsPlate={setLogisticsPlate}
                            logisticsOp={logisticsOp}
                            setLogisticsOp={setLogisticsOp}
                            sourceSector={sourceSector}
                            setSourceSector={setSourceSector}
                            targetSector={targetSector}
                            setTargetSector={setTargetSector}
                            quantity={quantity}
                            setQuantity={setQuantity}
                            quantityUnit={quantityUnit}
                            setQuantityUnit={setQuantityUnit}
                            priority={priority}
                            setPriority={setPriority}
                            parts={props.parts}
                            workplaces={props.workplaces}
                            logisticsOperationsList={props.logisticsOperations}
                            mapSectors={props.mapSectors}
                            t={t}
                            language={language}
                            hasPermission={hasPermission}
                            handleAdd={handleAddTask}
                            onRequestPart={props.onRequestPart}
                        />
                    )}

                    {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
                        <TaskList 
                            currentUser={props.currentUserRole as any}
                            currentUserName={props.currentUser}
                            tasks={props.tasks}
                            missingReasons={props.missingReasons}
                            mapSectors={props.mapSectors}
                            onToggleTask={props.onToggleTask}
                            onEditTask={props.onUpdateTask}
                            onDeleteTask={props.onDeleteTask}
                            onToggleMissing={props.onToggleMissing}
                            onSetInProgress={props.onSetInProgress}
                            onToggleBlock={props.onToggleBlock}
                            onToggleManualBlock={props.onToggleManualBlock}
                            onExhaustSearch={props.onExhaustSearch}
                            onMarkAsIncorrect={props.onMarkAsIncorrect}
                            onAddNote={props.onAddNote}
                            onReleaseTask={props.onReleaseTask}
                            onAuditPart={props.onStartAudit}
                            onFinishAudit={props.onFinishAudit}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'bom' && hasPermission('perm_tab_bom') && (
                        <BOMScreen 
                            parts={props.parts}
                            workplaces={props.workplaces}
                            bomMap={props.bomMap}
                            onAddTask={props.onAddTask}
                            onRequestBOM={props.onRequestBOM}
                            t={t}
                            language={language}
                        />
                    )}

                    {activeTab === 'catalog' && hasPermission('perm_tab_catalog') && (
                        <PartCatalogTab 
                            parts={props.parts}
                            onSelectPart={(p) => { setSelectedPart(p.value); setActiveTab('entry'); }}
                        />
                    )}

                    {activeTab === 'missing' && hasPermission('perm_tab_missing') && (
                        <MissingItemsTab 
                            tasks={props.tasks}
                            onDeleteMissingItem={props.onDeleteMissingItem}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'inventory' && hasPermission('perm_tab_inventory') && (
                        <InventoryTab 
                            currentUser={props.currentUser}
                            tasks={props.tasks}
                            onAddTask={props.onAddTask}
                            onUpdateTask={props.onUpdateTask}
                            onToggleTask={props.onToggleTask}
                            onDeleteTask={props.onDeleteTask}
                            hasPermission={hasPermission}
                            parts={props.parts.map(p => p.value)}
                            onRequestPart={props.onRequestPart}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logistics' && hasPermission('perm_tab_logistics_center') && (
                        <LogisticsCenterTab 
                            tasks={props.tasks} 
                            draftTasks={props.draftTasks}
                            users={props.users}
                            fetchSanons={props.fetchSanons}
                            onDeleteTask={props.onDeleteTask} 
                            hasPermission={hasPermission} 
                            resolveName={resolveName} 
                        />
                    )}

                    {activeTab === 'scrap_weighing' && hasPermission('perm_scrap_add') && (
                        <ScrapWeighingTab 
                            currentUser={props.currentUser}
                            bins={props.scrapBins}
                            metals={props.scrapMetals}
                            prices={props.scrapPrices}
                            actualScrap={props.actualScrap}
                            scrapSanons={props.scrapSanons}
                            onAddRecord={props.onAddScrapRecord}
                            onBulkAddScrapRecords={props.onBulkAddScrapRecords}
                            onDeleteRecord={props.onDeleteScrapRecord}
                            onFinalizeArchive={props.onFinalizeScrapArchive}
                            onAddTask={props.onAddTask}
                            onUpdateTask={props.onUpdateTask}
                            onDeleteTask={props.onDeleteTask}
                            tasks={props.tasks}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'scrap_warehouse' && hasPermission('perm_scrap_list') && (
                        <ScrapWarehouseTab 
                            currentUser={props.currentUser}
                            actualScrap={props.actualScrap}
                            bins={props.scrapBins}
                            metals={props.scrapMetals}
                            onDeleteRecord={props.onDeleteScrapRecord}
                            onUpdateRecord={props.onUpdateScrapRecord}
                            onExpedite={props.onExpediteScrap}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'scrap_archive' && hasPermission('perm_scrap_archive') && (
                        <ScrapArchiveTab 
                            scrapArchives={props.scrapSanons}
                            bins={props.scrapBins}
                            metals={props.scrapMetals}
                            onUpdateArchivedItem={props.onUpdateArchivedScrapItem}
                            resolveName={resolveName}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'map' && hasPermission('perm_tab_map') && (
                        <MapVisualizationTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            workplaces={props.workplaces}
                            logisticsOperations={props.logisticsOperations}
                            mapObstacles={props.mapObstacles}
                            systemConfig={props.systemConfig}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logs' && hasPermission('perm_tab_logs') && (
                        <TransactionLogTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'erp' && hasPermission('perm_tab_erp') && (
                        <ERPBlockageTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            parts={props.parts}
                            blockages={props.erpBlockages}
                            resolveName={resolveName}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && (
                        <AnalyticsTab 
                            systemConfig={props.systemConfig}
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'settings' && hasPermission('perm_tab_settings') && (
                        <SettingsTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            installPrompt={props.installPrompt}
                            onInstallApp={props.onInstallApp}
                            systemConfig={props.systemConfig}
                            onUpdateSystemConfig={props.onUpdateSystemConfig}
                            onUpdateAdminKey={props.onUpdateAdminKey}
                            onToggleAdminLock={props.onToggleAdminLock}
                        />
                    )}

                    {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && (
                        <PermissionsTab 
                            roles={props.roles}
                            onAddRole={props.onAddRole}
                            onDeleteRole={props.onDeleteRole}
                            onUpdatePermission={props.onUpdatePermission}
                            onVerifyAdminPassword={props.onVerifyAdminPassword}
                        />
                    )}
                </div>
            </main>
        </div>
    );
};

export default PartSearchScreen;

import React, { useMemo } from 'react';
import PartSearchScreen from './components/PartSearchScreen';
import NotificationModal from './components/modals/NotificationModal';
import { useData } from './context/DataContext';
import { SystemConfig } from './types/appTypes';

interface AppAuthenticatedProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  installPrompt: any;
  onInstallApp: () => void;
}

const AppAuthenticated: React.FC<AppAuthenticatedProps> = (props) => {
  const data = useData();

  // Získanie notifikácií pre aktuálneho používateľa
  const myNotifications = useMemo(() => {
      if (!data || !data.notifications) return [];
      return data.notifications
        .filter(n => n.targetUser === props.currentUser)
        .sort((a, b) => b.timestamp - a.timestamp); // Najnovšie prvé, ale zobrazujeme ich postupne
  }, [data?.notifications, props.currentUser]);

  // Vyberieme prvú notifikáciu v rade na zobrazenie
  const activeNotification = myNotifications.length > 0 ? myNotifications[0] : null;

  const handleConfirmNotification = () => {
      if (activeNotification && data.onClearNotification) {
          data.onClearNotification(activeNotification.id);
      }
  };

  const resolveName = (username?: string | null) => {
      if (!username) return '-';
      const u = data?.users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  };

  if (!data || !data.tasks || !data.users) {
      return (
          <div className="w-full h-full flex items-center justify-center bg-gray-900">
              <p className="text-white text-xl font-bold animate-pulse">Načítavam systém...</p>
          </div>
      );
  }

  // Bezpečné funkcie (fallbacky) ak by náhodou context zlyhal
  const safeGetDocCount = (data as any).onGetDocCount || (async () => 0);
  const safePurgeOldTasks = (data as any).onPurgeOldTasks || (async () => 0);
  const safeExportTasksJSON = (data as any).onExportTasksJSON || (async () => {});
  const safeFetchArchivedTasks = (data as any).onFetchArchivedTasks || (async () => []);
  const safeVerifyAdminPassword = (data as any).onVerifyAdminPassword || ((p: string) => false);
  const safeRequestPart = (data as any).onRequestPart || (async () => false);
  const safeRequestBOM = (data as any).onRequestBOM || (async () => false);
  const safeOnDailyClosing = (data as any).onDailyClosing || (async () => ({ success: false, count: 0 }));
  const safeOnWeeklyClosing = (data as any).onWeeklyClosing || (async () => ({ success: false, count: 0, sanon: '' }));
  const safeFetchSanons = (data as any).fetchSanons || (async () => []);

  // Admin Notes functions
  const safeAdminNotes = (data as any).adminNotes || [];
  const safeAddAdminNote = (data as any).onAddAdminNote || (() => {});
  const safeDeleteAdminNote = (data as any).onDeleteAdminNote || (() => {});
  const safeClearAdminNotes = (data as any).onClearAdminNotes || (() => {});

  const partsList = data.partsMap 
    ? Object.entries(data.partsMap).map(([p, d]) => ({ id: p, value: p, description: d }))
    : [];

  return (
    <div className="w-full h-full">
        <PartSearchScreen
          {...(data as any)}
          // Action Hooks (priame prepojenie na useTaskData cez Context)
          onAddTask={data.onAddTask}
          onUpdateTask={data.onUpdateTask}
          onDeleteTask={data.onDeleteTask}
          onToggleTask={data.onToggleTask}
          onToggleBlock={data.onToggleBlock}
          onToggleManualBlock={data.onToggleManualBlock}
          onExhaustSearch={data.onExhaustSearch}
          onAddNote={data.onAddNote}
          onMarkAsIncorrect={data.onMarkAsIncorrect}
          onStartAudit={data.onStartAudit}
          onFinishAudit={data.onFinishAudit}
          onToggleMissing={data.onToggleMissing}
          onDeleteMissingItem={(id) => data.onToggleMissing(id)}

          // Scrap Weighing Lifecycle
          onFinalizeScrapArchive={data.onFinalizeScrapArchive}
          onBulkAddScrapRecords={data.onBulkAddScrapRecords}
          onUpdateScrapRecord={data.onUpdateScrapRecord}
          onUpdateArchivedScrapItem={data.onUpdateArchivedScrapItem}
          onExpediteScrap={data.onExpediteScrap}

          // Maintenance & System
          onGetDocCount={safeGetDocCount}
          onPurgeOldTasks={safePurgeOldTasks}
          onExportTasksJSON={safeExportTasksJSON}
          onFetchArchivedTasks={safeFetchArchivedTasks}
          onVerifyAdminPassword={safeVerifyAdminPassword}
          onRequestPart={safeRequestPart}
          onRequestBOM={safeRequestBOM}
          onDailyClosing={safeOnDailyClosing}
          onWeeklyClosing={safeOnWeeklyClosing}
          fetchSanons={safeFetchSanons}

          // Data
          draftTasks={data.draftTasks || []}
          settings={{ draft: { data: data.draftTasks || [] } }}
          parts={partsList}

          // Props from Parent
          currentUser={props.currentUser}
          currentUserRole={props.currentUserRole}
          onLogout={props.onLogout}
          systemConfig={props.systemConfig}
          onUpdateSystemConfig={props.onUpdateSystemConfig}
          onUpdateAdminKey={props.onUpdateAdminKey}
          onToggleAdminLock={props.onToggleAdminLock}
          installPrompt={props.installPrompt}
          onInstallApp={props.onInstallApp}

          // Admin Notes
          dbLoadWarning={false}
          adminNotes={safeAdminNotes}
          onAddAdminNote={safeAddAdminNote}
          onDeleteAdminNote={safeDeleteAdminNote}
          onClearAdminNotes={safeClearAdminNotes}
        />

        {activeNotification && (
            <NotificationModal 
                notification={activeNotification}
                onConfirm={handleConfirmNotification}
                resolveName={resolveName}
            />
        )}
    </div>
  );
};

export default AppAuthenticated;

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { TAB_CONFIG, DEFAULT_TAB_ORDER } from '../constants/uiConstants';
import { SystemConfig } from '../types/appTypes';

interface TabNavigatorProps {
  activeTab: string;
  setActiveTab: (tab: any) => void;
  hasPermission: (perm: string) => boolean;
  t: (key: any) => string;
  counts: {
    tasks: number;
    pendingRequests: number;
    erpBlockages: number;
  };
  currentUserRole?: string;
  systemConfig?: SystemConfig;
}

const TabNavigator: React.FC<TabNavigatorProps> = ({
  activeTab, setActiveTab, hasPermission, t, counts, currentUserRole, systemConfig
}) => {
  const [openMenu, setOpenMenu] = useState<string | null>(null);
  const [dropdownPos, setDropdownPos] = useState({ top: 0, right: 0 });

  const navBarRef = useRef<HTMLDivElement>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  const currentOrder = systemConfig?.tabOrder || DEFAULT_TAB_ORDER;

  const ADMIN_TAB_IDS = ['settings', 'permissions'];
  const STAT_TAB_IDS = ['map', 'analytics', 'logs'];
  const LOG_TAB_IDS = ['logistics', 'catalog']; 
  const SCRAP_TAB_IDS = ['scrap_weighing', 'scrap_warehouse', 'scrap_archive']; 
  const PARTS_TAB_IDS: string[] = []; 

  const isAdminTabActive = ADMIN_TAB_IDS.includes(activeTab);
  const isStatsTabActive = STAT_TAB_IDS.includes(activeTab);
  const isLogisticsTabActive = LOG_TAB_IDS.includes(activeTab);
  const isScrapTabActive = SCRAP_TAB_IDS.includes(activeTab);

  useEffect(() => {
    const handleGlobalClick = (e: MouseEvent) => {
        const target = e.target as HTMLElement;
        if (openMenu && !target.closest('.dropdown-trigger') && !target.closest('.portal-dropdown-content')) {
            setOpenMenu(null);
        }
    };
    const handleScroll = () => { if (navBarRef.current && openMenu) setOpenMenu(null); };

    document.addEventListener("mousedown", handleGlobalClick);
    const scrollContainer = scrollContainerRef.current;
    if (scrollContainer) scrollContainer.addEventListener('scroll', handleScroll);

    return () => {
        document.removeEventListener("mousedown", handleGlobalClick);
        if (scrollContainer) scrollContainer.removeEventListener('scroll', handleScroll);
    };
  }, [openMenu]);

  const topLevelTabIds = currentOrder.filter(id => 
    !ADMIN_TAB_IDS.includes(id) && 
    !STAT_TAB_IDS.includes(id) && 
    !LOG_TAB_IDS.includes(id) && 
    !SCRAP_TAB_IDS.includes(id) && 
    !PARTS_TAB_IDS.includes(id)
  );

  const allowedAdminTabs = TAB_CONFIG.filter(config => 
    ADMIN_TAB_IDS.includes(config.id) && (config.adminOnly ? currentUserRole === 'ADMIN' : true) && hasPermission(config.permission)
  );

  const allowedStatsTabs = TAB_CONFIG.filter(config => 
    STAT_TAB_IDS.includes(config.id) && (config.adminOnly ? currentUserRole === 'ADMIN' : true) && hasPermission(config.permission)
  );

  const allowedLogisticsTabs = TAB_CONFIG.filter(config => 
    LOG_TAB_IDS.includes(config.id) && (config.adminOnly ? currentUserRole === 'ADMIN' : true) && hasPermission(config.permission)
  );

  const allowedScrapTabs = TAB_CONFIG.filter(config => 
    SCRAP_TAB_IDS.includes(config.id) && (config.adminOnly ? currentUserRole === 'ADMIN' : true) && hasPermission(config.permission)
  );

  const handleDropdownClick = (e: React.MouseEvent, menuId: string) => {
      if (openMenu === menuId) {
          setOpenMenu(null);
          return;
      }
      const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
      setDropdownPos({
          top: rect.bottom + window.scrollY,
          right: window.innerWidth - rect.right
      });
      setOpenMenu(menuId);
  };

  const renderDropdownTrigger = (labelKey: string, menuId: string, isActive: boolean, tabs: typeof TAB_CONFIG) => {
    if (tabs.length === 0) return null;
    return (
      <button
        onClick={(e) => handleDropdownClick(e, menuId)}
        className={`dropdown-trigger flex items-center gap-1 sm:gap-2 py-3 px-2 sm:px-3 border-b-4 font-black text-sm transition-all flex-shrink-0 ${isActive ? 'border-teal-500 text-teal-400' : 'border-transparent text-gray-400 hover:text-gray-200'}`}
      >
        <span className="whitespace-nowrap uppercase tracking-tighter">{t(labelKey as any)}</span>
        <svg className={`w-4 h-4 transition-transform duration-200 ${openMenu === menuId ? 'rotate-180 text-teal-400' : 'text-gray-600'}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg>
      </button>
    );
  };

  const renderPortalMenu = (menuId: string, tabs: typeof TAB_CONFIG) => {
      if (openMenu !== menuId) return null;
      return createPortal(
          <div 
            style={{ 
                position: 'fixed', 
                top: `${dropdownPos.top + 4}px`, 
                right: `${dropdownPos.right}px`,
                zIndex: 9999 
            }}
            className="portal-dropdown-content w-56 bg-gray-900 border-2 border-slate-700 rounded-xl shadow-[0_20px_50px_rgba(0,0,0,0.5)] overflow-hidden animate-fade-in"
          >
              <div className="py-2">
                {tabs.map(config => {
                    const bKey = config.badgeKey;
                    const badgeCount = bKey ? (counts as any)[bKey] : 0;
                    return (
                        <button 
                            key={config.id} 
                            onClick={() => { setActiveTab(config.id); setOpenMenu(null); }} 
                            className={`w-full flex items-center justify-between px-4 py-3 text-left text-sm font-bold transition-all ${activeTab === config.id ? 'bg-teal-600/20 text-teal-400' : 'text-gray-400 hover:bg-slate-800 hover:text-white'}`}
                        >
                            <span className="uppercase tracking-wide">{t(config.labelKey as any)}</span>
                            {badgeCount > 0 && <span className={`text-[10px] text-white px-1.5 py-0.5 rounded-full ${config.id === 'settings' ? 'bg-red-500' : 'bg-orange-600'}`}>{badgeCount}</span>}
                        </button>
                    );
                })}
              </div>
          </div>,
          document.body
      );
  };

  return (
    <>
      <div className="bg-gray-800 border-t border-gray-700 shadow-sm z-30 sticky top-0" ref={navBarRef}>
        <div 
            ref={scrollContainerRef}
            className="max-w-7xl mx-auto w-full px-4 flex items-center overflow-x-auto no-scrollbar custom-scrollbar"
        >
          <div className="flex flex-nowrap items-center min-w-full">
            <div className="flex space-x-4 sm:space-x-6 py-1">
              {topLevelTabIds.map(tabId => {
                const config = TAB_CONFIG.find(c => c.id === tabId);
                if (!config || (config.adminOnly && currentUserRole !== 'ADMIN') || !hasPermission(config.permission)) return null;
                const bKey = config.badgeKey;
                const badgeCount = bKey ? (counts as any)[bKey] : 0;
                return (
                  <button 
                    key={config.id} 
                    onClick={() => { setActiveTab(config.id); setOpenMenu(null); }} 
                    className={`relative whitespace-nowrap py-3 px-1 border-b-4 font-bold text-sm transition-colors ${activeTab === config.id ? (config.color || 'border-teal-500 text-teal-400') : `border-transparent text-gray-400 hover:text-gray-200 hover:border-gray-500`}`}
                  >
                    {t(config.labelKey as any)}
                    {badgeCount > 0 && <span className={`ml-2 text-white text-[10px] rounded-full px-1.5 py-0.5 bg-orange-600`}>{badgeCount}</span>}
                  </button>
                );
              })}
            </div>

            <div className="ml-auto flex items-center">
                {renderDropdownTrigger('tab_logistics_group', 'logistics', isLogisticsTabActive, allowedLogisticsTabs)}
                {renderDropdownTrigger('tab_scrap_group', 'scrap', isScrapTabActive, allowedScrapTabs)}
                {renderDropdownTrigger('tab_statistics', 'stats', isStatsTabActive, allowedStatsTabs)}
                {renderDropdownTrigger('tab_administration', 'admin', isAdminTabActive, allowedAdminTabs)}
            </div>
          </div>
        </div>
      </div>

      {renderPortalMenu('logistics', allowedLogisticsTabs)}
      {renderPortalMenu('scrap', allowedScrapTabs)}
      {renderPortalMenu('stats', allowedStatsTabs)}
      {renderPortalMenu('admin', allowedAdminTabs)}
    </>
  );
};

export default TabNavigator;

import React, { useState } from 'react';
import { Role } from '../../App'; 
import { useLanguage } from '../LanguageContext';

interface PermissionsTabProps {
    roles: Role[];
    onAddRole: (name: string, parentId?: string, rank?: number) => void;
    onDeleteRole: (id: string) => void;
    onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
    onVerifyAdminPassword: (password: string) => boolean;
}

const PermissionsTab: React.FC<PermissionsTabProps> = ({ roles, onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword }) => {
    const { t, language } = useLanguage();
    const [newRoleName, setNewRoleName] = useState('');
    const [selectedParentId, setSelectedParentId] = useState('');

    const permGroups = [
      {
          name: 'perm_group_tabs',
          perms: [
              'perm_tab_entry', 
              'perm_tab_tasks', 
              'perm_tab_bom', 
              'perm_tab_catalog',
              'perm_tab_missing', 
              'perm_tab_inventory', 
              'perm_tab_logistics_center', 
              'perm_scrap_add',
              'perm_scrap_list',
              'perm_scrap_archive',
              'perm_tab_map',
              'perm_tab_logs',
              'perm_tab_erp',
              'perm_tab_analytics', 
              'perm_tab_settings', 
              'perm_tab_permissions', 
              'perm_logistics_mode'
          ] 
      },
      {
          name: 'perm_group_actions',
          perms: [
              'perm_btn_finish', 
              'perm_btn_edit', 
              'perm_btn_delete', 
              'perm_btn_resolve', 
              'perm_btn_missing', 
              'perm_scrap_edit',
              'perm_btn_copy', 
              'perm_btn_return', 
              'perm_btn_note', 
              'perm_btn_incorrect', 
              'perm_btn_lock', 
              'perm_btn_block_new', 
              'perm_btn_audit', 
              'perm_erp_manage', 
              'perm_erp_delete', 
              'perm_view_fullscreen', 
              'perm_play_sound', 
              'perm_push_notification', 
              'perm_view_passwords'
          ]
      },
      {
          name: 'perm_group_settings',
          perms: ['perm_view_setup', 'perm_settings_users', 'perm_settings_parts', 'perm_settings_wp', 'perm_settings_bom', 'perm_settings_system', 'perm_settings_maint']
      },
      {
          name: 'perm_group_mgmt',
          perms: ['perm_manage_users', 'perm_delete_users', 'perm_manage_db', 'perm_manage_logistics_ops', 'perm_manage_bom', 'perm_scrap_manage', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles'] 
      }
    ];

    const hasPermission = (role: Role, permName: string) => {
        return role.permissions ? role.permissions.includes(permName) : false;
    };

    const handleCreateRole = () => {
        if (!newRoleName.trim()) return;
        const parent = roles.find(r => r.id === selectedParentId);
        const rank = parent ? (parent.rank || 0) + 1 : 5;
        onAddRole(newRoleName, selectedParentId || undefined, rank);
        setNewRoleName('');
        setSelectedParentId('');
    };

    const canDelete = (role: Role) => !role.isSystem && role.name.toUpperCase() !== 'ADMIN';

    const handleDeleteClick = (role: Role) => {
        if (!canDelete(role)) return;
        if (window.confirm(language === 'sk' ? `Naozaj chcete vymazať rolu ${role.name}?` : `Delete role ${role.name}?`)) {
            onDeleteRole(role.id);
