                        <p>Vystavil: {props.resolveName(props.currentUser)}</p>
                    </div>
                </div>

                <table className="w-full text-left border-collapse mb-10">
                    <thead>
                        <tr className="bg-gray-100">
                            <th className="p-3 border border-black font-black uppercase text-[9pt]">Dátum váženia</th>
                            <th className="p-3 border border-black font-black uppercase text-[9pt]">Materiál</th>
                            <th className="p-3 border border-black font-black uppercase text-[9pt]">Kontajner</th>
                            <th className="p-3 border border-black font-black uppercase text-[9pt] text-right">Brutto (kg)</th>
                            <th className="p-3 border border-black font-black uppercase text-[9pt] text-right">Tara (kg)</th>
                            <th className="p-3 border border-black font-black uppercase text-[9pt] text-right">Netto (kg)</th>
                        </tr>
                    </thead>
                    <tbody>
                        {props.actualScrap.map(r => {
                            const metal = props.metals.find(m => m.id === r.metalId);
                            const bin = props.bins.find(b => b.id === r.binId);
                            return (
                                <tr key={r.id}>
                                    <td className="p-3 border border-black text-[9pt]">{new Date(r.timestamp).toLocaleDateString('sk-SK')}</td>
                                    <td className="p-3 border border-black text-[9pt] font-bold uppercase">{metal?.type || '???'}</td>
                                    <td className="p-3 border border-black text-[9pt] uppercase">{bin?.name || '???'}</td>
                                    <td className="p-3 border border-black text-[9pt] text-right">{r.gross}</td>
                                    <td className="p-3 border border-black text-[9pt] text-right">{r.tara}</td>
                                    <td className="p-3 border border-black text-[9pt] text-right font-bold">{r.netto}</td>
                                </tr>
                            );
