                    </tbody>
                    <tfoot>
                        <tr className="bg-gray-50">
                            <td colSpan={5} className="p-4 border border-black text-right font-black uppercase text-[10pt]">Celková hmotnosť netto:</td>
                            <td className="p-4 border border-black text-right font-black text-xl">{totalNetto} kg</td>
                        </tr>
                    </tfoot>
                </table>

                <div className="grid grid-cols-2 gap-20 mt-24">
