                        const displayDate = new Date(archive.dispatchDate).toLocaleDateString('sk-SK', { day: '2-digit', month: '2-digit', year: 'numeric' });

                        return (
                            <div key={archive.id} className="bg-slate-900/60 border border-slate-800 rounded-3xl overflow-hidden transition-all shadow-xl">
                                <div className="flex flex-col md:flex-row items-center w-full">
                                    <button 
                                        onClick={() => setExpandedSanonId(isExpanded ? null : archive.id)}
                                        className="flex-grow p-6 flex flex-col md:flex-row justify-between items-center gap-6 hover:bg-white/[0.02] transition-colors"
                                    >
                                        <div className="flex items-center gap-6">
                                            <div className="p-3 bg-slate-800 rounded-xl text-slate-400">
                                                <Icons.Calendar />
                                            </div>
                                            <div className="text-left">
                                                <p className="text-lg font-black text-white uppercase tracking-tight">{displayDate}</p>
                                                <p className="text-[10px] font-mono text-slate-500 uppercase tracking-widest">{archive.id}</p>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-10">
                                            <div className="text-center">
                                                <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-1">HMOTNOSŤ</p>
                                                <p className="text-xl font-black text-teal-400 font-mono">{totalWeight} <span className="text-xs font-normal text-slate-600">kg</span></p>
                                            </div>
                                            <div className="text-center">
                                                <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-1">VYSTAVIL</p>
                                                <p className="text-xs font-bold text-slate-300 uppercase">{props.resolveName(archive.finalizedBy)}</p>
                                            </div>
                                            <div className={`transition-transform duration-300 ${isExpanded ? 'rotate-180 text-teal-500' : 'text-slate-600'}`}>
                                                <Icons.ChevronDown />
                                            </div>
                                        </div>
                                    </button>

                                    <div className="p-4 md:border-l border-slate-800 flex justify-center items-center gap-2 w-full md:w-auto">
                                        <button 
                                            onClick={() => handleExportSanon(archive)}
                                            className="p-3 bg-emerald-900/20 text-emerald-500 hover:bg-emerald-500 hover:text-white rounded-xl transition-all shadow-sm"
                                            title="Export do Excelu"
                                        >
                                            <Icons.Download />
                                        </button>
                                        {props.hasPermission('perm_scrap_edit') && (
                                            <button 
                                                onClick={() => handleConfirmDeleteSanon(archive.id, displayDate)}
                                                className="p-3 bg-red-900/20 text-red-500 hover:bg-red-500 hover:text-white rounded-xl transition-all shadow-sm"
                                                title="Vymazať celý šanón"
                                            >
                                                <Icons.Trash />
                                            </button>
                                        )}
                                    </div>
                                </div>

                                {isExpanded && (
                                    <div className="p-6 pt-0 border-t border-slate-800/50 animate-fade-in bg-slate-950/20">
                                        <div className="overflow-x-auto custom-scrollbar">
                                            <table className="w-full text-left border-collapse">
                                                <thead>
                                                    <tr className="text-[9px] font-black text-slate-600 uppercase tracking-widest border-b border-slate-800">
                                                        <th className="py-4 px-4">Čas váženia</th>
                                                        <th className="py-4 px-4">Materiál</th>
                                                        <th className="py-4 px-4">Kontajner</th>
                                                        <th className="py-4 px-4 text-right">Netto (kg)</th>
                                                        {props.hasPermission('perm_scrap_edit') && <th className="py-4 px-4"></th>}
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-slate-800/30">
                                                    {(archive.items || []).map((item: ScrapRecord) => {
                                                        const metal = props.metals.find(m => m.id === item.metalId);
                                                        const bin = props.bins.find(b => b.id === item.binId);
                                                        return (
                                                            <tr key={item.id} className="text-sm hover:bg-white/[0.01] group">
                                                                <td className="py-4 px-4 text-slate-500 font-mono">{new Date(item.timestamp).toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' })}</td>
                                                                <td className="py-4 px-4 font-bold text-slate-300 uppercase">{metal?.type || '???'}</td>
                                                                <td className="py-4 px-4 text-slate-500 uppercase">{bin?.name || '???'}</td>
                                                                <td className="py-4 px-4 text-right font-black text-white font-mono">{item.netto} kg</td>
                                                                {props.hasPermission('perm_scrap_edit') && (
                                                                    <td className="py-4 px-4 text-right">
                                                                        <div className="flex gap-2 justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                                                                            <button 
                                                                                onClick={() => handleOpenEdit(archive.id, item)}
                                                                                className="p-2 bg-slate-800 text-teal-500 hover:text-white hover:bg-teal-600 rounded-lg transition-all"
                                                                            >
                                                                                <Icons.Edit />
                                                                            </button>
                                                                            <button 
                                                                                onClick={() => handleConfirmDeleteItem(archive.id, item.id)}
                                                                                className="p-2 bg-slate-800 text-red-500 hover:text-white hover:bg-red-600 rounded-lg transition-all"
                                                                            >
                                                                                <Icons.Trash />
                                                                            </button>
                                                                        </div>
                                                                    </td>
                                                                )}
                                                            </tr>
                                                        );
                                                    })}
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })
                ) : (
                    <div className="py-32 text-center bg-slate-900/20 rounded-[3rem] border-2 border-dashed border-slate-800">
                        <Icons.Archive />
                        <p className="mt-4 text-slate-600 font-black uppercase tracking-[0.3em] text-sm">{t('scrap_archive_empty')}</p>
                    </div>
                )}
            </div>

            {/* EDIT MODAL */}
            {editingItem && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in" onClick={() => setEditingItem(null)}>
                    <div className="bg-slate-900 border-2 border-teal-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden" onClick={e => e.stopPropagation()}>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-8 flex items-center gap-3">
                            <Icons.Edit /> UPRAVIŤ ARCHÍV
                        </h3>

                        <div className="space-y-6 mb-10">
                            <div>
                                <label className={labelClass}>{t('scrap_metal_select')}</label>
                                <select value={editMetalId} onChange={e => setEditMetalId(e.target.value)} className={inputClass}>
                                    {props.metals.map(m => <option key={m.id} value={m.id}>{m.type}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={labelClass}>{t('scrap_bin_select')}</label>
                                <select value={editBinId} onChange={e => setEditBinId(e.target.value)} className={inputClass}>
                                    {props.bins.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={labelClass}>{t('scrap_gross')}</label>
                                <input type="number" value={editGross} onChange={e => setEditGross(e.target.value)} className={`${inputClass} !text-3xl text-teal-400`} />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setEditingItem(null)} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                            <button onClick={handleSaveEdit} className="h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-xl transition-all active:scale-95">ULOŽIŤ ZMENY</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default ScrapArchiveTab;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { useLanguage } from './LanguageContext';
import AppHeader from './AppHeader';
import TabNavigator from './TabNavigator';
import ProductionEntry from './tabs/ProductionEntry';
import TaskList from './tabs/TaskList';
import BOMScreen from './tabs/BOMScreen';
import MissingItemsTab from './tabs/MissingItemsTab';
import InventoryTab from './tabs/InventoryTab';
import LogisticsCenterTab from './tabs/LogisticsCenterTab';
import MapVisualizationTab from './tabs/MapVisualizationTab';
import TransactionLogTab from './tabs/TransactionLogTab';
import ERPBlockageTab from './tabs/ERPBlockageTab';
import AnalyticsTab from './tabs/Analytics/AnalyticsTab';
import SettingsTab from './settings/SettingsTab';
import PermissionsTab from './tabs/PermissionsTab';
import PartCatalogTab from './tabs/PartCatalogTab';
import ScrapWeighingTab from './tabs/ScrapWeighingTab';
import ScrapWarehouseTab from './tabs/ScrapWarehouseTab';
import ScrapArchiveTab from './tabs/ScrapArchiveTab';
import { Task, PriorityLevel, DBItem, Role, SystemConfig, MapSector, MapObstacle, BOMComponent, PartRequest, BOMRequest, AdminNote, ERPBlockage, ScrapBin, ScrapMetal, ScrapPrice, ScrapRecord } from '../types/appTypes';

// --- MAIN DASHBOARD COMPONENT ---
interface PartSearchScreenProps {
    tasks: Task[];
    draftTasks: Task[];
    users: any[];
    roles: Role[];
    workplaces: DBItem[];
    parts: { id: string; value: string; description?: string }[];
    missingReasons: DBItem[];
    logisticsOperations: DBItem[];
    mapSectors: MapSector[];
    mapObstacles: MapObstacle[];
    bomMap: Record<string, BOMComponent[]>;
    partRequests: PartRequest[];
    bomRequests: BOMRequest[];
    adminNotes: AdminNote[];
    erpBlockages: ERPBlockage[];
    systemConfig: SystemConfig;
    isBreakActive: boolean;

    // Scrap Data
    scrapBins: ScrapBin[];
    scrapMetals: ScrapMetal[];
    scrapPrices: ScrapPrice[];
    actualScrap: ScrapRecord[];
    scrapSanons: any[];
    onAddScrapRecord: (record: ScrapRecord) => Promise<void>;
    onBulkAddScrapRecords: (records: ScrapRecord[]) => Promise<void>;
    onDeleteScrapRecord: (id: string) => Promise<void>;
    onUpdateScrapRecord: (id: string, updates: Partial<ScrapRecord>) => Promise<void>;
    onUpdateArchivedScrapItem: (sanonId: string, itemId: string, updates: Partial<ScrapRecord>) => Promise<void>;
    onDeleteArchivedScrapItem: (sanonId: string, itemId: string) => Promise<void>;
    onDeleteScrapArchive: (id: string) => Promise<void>;
    onExpediteScrap: (worker: string, dispatchDate: string) => Promise<string | undefined>;
    onFinalizeScrapArchive: (date: string, worker: string, items: ScrapRecord[]) => Promise<string | undefined>;

    currentUser: string;
    currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
    onLogout: () => void;

    // Task Actions
    onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean, noteOrPlate?: string, isProduction?: boolean, sourceSectorId?: string | null, targetSectorId?: string | null) => Promise<void>;
    onUpdateTask: (id: string, updates: Partial<Task>) => Promise<void>;
    onDeleteTask: (id: string) => Promise<void>;
    onToggleTask: (id: string, sectorId?: string) => Promise<void>;
    onSetInProgress: (id: string) => Promise<void>;
    onToggleBlock: (id: string) => Promise<void>;
    onToggleManualBlock: (id: string) => Promise<void>;
    onExhaustSearch: (id: string) => Promise<void>;
    onMarkAsIncorrect: (id: string) => Promise<void>;
    onAddNote: (id: string, note: string) => Promise<void>;
    onReleaseTask: (id: string) => Promise<void>;
    onStartAudit: (id: string) => Promise<void>;
    onFinishAudit: (id: string, result: 'found' | 'missing', note: string) => Promise<void>;
    onToggleMissing: (id: string, reason?: string) => Promise<void>;
    onDeleteMissingItem: (id: string) => Promise<void>;

    // User & Permission Management
    onUpdatePermission: (permissionName: string, roleName: string, hasPermission: boolean) => Promise<void>;
    onUpdateUserRole: (username: string, newRole: string) => Promise<void>;
    onAddRole: (name: string, parentId?: string, rank?: number) => Promise<void>;
    onDeleteRole: (id: string) => Promise<void>;

    // System Settings
    onUpdateSystemConfig: (config: Partial<SystemConfig>) => Promise<void>;
    onUpdateAdminKey: (oldKey: string, newKey: string) => Promise<void>;
    onToggleAdminLock: (val: boolean) => void;

    // Database Management
    onAddPart: (value: string, description?: string) => Promise<void>;
    onBatchAddParts: (vals: string[]) => Promise<void>;
    onDeletePart: (val: string) => Promise<void>;
    onDeleteAllParts: () => Promise<void>;

    onAddWorkplace: (val: string, time?: number, x?: number, y?: number) => Promise<void>;
    onUpdateWorkplace: (id: string, updates: Partial<DBItem>) => Promise<void>;
    onBatchAddWorkplaces: (vals: string[]) => Promise<void>;
    onDeleteWorkplace: (id: string) => Promise<void>;
    onDeleteAllWorkplaces: () => Promise<void>;

    onAddLogisticsOperation: (val: string, time?: number, dist?: number, x?: number, y?: number, defaultSource?: string, defaultTarget?: string) => Promise<void>;
    onUpdateLogisticsOperation: (id: string, updates: Partial<DBItem>) => Promise<void>;
    onDeleteLogisticsOperation: (id: string) => Promise<void>;
    onDeleteAllLogisticsOperations: () => Promise<void>;

    onAddMapSector: (name: string, x: number, y: number, color?: string) => Promise<void>;
    onUpdateMapSector: (id: string, updates: Partial<MapSector>) => Promise<void>;
    onDeleteMapSector: (id: string) => Promise<void>;

    onAddMapObstacle: (obs: Omit<MapObstacle, 'id'>) => Promise<void>;
    onDeleteMapObstacle: (id: string) => Promise<void>;

    onAddBOMItem: (parent: string, child: string, qty: number) => Promise<void>;
    onBatchAddBOMItems: (vals: string[]) => Promise<void>;
    onDeleteBOMItem: (parent: string, child: string) => Promise<void>;
    onDeleteAllBOMItems: () => Promise<void>;

    onAddMissingReason: (val: string) => Promise<void>;
    onDeleteMissingReason: (id: string) => Promise<void>;
    onAddBreakSchedule: (start: string, end: string) => Promise<void>;
    onDeleteBreakSchedule: (id: string) => Promise<void>;

    onAddAdminNote: (text: string, author: string) => Promise<void>;
    onDeleteAdminNote: (id: string) => Promise<void>;
    onClearAdminNotes: () => Promise<void>;

    // Maintenance & Data
    onDailyClosing: () => Promise<{ success: boolean; count: number }>;
    onWeeklyClosing: () => Promise<{ success: boolean; count: number; sanon: string }>;
    onPurgeOldTasks: () => Promise<number>;
    onExportTasksJSON: () => Promise<void>;
    onGetDocCount: () => Promise<number>;
    fetchSanons: () => Promise<any[]>;
    onRequestPart: (part: string) => Promise<boolean>;
    onRequestBOM: (parent: string) => Promise<boolean>;
    onVerifyAdminPassword: (password: string) => boolean;

    installPrompt: any;
    onInstallApp: () => void;
}

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
    const { t, language, setLanguage } = useLanguage();
    const [activeTab, setActiveTab] = useState('entry');
    const [mode, setMode] = useState<'production' | 'logistics'>('production');
    const [isFullscreen, setIsFullscreen] = useState(false);

    // Form states for adding new tasks
    const [selectedPart, setSelectedPart] = useState<string | null>(null);
    const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
    const [quantity, setQuantity] = useState('');
    const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
    const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
    const [logisticsRef, setLogisticsRef] = useState('');
    const [logisticsPlate, setLogisticsPlate] = useState('');
    const [logisticsOp, setLogisticsOp] = useState('');
    const [sourceSector, setSourceSector] = useState<string | null>(null);
    const [targetSector, setTargetSector] = useState<string | null>(null);

    // Fullscreen handling
    const toggleFullscreen = () => {
        if (!document.fullscreenElement) {
            document.documentElement.requestFullscreen().then(() => setIsFullscreen(true)).catch(err => console.error(err));
        } else {
            if (document.exitFullscreen) {
                document.exitFullscreen().then(() => setIsFullscreen(false)).catch(err => console.error(err));
            }
        }
    };

    // Permission check memoized for children
    const hasPermission = useCallback((permName: string) => {
        if (props.currentUserRole === 'ADMIN') return true;
        const roleObj = props.roles.find(r => r.name === props.currentUserRole);
        if (!roleObj) return false;
        return roleObj.permissions ? roleObj.permissions.includes(permName) : false;
    }, [props.roles, props.currentUserRole]);

    // Name resolution memoized for performance
    const resolveName = useCallback((username?: string | null) => {
        if (!username) return '-';
        const u = props.users.find(x => x.username === username);
        return (u?.nickname || username).toUpperCase();
    }, [props.users]);

    const resetEntry = () => {
        setSelectedPart(null);
        setSelectedWorkplace(null);
        setQuantity('');
        setQuantityUnit('pcs');
        setPriority('NORMAL');
        setLogisticsRef('');
        setLogisticsPlate('');
        setLogisticsOp('');
        setSourceSector(null);
        setTargetSector(null);
    };

    const handleAddTask = async () => {
        if (mode === 'production') {
            if (!selectedPart || !selectedWorkplace || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                selectedPart,
                selectedWorkplace,
                quantity,
                quantityUnit,
                priority,
                false,
                '',
                true
            );
            resetEntry();
        } else {
            if (!logisticsRef || !logisticsOp || !quantity) {
                alert(t('fill_all_fields'));
                return;
            }
            await props.onAddTask(
                logisticsRef,
                logisticsOp,
                quantity,
                quantityUnit,
                priority,
                true,
                logisticsPlate,
                false,
                sourceSector,
                targetSector
            );
            resetEntry();
        }
    };

    const counts = useMemo(() => ({
        tasks: props.tasks.filter(t => !t.isDone).length,
        pendingRequests: props.partRequests.length + props.bomRequests.length,
        erpBlockages: (props.erpBlockages || []).filter(b => b.status !== 'ready').length
    }), [props.tasks, props.partRequests, props.bomRequests, props.erpBlockages]);

    return (
        <div className="flex flex-col h-screen overflow-hidden bg-gray-900">
            {/* Top UI Bar */}
            <AppHeader 
                currentUser={props.currentUser}
                currentUserRole={props.currentUserRole}
                users={props.users}
                onLogout={props.onLogout}
                language={language as any}
                setLanguage={setLanguage as any}
                t={t}
                isFullscreen={isFullscreen}
                onToggleFullscreen={toggleFullscreen}
                installPrompt={props.installPrompt}
                onInstallApp={props.onInstallApp}
                hasPermission={hasPermission}
                resolveName={resolveName}
                isBreakActive={props.isBreakActive}
            />

            {/* Application Tab Selector */}
            <TabNavigator 
                activeTab={activeTab}
                setActiveTab={setActiveTab}
                hasPermission={hasPermission}
                t={t}
                counts={counts}
                currentUserRole={props.currentUserRole}
                systemConfig={props.systemConfig}
            />

            {/* Main Application Container */}
            <main className="flex-grow overflow-y-auto custom-scrollbar p-4 sm:p-6">
                <div className="max-w-7xl mx-auto h-full">
                    {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
                        <ProductionEntry 
                            mode={mode}
                            setMode={setMode}
                            selectedPart={selectedPart}
                            setSelectedPart={setSelectedPart}
                            selectedWorkplace={selectedWorkplace}
                            setSelectedWorkplace={setSelectedWorkplace}
                            logisticsRef={logisticsRef}
                            setLogisticsRef={setLogisticsRef}
                            logisticsPlate={logisticsPlate}
                            setLogisticsPlate={setLogisticsPlate}
                            logisticsOp={logisticsOp}
                            setLogisticsOp={setLogisticsOp}
                            sourceSector={sourceSector}
                            setSourceSector={setSourceSector}
                            targetSector={targetSector}
                            setTargetSector={setTargetSector}
                            quantity={quantity}
                            setQuantity={setQuantity}
                            quantityUnit={quantityUnit}
                            setQuantityUnit={setQuantityUnit}
                            priority={priority}
                            setPriority={setPriority}
                            parts={props.parts}
                            workplaces={props.workplaces}
                            logisticsOperationsList={props.logisticsOperations}
                            mapSectors={props.mapSectors}
                            t={t}
                            language={language}
                            hasPermission={hasPermission}
                            handleAdd={handleAddTask}
                            onRequestPart={props.onRequestPart}
                        />
                    )}

                    {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
                        <TaskList 
                            currentUser={props.currentUserRole as any}
                            currentUserName={props.currentUser}
                            tasks={props.tasks}
                            missingReasons={props.missingReasons}
                            mapSectors={props.mapSectors}
                            onToggleTask={props.onToggleTask}
                            onEditTask={props.onUpdateTask}
                            onDeleteTask={props.onDeleteTask}
                            onToggleMissing={props.onToggleMissing}
                            onSetInProgress={props.onSetInProgress}
                            onToggleBlock={props.onToggleBlock}
                            onToggleManualBlock={props.onToggleManualBlock}
                            onExhaustSearch={props.onExhaustSearch}
                            onMarkAsIncorrect={props.onMarkAsIncorrect}
                            onAddNote={props.onAddNote}
                            onReleaseTask={props.onReleaseTask}
                            onAuditPart={props.onStartAudit}
                            onFinishAudit={props.onFinishAudit}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'bom' && hasPermission('perm_tab_bom') && (
                        <BOMScreen 
                            parts={props.parts}
                            workplaces={props.workplaces}
                            bomMap={props.bomMap}
                            onAddTask={props.onAddTask}
                            onRequestBOM={props.onRequestBOM}
                            t={t}
                            language={language}
                        />
                    )}

                    {activeTab === 'catalog' && hasPermission('perm_tab_catalog') && (
                        <PartCatalogTab 
                            parts={props.parts}
                            onSelectPart={(p) => { setSelectedPart(p.value); setActiveTab('entry'); }}
                        />
                    )}

                    {activeTab === 'missing' && hasPermission('perm_tab_missing') && (
                        <MissingItemsTab 
                            tasks={props.tasks}
                            onDeleteMissingItem={props.onDeleteMissingItem}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'inventory' && hasPermission('perm_tab_inventory') && (
                        <InventoryTab 
                            currentUser={props.currentUser}
                            tasks={props.tasks}
                            onAddTask={props.onAddTask}
                            onUpdateTask={props.onUpdateTask}
                            onToggleTask={props.onToggleTask}
                            onDeleteTask={props.onDeleteTask}
                            hasPermission={hasPermission}
                            parts={props.parts.map(p => p.value)}
                            onRequestPart={props.onRequestPart}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logistics' && hasPermission('perm_tab_logistics_center') && (
                        <LogisticsCenterTab 
                            tasks={props.tasks} 
                            draftTasks={props.draftTasks}
                            users={props.users}
                            fetchSanons={props.fetchSanons}
                            onDeleteTask={props.onDeleteTask} 
                            hasPermission={hasPermission} 
                            resolveName={resolveName} 
                        />
                    )}

                    {activeTab === 'scrap_weighing' && hasPermission('perm_scrap_add') && (
                        <ScrapWeighingTab 
                            currentUser={props.currentUser}
                            bins={props.scrapBins}
                            metals={props.scrapMetals}
                            prices={props.scrapPrices}
                            actualScrap={props.actualScrap}
                            scrapSanons={props.scrapSanons}
                            onAddRecord={props.onAddScrapRecord}
                            onBulkAddScrapRecords={props.onBulkAddScrapRecords}
                            onDeleteRecord={props.onDeleteScrapRecord}
                            onFinalizeArchive={props.onFinalizeScrapArchive}
                            onAddTask={props.onAddTask}
                            onUpdateTask={props.onUpdateTask}
                            onDeleteTask={props.onDeleteTask}
                            tasks={props.tasks}
                            hasPermission={hasPermission}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'scrap_warehouse' && hasPermission('perm_scrap_list') && (
                        <ScrapWarehouseTab 
                            currentUser={props.currentUser}
                            actualScrap={props.actualScrap}
                            bins={props.scrapBins}
                            metals={props.scrapMetals}
                            onDeleteRecord={props.onDeleteScrapRecord}
                            onUpdateRecord={props.onUpdateScrapRecord}
                            onExpedite={props.onExpediteScrap}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'scrap_archive' && hasPermission('perm_scrap_archive') && (
                        <ScrapArchiveTab 
                            scrapArchives={props.scrapSanons}
                            bins={props.scrapBins}
                            metals={props.scrapMetals}
                            onUpdateArchivedItem={props.onUpdateArchivedScrapItem}
                            onDeleteArchivedItem={props.onDeleteArchivedScrapItem}
                            onDeleteArchive={props.onDeleteScrapArchive}
                            resolveName={resolveName}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'map' && hasPermission('perm_tab_map') && (
                        <MapVisualizationTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            workplaces={props.workplaces}
                            logisticsOperations={props.logisticsOperations}
                            mapObstacles={props.mapObstacles}
                            systemConfig={props.systemConfig}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'logs' && hasPermission('perm_tab_logs') && (
                        <TransactionLogTab 
                            tasks={props.tasks}
                            draftTasks={props.draftTasks}
                            fetchSanons={props.fetchSanons}
                            users={props.users}
                            mapSectors={props.mapSectors}
                            resolveName={resolveName}
                        />
                    )}

                    {activeTab === 'erp' && hasPermission('perm_tab_erp') && (
                        <ERPBlockageTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            parts={props.parts}
                            blockages={props.erpBlockages}
                            resolveName={resolveName}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && (
                        <AnalyticsTab 
                            systemConfig={props.systemConfig}
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            hasPermission={hasPermission}
                        />
                    )}

                    {activeTab === 'settings' && hasPermission('perm_tab_settings') && (
                        <SettingsTab 
                            currentUser={props.currentUser}
                            currentUserRole={props.currentUserRole}
                            installPrompt={props.installPrompt}
                            onInstallApp={props.onInstallApp}
                            systemConfig={props.systemConfig}
                            onUpdateSystemConfig={props.onUpdateSystemConfig}
                            onUpdateAdminKey={props.onUpdateAdminKey}
                            onToggleAdminLock={props.onToggleAdminLock}
                        />
                    )}

                    {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && (
                        <PermissionsTab 
                            roles={props.roles}
                            onAddRole={props.onAddRole}
                            onDeleteRole={props.onDeleteRole}
                            onUpdatePermission={props.onUpdatePermission}
                            onVerifyAdminPassword={props.onVerifyAdminPassword}
                        />
                    )}
                </div>
            </main>
        </div>
    );
};

export default PartSearchScreen;

import React, { useState, useMemo, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { ScrapRecord, ScrapBin, ScrapMetal } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

interface ScrapWarehouseTabProps {
    currentUser: string;
    actualScrap: ScrapRecord[];
    bins: ScrapBin[];
    metals: ScrapMetal[];
    onDeleteRecord: (id: string) => Promise<void>;
    onUpdateRecord: (id: string, updates: Partial<ScrapRecord>) => Promise<void>;
    onExpedite: (worker: string, dispatchDate: string) => Promise<string | undefined>;
    resolveName: (username?: string | null) => string;
}

declare var jspdf: any;

const Icons = {
    Dispatch: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>,
    Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
    Edit: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>,
    Box: () => <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>,
    FileText: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>,
    Alert: () => <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>,
    Check: () => <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>,
};

const ScrapWarehouseTab: React.FC<ScrapWarehouseTabProps> = (props) => {
    const { t, language } = useLanguage();

    // State pre modaly
    const [isExpediteModalOpen, setIsExpediteModalOpen] = useState(false);
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);
    const [isDeliveryNoteModalOpen, setIsDeliveryNoteModalOpen] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isDeliveryNoteGenerated, setIsDeliveryNoteGenerated] = useState(false);

    // State pre expedíciu
    const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);

    // State pre editáciu
    const [editingItem, setEditingItem] = useState<ScrapRecord | null>(null);
    const [editGross, setEditGross] = useState('');
    const [editMetalId, setEditMetalId] = useState('');
    const [editBinId, setEditBinId] = useState('');

    // Reset stavu vygenerovaného listu pri zmene obsahu skladu
    useEffect(() => {
        setIsDeliveryNoteGenerated(false);
    }, [props.actualScrap.length]);

    const handleOpenEdit = (item: ScrapRecord) => {
        setEditingItem(item);
        setEditGross(String(item.gross ?? '0'));
        setEditMetalId(item.metalId || '');
        setEditBinId(item.binId || '');
        setIsEditModalOpen(true);
    };

    const handleSaveEdit = async () => {
        if (!editingItem || !editGross || !editMetalId || !editBinId) return;

        const bin = props.bins.find(b => b.id === editBinId);
        const grossVal = parseFloat(editGross) || 0;
        const taraVal = bin ? bin.tara : 0;

        await props.onUpdateRecord(editingItem.id, {
            metalId: editMetalId,
            binId: editBinId,
            gross: grossVal,
            tara: taraVal,
            netto: Math.max(grossVal - taraVal, 0)
        });

        setIsEditModalOpen(false);
        setEditingItem(null);
    };

    const confirmDeliveryNote = () => {
        if (props.actualScrap.length === 0 || typeof jspdf === 'undefined') return;

        const { jsPDF } = jspdf;
        const doc = new jsPDF();

        // 1. Hlavička
        doc.setFontSize(22);
        doc.setTextColor(0, 0, 0);
        doc.setFont("helvetica", "bold");
        doc.text("CLAMASON SLOVAKIA", 20, 25);

        doc.setFontSize(12);
        doc.text("DODACI LIST - KOVOVY ODPAD", 20, 32);

        // 2. Info blok
        doc.setFontSize(10);
        doc.setFont("helvetica", "normal");
        const dateStr = new Date().toLocaleDateString('sk-SK');
        const timeStr = new Date().toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' });
        doc.text(`Datum vystavenia: ${dateStr}`, 140, 25);
        doc.text(`Cas vystavenia: ${timeStr}`, 140, 30);
        doc.text(`Vystavil: ${props.resolveName(props.currentUser)}`, 140, 35);

        doc.setLineWidth(0.5);
        doc.line(20, 40, 190, 40);

        // 3. Tabuľka dát
        const tableBody = props.actualScrap.map(r => {
            const metal = props.metals.find(m => m.id === r.metalId);
            const bin = props.bins.find(b => b.id === r.binId);
            return [
                new Date(r.timestamp).toLocaleDateString('sk-SK'),
                metal?.type || '???',
                bin?.name || '???',
                r.gross.toString(),
                r.tara.toString(),
                r.netto.toString()
            ];
        });

        (doc as any).autoTable({
            startY: 50,
            head: [['Datum vazenia', 'Material', 'Kontajner', 'Brutto (kg)', 'Tara (kg)', 'Netto (kg)']],
            body: tableBody,
            theme: 'grid',
            headStyles: { fillColor: [240, 240, 240], textColor: [0, 0, 0], fontStyle: 'bold' },
            styles: { fontSize: 9, cellPadding: 3 },
            columnStyles: {
                3: { halign: 'right' },
                4: { halign: 'right' },
                5: { halign: 'right', fontStyle: 'bold' }
            }
        });

        let finalY = (doc as any).lastAutoTable.finalY || 70;

        // --- KONTROLA PRETEČENIA (Multi-page logic) ---
        if (finalY > 180) { 
            doc.addPage();
            finalY = 20; 
        }

        // 4. Sumár
        const totalGross = props.actualScrap.reduce((acc, curr) => acc + curr.gross, 0);
        const itemCount = props.actualScrap.length;

        doc.setFontSize(11);
        doc.setFont("helvetica", "bold");
        doc.setTextColor(0, 0, 0);

        doc.text(`CELKOVA HMOTNOST BRUTO: ${totalGross} kg`, 20, finalY + 15);
        doc.text(`POCET POLOZIEK: ${itemCount}`, 20, finalY + 22);
        doc.text(`DATUM EXPEDICIE: ...........................................`, 20, finalY + 35);

        // 5. Podpisy
        const signatureY = finalY + 95;
        doc.setLineWidth(0.2);
        doc.line(20, signatureY, 80, signatureY);
        doc.line(120, signatureY, 180, signatureY);

        doc.setFontSize(8);
        doc.setFont("helvetica", "normal");
        doc.text("Odovzdal (Clamason Slovakia)", 30, signatureY + 5);
        doc.text("Prevzal (Dopravca)", 135, signatureY + 5);

        // 6. Finálna pätička s číslovaním strán
        const totalPages = doc.internal.getNumberOfPages();
        for (let i = 1; i <= totalPages; i++) {
            doc.setPage(i);
            doc.setFontSize(8);
            doc.setTextColor(150, 150, 150);
            doc.text("Vygenerovane systemom Clamason Task Manager Intelligence", 105, 285, { align: 'center' });
            doc.text(`Strana ${i} / ${totalPages}`, 190, 285, { align: 'right' });
        }

        // 7. Uloženie
        doc.save(`Dodaci_list_srot_${new Date().toISOString().split('T')[0]}.pdf`);

        setIsDeliveryNoteGenerated(true);
        setIsDeliveryNoteModalOpen(false);
    };

    const handleExpediteConfirm = async () => {
        if (!dispatchDate) {
            alert(language === 'sk' ? "Vyberte dátum expedície." : "Select dispatch date.");
            return;
        }
        setIsSubmitting(true);
        try {
            const sanonId = await props.onExpedite(props.currentUser, dispatchDate);
            if (sanonId) {
                alert(language === 'sk' ? `Expedícia úspešná. Archív: ${sanonId}` : `Expedition successful. Archive: ${sanonId}`);
                setIsExpediteModalOpen(false);
                setIsDeliveryNoteGenerated(false);
            }
        } catch (e) {
            alert("Chyba pri expedícii.");
        } finally {
            setIsSubmitting(false);
        }
    };

    const totalNetto = useMemo(() => props.actualScrap.reduce((acc, curr) => acc + curr.netto, 0), [props.actualScrap]);

    const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-3xl p-6 shadow-2xl backdrop-blur-sm relative overflow-hidden";
    const labelClass = "block text-[10px] font-black text-slate-500 uppercase tracking-[0.25em] mb-2";
    const inputClass = "w-full h-14 bg-slate-900/80 border-2 border-slate-700 rounded-xl px-4 text-white text-lg font-black focus:outline-none focus:border-teal-500/50 transition-all font-mono uppercase text-center";

    return (
        <div className="max-w-7xl mx-auto space-y-8 animate-fade-in pb-20">

            {/* UI HEADER AREA */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 no-print">
                <div>
                    <h1 className="text-3xl font-black text-white uppercase tracking-tighter leading-none">{t('scrap_warehouse_title')}</h1>
                    <div className="flex items-center gap-3 mt-3">
                        <span className="bg-indigo-500/20 text-indigo-400 text-[9px] font-black px-3 py-1 rounded-full border border-indigo-500/30 uppercase tracking-widest">AKTUÁLNY SKLAD</span>
                        <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">Položiek: <span className="text-white">{props.actualScrap.length}</span></p>
                    </div>
                </div>

                <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
                    {/* BUTTON: DELIVERY NOTE (PDF) */}
                    <button 
                        disabled={props.actualScrap.length === 0}
                        onClick={() => setIsDeliveryNoteModalOpen(true)}
                        className="w-full sm:w-auto h-14 px-10 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-30 disabled:cursor-not-allowed text-white rounded-2xl font-black text-sm uppercase tracking-widest border-b-4 border-emerald-900 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3"
                    >
                        <Icons.FileText /> {t('scrap_btn_delivery_note')}
                    </button>

                    {/* BUTTON: EXPEDITE */}
                    <button 
                        disabled={props.actualScrap.length === 0 || !isDeliveryNoteGenerated}
                        onClick={() => setIsExpediteModalOpen(true)}
                        className={`w-full sm:w-auto h-14 px-10 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-30 disabled:cursor-not-allowed text-white rounded-2xl font-black text-sm uppercase tracking-widest border-b-4 border-indigo-900 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 ${!isDeliveryNoteGenerated && props.actualScrap.length > 0 ? 'ring-2 ring-indigo-500 ring-offset-4 ring-offset-gray-900 animate-pulse' : ''}`}
                    >
                        <Icons.Dispatch /> {t('scrap_btn_dispatch')}
                    </button>
                </div>
            </div>

            {/* LIST AREA */}
            <div className={`${cardClass} no-print`}>
                <div className="overflow-x-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-950/50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b border-slate-800">
                                <th className="p-4">Dátum / Čas</th>
                                <th className="p-4">Skladník</th>
                                <th className="p-4">Typ kovu</th>
                                <th className="p-4">Kontajner</th>
                                <th className="p-4 text-right">Netto (kg)</th>
                                <th className="p-4 w-24"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-800/50">
                            {props.actualScrap.length > 0 ? (
                                props.actualScrap.map(r => {
                                    const metal = props.metals.find(m => m.id === r.metalId);
                                    const bin = props.bins.find(b => b.id === r.binId);
                                    return (
                                        <tr key={r.id} className="hover:bg-white/[0.02] transition-colors group text-sm">
                                            <td className="p-4">
                                                <div className="text-white font-bold">{new Date(r.timestamp).toLocaleDateString('sk-SK')}</div>
                                                <div className="text-[10px] text-slate-500 font-mono">{new Date(r.timestamp).toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' })}</div>
                                            </td>
                                            <td className="p-4 text-slate-300 font-bold uppercase">{props.resolveName(r.worker)}</td>
                                            <td className="p-4 font-black text-white uppercase">{metal?.type || '???'}</td>
                                            <td className="p-4 text-slate-400 font-bold uppercase">{bin?.name || '???'}</td>
                                            <td className="p-4 text-right font-black text-teal-400 font-mono text-lg">{r.netto} kg</td>
                                            <td className="p-4 text-center">
                                                <div className="flex gap-2 justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button onClick={() => handleOpenEdit(r)} className="p-2 bg-slate-800 text-teal-400 hover:text-white hover:bg-teal-600 rounded-lg transition-all">
                                                        <Icons.Edit />
                                                    </button>
                                                    <button onClick={() => { if(window.confirm(t('confirm_delete_msg'))) props.onDeleteRecord(r.id); }} className="p-2 bg-slate-800 text-red-500 hover:text-white hover:bg-red-600 rounded-lg transition-all">
                                                        <Icons.Trash />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={6} className="py-32 text-center text-slate-700">
                                        <div className="flex flex-col items-center gap-4">
                                            <Icons.Box />
                                            <p className="font-black uppercase tracking-[0.3em] text-xs italic">{t('scrap_empty_warehouse')}</p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* DELIVERY NOTE CONFIRMATION MODAL */}
            {isDeliveryNoteModalOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in no-print" onClick={() => setIsDeliveryNoteModalOpen(false)}>
                    <div className="bg-slate-900 border-2 border-emerald-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden text-center" onClick={e => e.stopPropagation()}>
                        <div className="w-20 h-20 bg-emerald-500/10 border border-emerald-500/30 rounded-full flex items-center justify-center mx-auto mb-6 text-emerald-500">
                            <Icons.FileText />
                        </div>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-4">
                            {language === 'sk' ? 'STIAHNUŤ DODACÍ LIST?' : 'DOWNLOAD DELIVERY NOTE?'}
                        </h3>

                        <p className="text-sm text-slate-400 font-bold uppercase leading-relaxed mb-10">
                            {language === 'sk' 
                                ? "Systém vygeneruje a stiahne profesionálny PDF dokument. Po stiahnutí sa odomkne možnosť finálnej expedície šrotu do archívu." 
                                : "The system will generate and download a professional PDF document. After downloading, the option for final scrap expedition to archive will be unlocked."
                            }
                        </p>

                        <div className="grid grid-cols-2 gap-4">
                            <button 
                                onClick={() => setIsDeliveryNoteModalOpen(false)} 
                                className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all"
                            >
                                {t('btn_cancel')}
                            </button>
                            <button 
                                onClick={confirmDeliveryNote} 
                                className="h-14 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-emerald-800 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2"
                            >
                                <Icons.Check /> {language === 'sk' ? 'STIAHNUŤ PDF' : 'DOWNLOAD PDF'}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

            {/* EXPEDITE MODAL */}
            {isExpediteModalOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in no-print" onClick={() => !isSubmitting && setIsExpediteModalOpen(false)}>
                    <div className="bg-slate-900 border-2 border-indigo-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden text-center" onClick={e => e.stopPropagation()}>
                        <div className="w-20 h-20 bg-indigo-500/10 border border-indigo-500/30 rounded-full flex items-center justify-center mx-auto mb-6 text-indigo-500">
                            <Icons.Dispatch />
                        </div>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-4">
                            {t('scrap_dispatch_modal_title')}
                        </h3>

                        <div className="space-y-4 mb-10">
                            <p className="text-sm text-slate-400 font-bold uppercase leading-relaxed">
                                {t('scrap_dispatch_modal_desc')}
                                <br />
                                <span className="text-white text-lg font-black">{props.actualScrap.length} položiek</span>
                            </p>

                            <div className="mt-6">
                                <label className={labelClass}>{t('scrap_dispatch_date')}</label>
                                <input 
                                    type="date" 
                                    value={dispatchDate} 
                                    onChange={e => setDispatchDate(e.target.value)}
                                    className={inputClass}
                                />
                                <p className="text-[10px] text-slate-500 mt-2 font-bold uppercase italic">* Tento dátum určí názov archívneho šanónu.</p>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <button 
                                disabled={isSubmitting}
                                onClick={() => setIsExpediteModalOpen(false)} 
                                className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all disabled:opacity-30"
                            >
                                ZRUŠIŤ
                            </button>
                            <button 
                                disabled={isSubmitting}
                                onClick={handleExpediteConfirm} 
                                className="h-14 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-indigo-800 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 disabled:bg-slate-700 disabled:border-slate-800"
                            >
                                {isSubmitting ? '...' : 'POTVRDIŤ EXPEDÍCIU'}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

            {/* EDIT MODAL */}
            {isEditModalOpen && editingItem && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in no-print" onClick={() => setIsEditModalOpen(false)}>
                    <div className="bg-slate-900 border-2 border-teal-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden" onClick={e => e.stopPropagation()}>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-8 flex items-center gap-3">
                            <Icons.Edit /> {t('scrap_edit_title')}
                        </h3>

                        <div className="space-y-6 mb-10">
                            <div>
                                <label className={labelClass}>{t('scrap_metal_select')}</label>
                                <select value={editMetalId} onChange={e => setEditMetalId(e.target.value)} className={inputClass}>
                                    {props.metals.map(m => <option key={m.id} value={m.id}>{m.type}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={labelClass}>{t('scrap_bin_select')}</label>
                                <select value={editBinId} onChange={e => setEditBinId(e.target.value)} className={inputClass}>
                                    {props.bins.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={labelClass}>{t('scrap_gross')}</label>
                                <input type="number" value={editGross} onChange={e => setEditGross(e.target.value)} className={`${inputClass} !text-3xl text-teal-400`} />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setIsEditModalOpen(false)} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                            <button onClick={handleSaveEdit} className="h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-xl transition-all active:scale-95">ULOŽIŤ ZMENY</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

        </div>
    );
};

export default ScrapWarehouseTab;

import React, { useState, useMemo, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { ScrapRecord, ScrapBin, ScrapMetal } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

interface ScrapWarehouseTabProps {
    currentUser: string;
    actualScrap: ScrapRecord[];
    bins: ScrapBin[];
    metals: ScrapMetal[];
    onDeleteRecord: (id: string) => Promise<void>;
    onUpdateRecord: (id: string, updates: Partial<ScrapRecord>) => Promise<void>;
    onExpedite: (worker: string, dispatchDate: string) => Promise<string | undefined>;
    resolveName: (username?: string | null) => string;
}

declare var jspdf: any;

const Icons = {
    Dispatch: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>,
    Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
    Edit: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>,
    Box: () => <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>,
    FileText: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>,
    Alert: () => <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>,
    Check: () => <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>,
};

const ScrapWarehouseTab: React.FC<ScrapWarehouseTabProps> = (props) => {
    const { t, language } = useLanguage();

    // State pre modaly
    const [isExpediteModalOpen, setIsExpediteModalOpen] = useState(false);
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);
    const [isDeliveryNoteModalOpen, setIsDeliveryNoteModalOpen] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isDeliveryNoteGenerated, setIsDeliveryNoteGenerated] = useState(false);

    // State pre expedíciu
    const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);

    // State pre editáciu
    const [editingItem, setEditingItem] = useState<ScrapRecord | null>(null);
    const [editGross, setEditGross] = useState('');
    const [editMetalId, setEditMetalId] = useState('');
    const [editBinId, setEditBinId] = useState('');

    // Reset stavu vygenerovaného listu pri zmene obsahu skladu
    useEffect(() => {
        setIsDeliveryNoteGenerated(false);
    }, [props.actualScrap.length]);

    const handleOpenEdit = (item: ScrapRecord) => {
        setEditingItem(item);
        setEditGross(String(item.gross ?? '0'));
        setEditMetalId(item.metalId || '');
        setEditBinId(item.binId || '');
        setIsEditModalOpen(true);
    };

    const handleSaveEdit = async () => {
        if (!editingItem || !editGross || !editMetalId || !editBinId) return;

        const bin = props.bins.find(b => b.id === editBinId);
        const grossVal = parseFloat(editGross) || 0;
        const taraVal = bin ? bin.tara : 0;

        await props.onUpdateRecord(editingItem.id, {
            metalId: editMetalId,
            binId: editBinId,
            gross: grossVal,
            tara: taraVal,
            netto: Math.max(grossVal - taraVal, 0)
        });

        setIsEditModalOpen(false);
        setEditingItem(null);
    };

    const confirmDeliveryNote = () => {
        if (props.actualScrap.length === 0 || typeof jspdf === 'undefined') return;

        const { jsPDF } = jspdf;
        const doc = new jsPDF();

        // 1. Hlavička
        doc.setFontSize(22);
        doc.setTextColor(0, 0, 0);
        doc.setFont("helvetica", "bold");
        doc.text("CLAMASON SLOVAKIA", 20, 25);

        doc.setFontSize(12);
        doc.text("DODACI LIST - KOVOVY ODPAD", 20, 32);

        // 2. Info blok
        doc.setFontSize(10);
        doc.setFont("helvetica", "normal");
        const dateStr = new Date().toLocaleDateString('sk-SK');
        const timeStr = new Date().toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' });
        doc.text(`Datum vystavenia: ${dateStr}`, 140, 25);
        doc.text(`Cas vystavenia: ${timeStr}`, 140, 30);
        doc.text(`Vystavil: ${props.resolveName(props.currentUser)}`, 140, 35);

        doc.setLineWidth(0.5);
        doc.line(20, 40, 190, 40);

        // 3. Tabuľka dát
        const tableBody = props.actualScrap.map(r => {
            const metal = props.metals.find(m => m.id === r.metalId);
            const bin = props.bins.find(b => b.id === r.binId);
            return [
                new Date(r.timestamp).toLocaleDateString('sk-SK'),
                metal?.type || '???',
                bin?.name || '???',
                r.gross.toString(),
                r.tara.toString(),
                r.netto.toString()
            ];
        });

        (doc as any).autoTable({
            startY: 50,
            head: [['Datum vazenia', 'Material', 'Kontajner', 'Brutto (kg)', 'Tara (kg)', 'Netto (kg)']],
            body: tableBody,
            theme: 'grid',
            headStyles: { fillColor: [240, 240, 240], textColor: [0, 0, 0], fontStyle: 'bold' },
            styles: { fontSize: 9, cellPadding: 3 },
            columnStyles: {
                3: { halign: 'right' },
                4: { halign: 'right' },
                5: { halign: 'right', fontStyle: 'bold' }
            }
        });

        let finalY = (doc as any).lastAutoTable.finalY || 70;

        // Kontrola pretečenia na novú stranu pre sumáre
        if (finalY > 170) { 
            doc.addPage();
            finalY = 20; 
        }

        // --- NOVINKA: SUMÁR PODĽA MATERIÁLU ---
        const metalSummaryMap: Record<string, number> = {};
        props.actualScrap.forEach(r => {
            const metal = props.metals.find(m => m.id === r.metalId);
            const name = metal?.type || 'Neznamy';
            metalSummaryMap[name] = (metalSummaryMap[name] || 0) + r.netto;
        });

        doc.setFontSize(10);
        doc.setFont("helvetica", "bold");
        doc.text("SUMAR CISTEJ VAHY PODLA MATERIALU (NETTO):", 20, finalY + 12);
        doc.setFont("helvetica", "normal");

        let summaryY = finalY + 18;
        Object.entries(metalSummaryMap).forEach(([name, weight]) => {
            doc.text(`${name}:`, 20, summaryY);
            doc.setFont("helvetica", "bold");
            doc.text(`${weight} kg`, 80, summaryY, { align: 'right' });
            doc.setFont("helvetica", "normal");
            summaryY += 6;
        });

        // 4. Celkové Totály
        const totalGross = props.actualScrap.reduce((acc, curr) => acc + curr.gross, 0);
        const itemCount = props.actualScrap.length;

        doc.setLineWidth(0.2);
        doc.line(20, summaryY + 2, 80, summaryY + 2);

        doc.setFontSize(11);
        doc.setFont("helvetica", "bold");
        doc.text(`CELKOVA HMOTNOST BRUTTO: ${totalGross} kg`, 20, summaryY + 10);
        doc.setFontSize(10);
        doc.setFont("helvetica", "normal");
        doc.text(`POCET POLOZIEK: ${itemCount}`, 20, summaryY + 16);

        // --- NOVINKA: DOPLNKOVÉ INFORMÁCIE ---
        doc.setFontSize(9);
        doc.setFont("helvetica", "bold");
        doc.text("DOPLNKOVE INFORMACIE:", 20, summaryY + 26);
        doc.setDrawColor(200, 200, 200);
        doc.rect(20, summaryY + 28, 170, 20); // Prázdny box na poznámky

        // 5. Dátum expedície a podpisy
        doc.setFontSize(10);
        doc.setTextColor(0, 0, 0);
        doc.text(`DATUM EXPEDICIE: ...........................................`, 20, summaryY + 58);

        const signatureY = summaryY + 90;
        doc.setLineWidth(0.2);
        doc.line(20, signatureY, 80, signatureY);
        doc.line(120, signatureY, 180, signatureY);

        doc.setFontSize(8);
        doc.setFont("helvetica", "normal");
        doc.text("Odovzdal (Clamason Slovakia)", 30, signatureY + 5);
        doc.text("Prevzal (Dopravca)", 135, signatureY + 5);

        // 6. Finálna pätička s číslovaním strán
        const totalPages = doc.internal.getNumberOfPages();
        for (let i = 1; i <= totalPages; i++) {
            doc.setPage(i);
            doc.setFontSize(8);
            doc.setTextColor(150, 150, 150);
            doc.text("Vygenerovane systemom Clamason Task Manager Intelligence", 105, 285, { align: 'center' });
            doc.text(`Strana ${i} / ${totalPages}`, 190, 285, { align: 'right' });
        }

        // 7. Uloženie
        doc.save(`Dodaci_list_srot_${new Date().toISOString().split('T')[0]}.pdf`);

        setIsDeliveryNoteGenerated(true);
        setIsDeliveryNoteModalOpen(false);
    };

    const handleExpediteConfirm = async () => {
        if (!dispatchDate) {
            alert(language === 'sk' ? "Vyberte dátum expedície." : "Select dispatch date.");
            return;
        }
        setIsSubmitting(true);
        try {
            const sanonId = await props.onExpedite(props.currentUser, dispatchDate);
            if (sanonId) {
                alert(language === 'sk' ? `Expedícia úspešná. Archív: ${sanonId}` : `Expedition successful. Archive: ${sanonId}`);
                setIsExpediteModalOpen(false);
                setIsDeliveryNoteGenerated(false);
            }
        } catch (e) {
            alert("Chyba pri expedícii.");
        } finally {
            setIsSubmitting(false);
        }
    };

    const totalNetto = useMemo(() => props.actualScrap.reduce((acc, curr) => acc + curr.netto, 0), [props.actualScrap]);

    const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-3xl p-6 shadow-2xl backdrop-blur-sm relative overflow-hidden";
    const labelClass = "block text-[10px] font-black text-slate-500 uppercase tracking-[0.25em] mb-2";
    const inputClass = "w-full h-14 bg-slate-900/80 border-2 border-slate-700 rounded-xl px-4 text-white text-lg font-black focus:outline-none focus:border-teal-500/50 transition-all font-mono uppercase text-center";

    return (
        <div className="max-w-7xl mx-auto space-y-8 animate-fade-in pb-20">

            {/* UI HEADER AREA */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 no-print">
                <div>
                    <h1 className="text-3xl font-black text-white uppercase tracking-tighter leading-none">{t('scrap_warehouse_title')}</h1>
                    <div className="flex items-center gap-3 mt-3">
                        <span className="bg-indigo-500/20 text-indigo-400 text-[9px] font-black px-3 py-1 rounded-full border border-indigo-500/30 uppercase tracking-widest">AKTUÁLNY SKLAD</span>
                        <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">Položiek: <span className="text-white">{props.actualScrap.length}</span></p>
                    </div>
                </div>

                <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
                    {/* BUTTON: DELIVERY NOTE (PDF) */}
                    <button 
                        disabled={props.actualScrap.length === 0}
                        onClick={() => setIsDeliveryNoteModalOpen(true)}
                        className="w-full sm:w-auto h-14 px-10 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-30 disabled:cursor-not-allowed text-white rounded-2xl font-black text-sm uppercase tracking-widest border-b-4 border-emerald-900 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3"
                    >
                        <Icons.FileText /> {t('scrap_btn_delivery_note')}
                    </button>

                    {/* BUTTON: EXPEDITE */}
                    <button 
                        disabled={props.actualScrap.length === 0 || !isDeliveryNoteGenerated}
                        onClick={() => setIsExpediteModalOpen(true)}
                        className={`w-full sm:w-auto h-14 px-10 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-30 disabled:cursor-not-allowed text-white rounded-2xl font-black text-sm uppercase tracking-widest border-b-4 border-indigo-900 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 ${!isDeliveryNoteGenerated && props.actualScrap.length > 0 ? 'ring-2 ring-indigo-500 ring-offset-4 ring-offset-gray-900 animate-pulse' : ''}`}
                    >
                        <Icons.Dispatch /> {t('scrap_btn_dispatch')}
                    </button>
                </div>
            </div>

            {/* LIST AREA */}
            <div className={`${cardClass} no-print`}>
                <div className="overflow-x-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-950/50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b border-slate-800">
                                <th className="p-4">Dátum / Čas</th>
                                <th className="p-4">Skladník</th>
                                <th className="p-4">Typ kovu</th>
                                <th className="p-4">Kontajner</th>
                                <th className="p-4 text-right">Netto (kg)</th>
                                <th className="p-4 w-24"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-800/50">
                            {props.actualScrap.length > 0 ? (
                                props.actualScrap.map(r => {
                                    const metal = props.metals.find(m => m.id === r.metalId);
                                    const bin = props.bins.find(b => b.id === r.binId);
                                    return (
                                        <tr key={r.id} className="hover:bg-white/[0.02] transition-colors group text-sm">
                                            <td className="p-4">
                                                <div className="text-white font-bold">{new Date(r.timestamp).toLocaleDateString('sk-SK')}</div>
                                                <div className="text-[10px] text-slate-500 font-mono">{new Date(r.timestamp).toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' })}</div>
                                            </td>
                                            <td className="p-4 text-slate-300 font-bold uppercase">{props.resolveName(r.worker)}</td>
                                            <td className="p-4 font-black text-white uppercase">{metal?.type || '???'}</td>
                                            <td className="p-4 text-slate-400 font-bold uppercase">{bin?.name || '???'}</td>
                                            <td className="p-4 text-right font-black text-teal-400 font-mono text-lg">{r.netto} kg</td>
                                            <td className="p-4 text-center">
                                                <div className="flex gap-2 justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button onClick={() => handleOpenEdit(r)} className="p-2 bg-slate-800 text-teal-400 hover:text-white hover:bg-teal-600 rounded-lg transition-all">
                                                        <Icons.Edit />
                                                    </button>
                                                    <button onClick={() => { if(window.confirm(t('confirm_delete_msg'))) props.onDeleteRecord(r.id); }} className="p-2 bg-slate-800 text-red-500 hover:text-white hover:bg-red-600 rounded-lg transition-all">
                                                        <Icons.Trash />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={6} className="py-32 text-center text-slate-700">
                                        <div className="flex flex-col items-center gap-4">
                                            <Icons.Box />
                                            <p className="font-black uppercase tracking-[0.3em] text-xs italic">{t('scrap_empty_warehouse')}</p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* DELIVERY NOTE CONFIRMATION MODAL */}
            {isDeliveryNoteModalOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in no-print" onClick={() => setIsDeliveryNoteModalOpen(false)}>
                    <div className="bg-slate-900 border-2 border-emerald-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden text-center" onClick={e => e.stopPropagation()}>
                        <div className="w-20 h-20 bg-emerald-500/10 border border-emerald-500/30 rounded-full flex items-center justify-center mx-auto mb-6 text-emerald-500">
                            <Icons.FileText />
                        </div>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-4">
                            {language === 'sk' ? 'STIAHNUŤ DODACÍ LIST?' : 'DOWNLOAD DELIVERY NOTE?'}
                        </h3>

                        <p className="text-sm text-slate-400 font-bold uppercase leading-relaxed mb-10">
                            {language === 'sk' 
                                ? "Systém vygeneruje a stiahne profesionálny PDF dokument. Po stiahnutí sa odomkne možnosť finálnej expedície šrotu do archívu." 
                                : "The system will generate and download a professional PDF document. After downloading, the option for final scrap expedition to archive will be unlocked."
                            }
                        </p>

                        <div className="grid grid-cols-2 gap-4">
                            <button 
                                onClick={() => setIsDeliveryNoteModalOpen(false)} 
                                className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all"
                            >
                                {t('btn_cancel')}
                            </button>
                            <button 
                                onClick={confirmDeliveryNote} 
                                className="h-14 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-emerald-800 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2"
                            >
                                <Icons.Check /> {language === 'sk' ? 'STIAHNUŤ PDF' : 'DOWNLOAD PDF'}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

            {/* EXPEDITE MODAL */}
            {isExpediteModalOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in no-print" onClick={() => !isSubmitting && setIsExpediteModalOpen(false)}>
                    <div className="bg-slate-900 border-2 border-indigo-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden text-center" onClick={e => e.stopPropagation()}>
                        <div className="w-20 h-20 bg-indigo-500/10 border border-indigo-500/30 rounded-full flex items-center justify-center mx-auto mb-6 text-indigo-500">
                            <Icons.Dispatch />
                        </div>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-4">
                            {t('scrap_dispatch_modal_title')}
                        </h3>

                        <div className="space-y-4 mb-10">
                            <p className="text-sm text-slate-400 font-bold uppercase leading-relaxed">
                                {t('scrap_dispatch_modal_desc')}
                                <br />
                                <span className="text-white text-lg font-black">{props.actualScrap.length} položiek</span>
                            </p>

                            <div className="mt-6">
                                <label className={labelClass}>{t('scrap_dispatch_date')}</label>
                                <input 
                                    type="date" 
                                    value={dispatchDate} 
                                    onChange={e => setDispatchDate(e.target.value)}
                                    className={inputClass}
                                />
                                <p className="text-[10px] text-slate-500 mt-2 font-bold uppercase italic">* Tento dátum určí názov archívneho šanónu.</p>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <button 
                                disabled={isSubmitting}
                                onClick={() => setIsExpediteModalOpen(false)} 
                                className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all disabled:opacity-30"
                            >
                                ZRUŠIŤ
                            </button>
                            <button 
                                disabled={isSubmitting}
                                onClick={handleExpediteConfirm} 
                                className="h-14 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-indigo-800 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 disabled:bg-slate-700 disabled:border-slate-800"
                            >
                                {isSubmitting ? '...' : 'POTVRDIŤ EXPEDÍCIU'}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

            {/* EDIT MODAL */}
            {isEditModalOpen && editingItem && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in no-print" onClick={() => setIsEditModalOpen(false)}>
                    <div className="bg-slate-900 border-2 border-teal-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden" onClick={e => e.stopPropagation()}>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-8 flex items-center gap-3">
                            <Icons.Edit /> {t('scrap_edit_title')}
                        </h3>

                        <div className="space-y-6 mb-10">
                            <div>
                                <label className={labelClass}>{t('scrap_metal_select')}</label>
                                <select value={editMetalId} onChange={e => setEditMetalId(e.target.value)} className={inputClass}>
                                    {props.metals.map(m => <option key={m.id} value={m.id}>{m.type}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={labelClass}>{t('scrap_bin_select')}</label>
                                <select value={editBinId} onChange={e => setEditBinId(e.target.value)} className={inputClass}>
                                    {props.bins.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={labelClass}>{t('scrap_gross')}</label>
                                <input type="number" value={editGross} onChange={e => setEditGross(e.target.value)} className={`${inputClass} !text-3xl text-teal-400`} />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setIsEditModalOpen(false)} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                            <button onClick={handleSaveEdit} className="h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-xl transition-all active:scale-95">ULOŽIŤ ZMENY</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

        </div>
    );
};

