                            const months = ['JAN','FEB','MAR','APR','MÁJ','JÚN','JÚL','AUG','SEP','OKT','NOV','DEC'];
                            const parts = v.split('-');
                            if (parts.length < 2) return v;
                            return months[parseInt(parts[1]) - 1] || v;
                        }}
                    />
                    <YAxis stroke="#475569" fontSize={10} tickLine={false} axisLine={false} tickFormatter={(v) => `${v.toLocaleString()}€`} />
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#0f172a', borderColor: '#334155', borderRadius: '16px' }}
                        itemStyle={{ color: '#10b981', fontWeight: 'bold' }}
                    />
                    <Area 
                        type="monotone" 
                        dataKey="externalValue" 
                        stroke="#10b981" 
                        strokeWidth={4}
                        fillOpacity={1} 
                        fill="url(#colorYield)" 
                        name={language === 'sk' ? "Výnos (€)" : "Yield (€)"}
                        animationDuration={2000}
                        activeDot={{ r: 8, strokeWidth: 2, stroke: '#fff' }}
                    />
                </AreaChart>
            </ResponsiveContainer>
        </div>
      </div>

      {/* SECTION 3: INDEPENDENT METAL PRICE TREND (YEAR SELECTABLE) */}
      <div className="bg-slate-950/40 border border-slate-800 p-8 rounded-[2.5rem] shadow-2xl overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-teal-500 via-sky-500 to-amber-500 opacity-30"></div>

        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-6 mb-12">
            <div className="flex items-center gap-4">
                <div className="p-3 bg-teal-500/10 rounded-2xl text-teal-400 border border-teal-500/20 shadow-lg">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" />
                    </svg>
                </div>
                <div>
                    <h3 className="text-xl font-black text-white uppercase tracking-tighter leading-none">{t('scrap_price_trend')}</h3>
                    <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mt-1">Prehľad trhových cien za rok {selectedYear} (€ / kg)</p>
                </div>
            </div>

            <div className="hidden lg:flex flex-wrap gap-4 bg-slate-900/60 p-3 rounded-2xl border border-white/5 shadow-inner">
                {metals.map((m, idx) => (
                    <div key={m.id} className="flex items-center gap-2 px-2">
                        <div className="w-2.5 h-2.5 rounded-full shadow-sm" style={{ backgroundColor: COLORS[idx % COLORS.length] }}></div>
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">{m.type}</span>
                    </div>
                ))}
            </div>
        </div>

        <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
                <LineChart data={yearlyData}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#ffffff05" vertical={false} />
                    <XAxis 
                        dataKey="month" 
                        stroke="#475569" 
                        fontSize={10} 
                        tickLine={false} 
                        axisLine={false} 
                        padding={{ left: 30, right: 30 }}
                        tickFormatter={(v) => {
                            const months = ['JAN','FEB','MAR','APR','MÁJ','JÚN','JÚL','AUG','SEP','OKT','NOV','DEC'];
                            const parts = v.split('-');
                            if (parts.length < 2) return v;
                            const mIdx = parseInt(parts[1]) - 1;
                            return months[mIdx] || v;
                        }}
                    />
                    <YAxis 
                        stroke="#475569" 
                        fontSize={10} 
                        tickLine={false} 
                        axisLine={false} 
                        domain={['auto', 'auto']} 
                        tickFormatter={(v) => `${v.toLocaleString('sk-SK', { minimumFractionDigits: 2 })}€`} 
                    />
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#0f172a', borderColor: '#334155', borderRadius: '16px', boxShadow: '0 10px 25px rgba(0,0,0,0.5)' }}
                        itemStyle={{ fontWeight: '900', textTransform: 'uppercase', fontSize: '11px' }}
                    />
                    {metals.map((metal, idx) => (
                        <Line 
                            key={metal.id}
                            type="monotone"
                            dataKey={metal.type}
                            stroke={COLORS[idx % COLORS.length]}
                            strokeWidth={4}
                            dot={{ r: 5, strokeWidth: 3, fill: '#0f172a' }}
                            activeDot={{ r: 8, strokeWidth: 2, stroke: '#fff' }}
                            name={metal.type}
                            connectNulls
                            animationDuration={1500}
                        />
                    ))}
                </LineChart>
            </ResponsiveContainer>
        </div>

        <div className="mt-8 pt-6 border-t border-white/5 text-center">
            <p className="text-[9px] text-slate-600 font-bold uppercase tracking-[0.2em] italic">
                * Dáta sú čerpané z historických záznamov cenníkov pre zvolený rok {selectedYear}
            </p>
        </div>
      </div>
    </div>
  );
};

export default ScrapAnalyticsSection;

import React, { useState, memo } from 'react';
import { UserData, Role } from '../../App';
import { useLanguage } from '../LanguageContext';

interface UserSectionProps {
  users: UserData[];
  roles: Role[];
  onAddUser: (user: UserData) => void;
  onUpdatePassword: (username: string, newPass: string) => void;
  onUpdateNickname: (username: string, newNick: string) => void;
  onUpdateUserRole: (username: string, newRole: string) => void;
  onUpdateExportPermission: (username: string, canExport: boolean) => void;
  onDeleteUser: (username: string) => void;
}

const Icons = {
  Save: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7H5a2 2 0 00-2 2v9a2 2 0 002 2h14a2 2 0 002-2V9a2 2 0 00-2-2h-3m-1 4l-3 3m0 0l-3-3m3 3V4" /></svg>,
  Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
  Eye: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>,
  EyeOff: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" /></svg>
};

const UserSection: React.FC<UserSectionProps> = memo(({ users, roles, onAddUser, onUpdatePassword, onUpdateNickname, onUpdateUserRole, onUpdateExportPermission, onDeleteUser }) => {
  const { t, language } = useLanguage();
  const [newUser, setNewUser] = useState('');
  const [newPass, setNewPass] = useState('');
  const [newRole, setNewRole] = useState<'USER' | 'ADMIN' | 'LEADER'>('USER');
  const [passwordInputs, setPasswordInputs] = useState<Record<string, string>>({});
  const [nicknameInputs, setNicknameInputs] = useState<Record<string, string>>({});
  const [revealedPasswords, setRevealedPasswords] = useState<Record<string, boolean>>({});

  const toggleReveal = (username: string) => {
    setRevealedPasswords(prev => ({ ...prev, [username]: !prev[username] }));
  };

  const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-2xl p-6 shadow-2xl backdrop-blur-sm";
  const inputClass = "w-full h-12 bg-slate-800/80 border border-slate-700 rounded-xl px-4 text-white text-base focus:outline-none focus:ring-2 focus:ring-teal-500/50 transition-all font-mono placeholder-gray-500 uppercase";
  const labelClass = "block text-xs font-black text-slate-500 uppercase tracking-[0.2em] mb-3";

  return (
    <div className={cardClass}>
      <div className="space-y-10">
        <div className="flex justify-between items-center border-b border-slate-800 pb-6">
          <h3 className="text-2xl font-black text-white uppercase tracking-tighter">SPRÁVA TÍMU</h3>
          <span className="text-xs font-black text-slate-500 uppercase tracking-widest">{users.length} UŽÍVATEĽOV</span>
        </div>
        <div className="grid grid-cols-1 gap-4 max-h-[500px] overflow-y-auto custom-scrollbar pr-2">
          {users.map(u => {
            const isRevealed = revealedPasswords[u.username] || false;
            return (
              <div key={u.id || u.username} className="bg-slate-950/30 p-5 rounded-2xl border border-white/5 flex flex-col md:flex-row justify-between items-center gap-6 group">
                <div className="flex items-center gap-6 min-w-[220px]">
                  <div className="w-12 h-12 rounded-full bg-teal-500/10 border border-teal-500/20 flex items-center justify-center text-teal-400 font-black text-xl">{(u.nickname || u.username).charAt(0).toUpperCase()}</div>
                  <div>
                    <p className="font-black text-white text-base truncate max-w-[120px]">{u.nickname || u.username}</p>
                    <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{u.username} • {u.role}</p>
                  </div>
                </div>
                <div className="flex flex-1 items-center gap-4 w-full">
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 flex-grow">
                      <div className="relative">
                        <input 
                          type={isRevealed ? "text" : "password"}
                          placeholder={isRevealed ? u.password : "Zmeniť Heslo"}
                          value={passwordInputs[u.username] || ''}
                          onChange={(e) => setPasswordInputs(p => ({ ...p, [u.username]: e.target.value }))}
                          className={`${inputClass} pr-10`}
                        />
                        <button 
                          onClick={() => toggleReveal(u.username)}
                          className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-500 hover:text-teal-400 transition-colors"
                        >
                          {isRevealed ? <Icons.EyeOff /> : <Icons.Eye />}
                        </button>
                      </div>
                      <input 
                        type="text" 
                        placeholder="Nickname"
                        value={nicknameInputs[u.username] === undefined ? (u.nickname || '') : nicknameInputs[u.username]}
                        onChange={(e) => setNicknameInputs(p => ({ ...p, [u.username]: e.target.value }))}
                        className={inputClass}
                      />
                      {/* ROLE SELECTOR */}
                      <select 
                          value={u.role}
                          onChange={(e) => onUpdateUserRole(u.username, e.target.value)}
                          disabled={u.username === 'ADMIN'}
                          className={`${inputClass} ${u.username === 'ADMIN' ? 'opacity-50 cursor-not-allowed' : ''}`}
                      >
                          {roles.map(r => (
                              <option key={r.id} value={r.name}>{r.name}</option>
                          ))}
                      </select>
                      {/* EXPORT CHECKBOX */}
                      <label className="flex items-center justify-center gap-2 bg-slate-800/50 rounded-xl border border-slate-700 px-4 cursor-pointer hover:bg-slate-800 transition-colors h-12">
                        <input 
                          type="checkbox" 
                          checked={u.canExportAnalytics || false}
                          onChange={(e) => onUpdateExportPermission(u.username, e.target.checked)}
                          className="form-checkbox h-5 w-5 text-teal-500 rounded border-gray-600 bg-gray-700 focus:ring-teal-500"
                        />
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Export</span>
                      </label>
                  </div>
                  <button onClick={() => { 
                      if(passwordInputs[u.username]) { onUpdatePassword(u.username, passwordInputs[u.username]); setPasswordInputs(p => ({...p, [u.username]: ''})); }
                      if(nicknameInputs[u.username] !== undefined) { onUpdateNickname(u.username, nicknameInputs[u.username]); }
                  }} className="h-12 w-12 flex items-center justify-center bg-slate-800 rounded-xl border border-slate-700 text-teal-400 hover:bg-slate-700 transition-all flex-shrink-0 shadow-lg"><Icons.Save /></button>
                  {u.username !== 'ADMIN' && <button onClick={() => { if(window.confirm('Vymazať užívateľa?')) onDeleteUser(u.username); }} className="h-12 w-12 flex items-center justify-center text-slate-600 hover:text-red-500 transition-all flex-shrink-0"><Icons.Trash /></button>}
                </div>
              </div>
            );
          })}
        </div>
        <div className="pt-8 border-t border-slate-800">
          <h4 className={labelClass}>PRIDAŤ NOVÉHO ČLENA</h4>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <input value={newUser} onChange={e=>setNewUser(e.target.value)} placeholder="MENO" className={inputClass} />
            <input value={newPass} onChange={e=>setNewPass(e.target.value)} placeholder="HESLO" className={inputClass} />
            <select value={newRole} onChange={e=>setNewRole(e.target.value as any)} className={inputClass}>
              {roles.map(r => <option key={r.id} value={r.name}>{r.name}</option>)}
            </select>
            <button onClick={() => { if(newUser && newPass) { onAddUser({username:newUser, password:newPass, role:newRole, canExportAnalytics: false}); setNewUser(''); setNewPass(''); } }} className="h-12 bg-teal-600 hover:bg-teal-500 text-white font-black px-6 rounded-xl uppercase tracking-widest text-xs transition-all active:scale-95 shadow-xl border-2 border-teal-500">PRIDAŤ</button>
          </div>
        </div>
      </div>
    </div>
  );
});

export default UserSection;

import React, { useState, useEffect } from 'react';
import { DBItem, BreakSchedule, SystemConfig } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';
import { useData } from '../../context/DataContext';
import { TAB_CONFIG, DEFAULT_TAB_ORDER } from '../../constants/uiConstants';

interface SystemSectionProps {
  missingReasons: DBItem[];
  breakSchedules: BreakSchedule[];
  onAddMissingReason: (val: string) => void;
  onDeleteMissingReason: (id: string) => void;
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  isAdminLockEnabled: boolean;
  onToggleAdminLock: (val: boolean) => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
}

const Icons = {
  Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
  Megaphone: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5.882V19.24a1.76 1.76 0 01-3.417.592l-2.147-6.15M18 13a3 3 0 100-6M5.436 13.683A4.001 4.001 0 017 6h1.832c4.1 0 7.625-1.234 9.168-3v14c-1.543-1.766-5.067-3-9.168-3H7a3.988 3.988 0 01-1.564-.317z" /></svg>,
  UserGroup: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" /></svg>,
  ArrowUp: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 15l7-7 7 7" /></svg>,
  ArrowDown: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 9l-7 7-7-7" /></svg>,
  Layout: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2H6a2 2 0 01-2-2V6zM14 6a2 2 0 012-2h2a2 2 0 012 2v2a2 2 0 01-2 2h-2a2 2 0 01-2-2V6zM4 16a2 2 0 012-2h2a2 2 0 012 v2a2 2 0 01-2 2H6a2 2 0 01-2-2v-2zM14 16a2 2 0 012-2h2a2 2 0 012 v2a2 2 0 01-2 2h-2a2 2 0 01-2-2v-2z" /></svg>,
  Eye: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>,
  EyeOff: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" /></svg>
};

const SystemSection: React.FC<SystemSectionProps> = ({ 
  missingReasons, breakSchedules, onAddMissingReason, onDeleteMissingReason, onAddBreakSchedule, onDeleteBreakSchedule, onUpdateAdminKey,
  isAdminLockEnabled, onToggleAdminLock, systemConfig, onUpdateSystemConfig
}) => {
  const { t, language } = useLanguage();
  const { onBroadcastNotification, users } = useData();

  const [newMissingReason, setNewMissingReason] = useState('');
  const [newBreakStart, setNewBreakStart] = useState('');
  const [newBreakEnd, setNewBreakEnd] = useState('');

  const [oldKey, setOldKey] = useState('');
  const [newKey, setNewKey] = useState('');
  const [confirmKey, setConfirmKey] = useState('');
  const [isUpdating, setIsUpdating] = useState(false);
  const [showOldKey, setShowOldKey] = useState(false);

  // Broadcast State
  const [broadcastMsg, setBroadcastMsg] = useState('');
  const [isBroadcasting, setIsBroadcasting] = useState(false);
  const [selectedRecipients, setSelectedRecipients] = useState<string[]>([]);
  const [selectAll, setSelectAll] = useState(true);

  // Tab Order State
  const [localTabOrder, setLocalTabOrder] = useState<string[]>([]);
  const [hasOrderChanged, setHasOrderChanged] = useState(false);

  useEffect(() => {
    setLocalTabOrder(systemConfig.tabOrder || DEFAULT_TAB_ORDER);
  }, [systemConfig.tabOrder]);

  const moveTab = (index: number, direction: 'up' | 'down') => {
    const newOrder = [...localTabOrder];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    if (targetIndex < 0 || targetIndex >= newOrder.length) return;

    const temp = newOrder[index];
    newOrder[index] = newOrder[targetIndex];
    newOrder[targetIndex] = temp;

    setLocalTabOrder(newOrder);
    setHasOrderChanged(true);
  };

  const handleSaveTabOrder = async () => {
    await onUpdateSystemConfig({ tabOrder: localTabOrder });
    setHasOrderChanged(false);
    alert(language === 'sk' ? 'Usporiadanie menu bolo uložené.' : 'Tab order saved.');
  };

  const resetToDefaultOrder = () => {
    setLocalTabOrder(DEFAULT_TAB_ORDER);
    setHasOrderChanged(true);
  };

  const toggleRecipient = (username: string) => {
    setSelectAll(false);
    setSelectedRecipients(prev => 
      prev.includes(username) ? prev.filter(u => u !== username) : [...prev, username]
    );
  };

  const handleToggleAll = () => {
    const newState = !selectAll;
    setSelectAll(newState);
    if (newState) setSelectedRecipients([]);
  };

  const handleUpdateKey = async () => {
    if (!isAdminLockEnabled) return;
    if (!oldKey && !systemConfig.adminKey) {
        // Init state
    } else if (!oldKey || !newKey || !confirmKey) {
        alert(language === 'sk' ? 'Prosím, vyplňte všetky polia.' : 'Please fill all fields.');
        return;
    }
    if (newKey !== confirmKey) {
        alert(language === 'sk' ? 'Nové kľúče sa nezhodujú.' : 'New keys do not match.');
        return;
    }

    setIsUpdating(true);
    try {
        await onUpdateAdminKey(oldKey, newKey);
        setOldKey('');
        setNewKey('');
        setConfirmKey('');
    } catch (e) {
        // Error handled in hook
    } finally {
        setIsUpdating(false);
    }
  };

  const handleBroadcast = async () => {
    if (!broadcastMsg.trim()) return;

    const recipientCount = selectAll ? users.length : selectedRecipients.length;
    if (recipientCount === 0) {
        alert(language === 'sk' ? 'Vyberte aspoň jedného príjemcu.' : 'Select at least one recipient.');
        return;
    }

    if (!window.confirm(language === 'sk' ? `Odoslať túto správu ${recipientCount} užívateľom?` : `Send this message to ${recipientCount} users?`)) return;

    setIsBroadcasting(true);
    const author = localStorage.getItem('app_user') || 'ADMIN';

    await onBroadcastNotification(broadcastMsg, author, selectAll ? undefined : selectedRecipients);

    setBroadcastMsg('');
    setIsBroadcasting(false);
    alert(language === 'sk' ? 'Správa bola rozoslaná.' : 'Message broadcasted.');
  };

  const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-2xl p-6 shadow-2xl backdrop-blur-sm";
  const inputClass = "w-full h-12 bg-slate-800/80 border border-slate-700 rounded-xl px-4 text-white text-base focus:outline-none focus:ring-2 focus:ring-teal-500/50 transition-all font-mono placeholder-gray-500 uppercase";
  const labelClass = "block text-xs font-black text-slate-500 uppercase tracking-[0.2em] mb-3";

  return (
    <div className="space-y-8 animate-fade-in">

      {/* BROADCAST SECTION */}
      <div className="bg-indigo-900/10 border-2 border-indigo-500/30 rounded-3xl p-6 shadow-xl ring-1 ring-indigo-500/20">
          <div className="flex items-center gap-3 mb-6">
              <div className="p-3 bg-indigo-500/20 rounded-xl text-indigo-400">
                  <Icons.Megaphone />
              </div>
              <div>
                  <h3 className="text-xl font-black text-white uppercase tracking-tighter">HROMADNÁ SPRÁVA</h3>
                  <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-1">Odoslať notifikáciu vybraným užívateľom</p>
              </div>
          </div>

          <div className="space-y-6">
              <div className="bg-slate-950/50 p-4 rounded-2xl border border-indigo-500/20">
                  <div className="flex items-center justify-between mb-4 px-2">
                      <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <Icons.UserGroup />
                          PRÍJEMCOVIA
                      </div>
                      <button 
                        onClick={handleToggleAll}
                        className={`text-[10px] font-black px-3 py-1 rounded-full border transition-all ${selectAll ? 'bg-indigo-500 text-white border-indigo-400 shadow-md' : 'bg-slate-800 text-slate-500 border-slate-700'}`}
                      >
                        VŠETCI PRIHLÁSENÍ
                      </button>
                  </div>

                  {!selectAll && (
                      <div className="flex flex-wrap gap-2 max-h-32 overflow-y-auto custom-scrollbar p-1 animate-fade-in">
                          {users.map(u => (
                              <button
                                  key={u.username}
                                  onClick={() => toggleRecipient(u.username)}
                                  className={`px-3 py-1.5 rounded-lg text-[10px] font-bold uppercase tracking-wide border transition-all ${selectedRecipients.includes(u.username) ? 'bg-teal-600/20 border-teal-500 text-teal-400' : 'bg-slate-900 border-slate-800 text-slate-500 hover:border-slate-700'}`}
                              >
                                  {u.nickname || u.username}
                              </button>
                          ))}
                      </div>
                  )}
              </div>

              <div className="flex gap-3">
                  <textarea 
                      value={broadcastMsg}
                      onChange={(e) => setBroadcastMsg(e.target.value)}
                      placeholder="ZADAJTE TEXT SPRÁVY..."
                      className="w-full bg-slate-950 border border-indigo-500/30 rounded-2xl px-5 py-4 text-white text-sm focus:outline-none focus:border-indigo-500 transition-all font-medium placeholder-slate-700 resize-none h-24"
                  />
                  <button 
                      onClick={handleBroadcast}
                      disabled={isBroadcasting || !broadcastMsg.trim() || (!selectAll && selectedRecipients.length === 0)}
                      className="w-32 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-800 disabled:text-slate-600 text-white rounded-2xl font-black shadow-lg transition-all active:scale-95 border-2 border-indigo-500 uppercase tracking-widest text-[10px]"
                  >
                      {isBroadcasting ? '...' : 'ODOSLAŤ'}
                  </button>
              </div>
          </div>
      </div>

      {/* TAB ORDER MANAGEMENT SECTION */}
      <div className={cardClass}>
        <div className="flex justify-between items-center mb-6">
            <div className="flex items-center gap-3">
                <div className="p-3 bg-teal-500/10 rounded-xl text-teal-400 border border-teal-500/20">
                    <Icons.Layout />
                </div>
                <div>
                    <h3 className="text-xl font-black text-white uppercase tracking-tighter">USPORIADANIE NAVIGÁCIE</h3>
                    <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-1">Zmeňte poradie kariet v hlavnom menu</p>
                </div>
            </div>
            <div className="flex gap-2">
                <button 
                    onClick={resetToDefaultOrder}
                    className="h-10 px-4 rounded-lg bg-slate-800 text-slate-400 border border-slate-700 text-[9px] font-black uppercase tracking-widest hover:text-white transition-all"
                >
                    RESET
                </button>
                {hasOrderChanged && (
                    <button 
                        onClick={handleSaveTabOrder}
                        className="h-10 px-6 rounded-lg bg-teal-600 text-white border-2 border-teal-500 text-[10px] font-black uppercase tracking-widest shadow-lg animate-pulse"
                    >
                        ULOŽIŤ ZMENY
                    </button>
                )}
            </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
            {localTabOrder.map((tabId, idx) => {
                const config = TAB_CONFIG.find(c => c.id === tabId);
                if (!config) return null;
                return (
                    <div key={tabId} className="bg-slate-950/40 p-4 rounded-xl border border-white/5 flex items-center justify-between group">
                        <div className="flex items-center gap-4">
                            <span className="text-[10px] font-black text-slate-700 font-mono w-4">{idx + 1}.</span>
                            <span className="text-xs font-black text-slate-300 uppercase tracking-wider">{t(config.labelKey as any)}</span>
                        </div>
                        <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button 
                                onClick={() => moveTab(idx, 'up')} 
                                disabled={idx === 0}
                                className="p-2 rounded bg-slate-800 text-slate-500 hover:text-teal-400 disabled:opacity-10"
                            >
                                <Icons.ArrowUp />
                            </button>
                            <button 
                                onClick={() => moveTab(idx, 'down')} 
                                disabled={idx === localTabOrder.length - 1}
                                className="p-2 rounded bg-slate-800 text-slate-500 hover:text-teal-400 disabled:opacity-10"
                            >
                                <Icons.ArrowDown />
                            </button>
                        </div>
                    </div>
                );
            })}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* REASONS */}
        <div className={cardClass}>
          <h3 className="text-xl font-black text-white mb-6 uppercase tracking-tighter">DÔVODY CHÝBANIA</h3>
          <div className="space-y-4 max-h-60 overflow-y-auto custom-scrollbar pr-2 mb-6">
            {missingReasons.map(r => (
              <div key={r.id} className="flex justify-between items-center bg-slate-950/30 p-3 rounded-xl border border-white/5 group">
                <span className="text-sm font-bold text-slate-300 uppercase">{r.value}</span>
                <button onClick={() => onDeleteMissingReason(r.id)} className="text-slate-600 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><Icons.Trash /></button>
              </div>
            ))}
          </div>
          <div className="flex gap-2">
            <input value={newMissingReason} onChange={e=>setNewMissingReason(e.target.value)} placeholder="NOVÝ DÔVOD" className={inputClass} />
            <button onClick={()=>{if(newMissingReason){onAddMissingReason(newMissingReason); setNewMissingReason('');}}} className="bg-teal-600 hover:bg-teal-500 text-white px-6 rounded-xl font-black text-xs uppercase tracking-widest border-2 border-teal-500 shadow-lg">PRIDAŤ</button>
          </div>
        </div>

        {/* BREAKS */}
        <div className={cardClass}>
          <h3 className="text-xl font-black text-white mb-6 uppercase tracking-tighter">PLÁNOVANÉ PRESTÁVKY</h3>
          <div className="space-y-4 max-h-60 overflow-y-auto custom-scrollbar pr-2 mb-6">
            {breakSchedules.map(b => (
              <div key={b.id} className="flex justify-between items-center bg-slate-950/30 p-3 rounded-xl border border-white/5 group">
                <span className="text-sm font-bold text-amber-500 font-mono">{b.startTime} - {b.endTime}</span>
                <button onClick={() => onDeleteBreakSchedule(b.id)} className="text-slate-600 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100"><Icons.Trash /></button>
              </div>
            ))}
          </div>
          <div className="grid grid-cols-3 gap-2">
            <input type="time" value={newBreakStart} onChange={e=>setNewBreakStart(e.target.value)} className={inputClass} />
            <input type="time" value={newBreakEnd} onChange={e=>setNewBreakEnd(e.target.value)} className={inputClass} />
            <button onClick={()=>{if(newBreakStart && newBreakEnd){onAddBreakSchedule(newBreakStart, newBreakEnd); setNewBreakStart(''); setNewBreakEnd('');}}} className="bg-amber-600 hover:bg-amber-500 text-white rounded-xl font-black text-[10px] uppercase tracking-widest border-2 border-amber-500 shadow-lg">PRIDAŤ</button>
          </div>
        </div>
      </div>

      {/* ADMIN LOCK SETTINGS */}
      <div className={cardClass}>
        <div className="flex justify-between items-center mb-8 border-b border-slate-800 pb-6">
            <h3 className="text-xl font-black text-white uppercase tracking-tighter">ZABEZPEČENIE ADMIN KONZOLY</h3>
            <button 
                onClick={() => onToggleAdminLock(!isAdminLockEnabled)}
                className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest border-2 transition-all ${isAdminLockEnabled ? 'bg-amber-500/10 border-amber-500 text-amber-500 shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-500'}`}
            >
                {isAdminLockEnabled ? 'ZÁMOK AKTÍVNY' : 'ZÁMOK VYPNUTÝ'}
            </button>
        </div>

        {isAdminLockEnabled && (
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 items-end animate-fade-in">
                <div className="relative">
                    <label className={labelClass}>AKTUÁLNY KĽÚČ</label>
                    <input 
                      type={showOldKey ? "text" : "password"}
                      value={oldKey} 
                      onChange={e=>setOldKey(e.target.value)} 
                      className={`${inputClass} pr-10`} 
                      placeholder={showOldKey ? systemConfig.adminKey : "••••"} 
                    />
                    <button 
                      onClick={() => setShowOldKey(!showOldKey)}
                      className="absolute right-3 top-[38px] text-slate-500 hover:text-teal-400 transition-colors"
                    >
                      {showOldKey ? <Icons.EyeOff /> : <Icons.Eye />}
                    </button>
                </div>
                <div>
                    <label className={labelClass}>NOVÝ KĽÚČ</label>
                    <input type="password" value={newKey} onChange={e=>setNewKey(e.target.value)} className={inputClass} placeholder="••••" />
                </div>
                <div>
                    <label className={labelClass}>POTVRDIŤ NOVÝ</label>
                    <input type="password" value={confirmKey} onChange={e=>setConfirmKey(e.target.value)} className={inputClass} placeholder="••••" />
                </div>
                <button 
                    onClick={handleUpdateKey}
                    disabled={isUpdating}
                    className="h-12 bg-amber-600 hover:bg-amber-500 text-white rounded-xl font-black uppercase tracking-widest text-[10px] transition-all border-2 border-amber-500 shadow-xl disabled:opacity-50"
                >
                    {isUpdating ? 'AKTUALIZUJEM...' : 'ZMENIŤ KĽÚČ'}
                </button>
            </div>
        )}
      </div>
    </div>
  );
};

export default SystemSection;

import React, { useState, useEffect, useCallback } from 'react';
import LoginScreen from './components/LoginScreen';
import AppAuthenticated from './AppAuthenticated';
import { useAppSecurity } from './hooks/useAppSecurity';
import { DataProvider, useData } from './context/DataContext';
import { SystemConfig, UserData, Task, DBItem, MapSector, PriorityLevel, InventorySession, Notification, PartRequest, BOMRequest, BreakSchedule, SystemBreak, BOMComponent, Role, Permission } from './types/appTypes';

// Export types for backward compatibility with components
export type { 
  UserData, Task, DBItem, MapSector, PriorityLevel, InventorySession,
  Notification, PartRequest, BOMRequest, BreakSchedule, SystemBreak,
  BOMComponent, Role, Permission, SystemConfig 
};

// --- INNER COMPONENT (Consumes Context) ---
const AppContent = ({ 
  isAuthenticated, 
  currentUser, 
  currentUserRole, 
  onLoginSuccess, 
  onLogout, 
  systemConfig, 
  isUnlocked, 
  onUnlockAttempt, 
  onUpdateAdminKey, 
  onToggleAdminLock, 
  onUpdateSystemConfig, 
  installPrompt, 
  onInstallApp 
}: any) => {
  const { users } = useData(); 
  const [unlockKey, setUnlockKey] = useState("");

  // SERVICE MODE WATCHER: Okamžité vyhodenie ne-adminov pri zapnutí údržby
  useEffect(() => {
    if (isAuthenticated && currentUserRole !== 'ADMIN') {
      const nowMs = Date.now();

      // Prevod plánovaných časov na milisekundy pre presné porovnanie
      const startMs = systemConfig.maintenanceStart ? new Date(systemConfig.maintenanceStart).getTime() : null;
      const endMs = systemConfig.maintenanceEnd ? new Date(systemConfig.maintenanceEnd).getTime() : null;

      const isScheduled = startMs && endMs && nowMs >= startMs && nowMs <= endMs;

      if (systemConfig.maintenanceMode || isScheduled) {
        onLogout();
      }
    }
  }, [systemConfig.maintenanceMode, systemConfig.maintenanceStart, systemConfig.maintenanceEnd, isAuthenticated, currentUserRole, onLogout]);

  if (!isAuthenticated) {
    return (
      <LoginScreen 
        onLoginSuccess={onLoginSuccess} 
        users={users} 
        systemConfig={systemConfig} 
      />
    );
  }

  // Admin Lock Screen
  if (currentUserRole === 'ADMIN' && systemConfig.adminLockEnabled && !isUnlocked) {
    return (
        <div className="flex flex-col items-center justify-center p-10 bg-gray-900 w-full h-full">
            <div className="flex flex-col items-center justify-center p-10 bg-gray-800 rounded-3xl border-2 border-amber-600 shadow-[0_0_50px_rgba(217,119,6,0.2)] max-w-md w-full">
                <div className="text-amber-500 mb-6 animate-pulse">
                    <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                    </svg>
                </div>
                <h2 className="text-white text-2xl font-black mb-2 tracking-widest uppercase text-center">Zabezpečený prístup</h2>
                <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mb-8 text-center leading-relaxed">Zadajte kľúč pre prístup k nastaveniam</p>

                <input 
                    type="password" 
                    inputMode="numeric"
                    value={unlockKey} 
                    onChange={(e) => setUnlockKey(e.target.value)}
                    placeholder="ADMIN KĽÚČ"
                    className="w-full bg-slate-900 border-2 border-slate-700 text-white text-center px-4 py-4 rounded-2xl mb-4 focus:border-amber-500 outline-none font-mono text-2xl"
                    onKeyDown={(e) => e.key === 'Enter' && onUnlockAttempt(unlockKey)}
                />

                <button 
                    onClick={() => onUnlockAttempt(unlockKey)}
                    className="w-full py-4 bg-amber-600 hover:bg-amber-500 text-white rounded-2xl font-black transition-all shadow-xl active:scale-95 border-b-4 border-amber-800 mb-6"
                >
                    ODOMKNÚŤ SYSTÉM
                </button>

                <div className="w-full pt-6 border-t border-slate-700 flex flex-col items-center gap-4">
                    <button onClick={onLogout} className="text-slate-500 hover:text-white text-[10px] uppercase font-black tracking-widest transition-colors">Odhlásiť sa</button>

                    {/* EMERGENCY RECOVERY INFO */}
                    <div className="bg-slate-900/50 p-4 rounded-xl border border-white/5 text-center">
                        <p className="text-[9px] text-slate-600 font-bold uppercase mb-2">Zabudli ste kľúč?</p>
                        <a 
                            href="https://console.firebase.google.com/u/0/project/sklad-ulohy/firestore/databases/-default-/data/~2Fsystem_data~2Fconfig"
                            target="_blank"
                            rel="noopener noreferrer"
                            className="text-[9px] text-amber-500/60 hover:text-amber-400 font-black uppercase tracking-tighter underline"
                        >
                            Resetovať cez Firebase Console
                        </a>
                    </div>
                </div>
            </div>
        </div>
    );
  }

  return (
    <AppAuthenticated
      currentUser={currentUser}
      currentUserRole={currentUserRole}
      onLogout={onLogout}
      systemConfig={systemConfig}
      onUpdateSystemConfig={onUpdateSystemConfig}
      onUpdateAdminKey={onUpdateAdminKey}
      onToggleAdminLock={onToggleAdminLock}
      installPrompt={installPrompt}
      onInstallApp={onInstallApp}
    />
  );
};

// --- MAIN COMPONENT ---
const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'LEADER'>('USER');

  // Security Hooks
  const { 
    isUnlocked, 
    setIsUnlocked, 
    systemConfig, 
    handleUnlockAttempt, 
    handleUpdateAdminKey, 
    handleUpdateSystemConfig 
  } = useAppSecurity(currentUserRole, isAuthenticated);

  // Auth Restoration
  useEffect(() => {
    const storedUser = localStorage.getItem('app_user');
    const storedRole = localStorage.getItem('app_role');
    if (storedUser && storedRole) {
      setCurrentUser(storedUser);
      setCurrentUserRole(storedRole as any);
      setIsAuthenticated(true);
    }
  }, []);

  const handleLogin = (u: string, r: any) => { 
    setIsAuthenticated(true); 
    setCurrentUser(u); 
    setCurrentUserRole(r); 
    localStorage.setItem('app_user', u); 
    localStorage.setItem('app_role', r); 

    if (r !== 'ADMIN' || !systemConfig.adminLockEnabled) { 
        setIsUnlocked(true); 
        sessionStorage.setItem('app_unlocked', 'true'); 
    }
  };

  const handleLogout = useCallback(() => { 
    setIsAuthenticated(false); 
    setIsUnlocked(false);
    setCurrentUser(''); 
    setCurrentUserRole('USER'); 
    localStorage.removeItem('app_user'); 
    localStorage.removeItem('app_role'); 
    sessionStorage.removeItem('app_unlocked');
  }, [setIsUnlocked]);

  // PWA Logic
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallApp = () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    installPrompt.userChoice.then((result: any) => {
      if (result.outcome === 'accepted') setInstallPrompt(null);
    });
  };

  return (
    <div className={`min-h-screen bg-gray-900 flex flex-col ${!isAuthenticated ? 'items-center justify-center' : ''}`}>
       <DataProvider isAuthenticated={isAuthenticated} currentUserRole={currentUserRole}>
          <AppContent 
             isAuthenticated={isAuthenticated}
             currentUser={currentUser}
             currentUserRole={currentUserRole}
             onLoginSuccess={handleLogin}
             onLogout={handleLogout}
             systemConfig={systemConfig}
             isUnlocked={isUnlocked}
             onUnlockAttempt={handleUnlockAttempt}
             onUpdateAdminKey={handleUpdateAdminKey}
             onToggleAdminLock={(val: boolean) => handleUpdateSystemConfig({ adminLockEnabled: val })}
             onUpdateSystemConfig={handleUpdateSystemConfig}
             installPrompt={installPrompt}
             onInstallApp={handleInstallApp}
          />
       </DataProvider>
    </div>
  );
};

export default App;

import React, { useState, memo, useMemo } from 'react';
