  Check: () => <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>,
  Alert: () => <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>,
  Search: () => <svg className="w-4 h-4 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>,
  ChevronRight: () => <svg className="w-5 h-5 text-slate-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M9 5l7 7-7 7" /></svg>,
  Cube: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>
};

const ScrapWeighingTab: React.FC<ScrapWeighingTabProps> = (props) => {
  const { t, language } = useLanguage();

  const activeScrapTask = useMemo(() => {
      return (props.tasks || []).find(t => 
          t.partNumber === "Váženie šrotu" && 
          !t.isDone && 
          (t.inProgressBy === props.currentUser || t.createdBy === props.currentUser)
      );
  }, [props.tasks, props.currentUser]);

  // States pre modaly výberu
  const [isMetalModalOpen, setIsMetalModalOpen] = useState(false);
  const [metalSearch, setMetalSearch] = useState('');

  const [isBinModalOpen, setIsBinModalOpen] = useState(false);
  const [binSearchQuery, setBinSearchQuery] = useState('');

  const [selectedMetalId, setSelectedMetalId] = useState('');
  const [selectedBinId, setSelectedBinId] = useState('');
  const [gross, setGross] = useState('');
  const [tara, setTara] = useState(0);
  const [sessionRecords, setSessionRecords] = useState<ScrapRecord[]>([]);

  const [isFinishModalOpen, setIsFinishModalOpen] = useState(false);
  const [isCancelModalOpen, setIsCancelModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    if (!activeScrapTask) {
        setSessionRecords([]);
        return;
    }
    const storageKey = `scrap_weighing_${activeScrapTask.id}`;
    const saved = localStorage.getItem(storageKey);
    if (saved) {
        try { setSessionRecords(JSON.parse(saved)); } catch (e) { console.error(e); }
    }
  }, [activeScrapTask?.id]);

  useEffect(() => {
    if (activeScrapTask && sessionRecords.length >= 0) {
        localStorage.setItem(`scrap_weighing_${activeScrapTask.id}`, JSON.stringify(sessionRecords));
    }
  }, [sessionRecords, activeScrapTask?.id]);

  const netto = useMemo(() => {
    const g = parseFloat(gross) || 0;
    return Math.max(g - tara, 0);
  }, [gross, tara]);

  // Filtrovanie kovov v modale
  const filteredMetals = useMemo(() => {
    const q = metalSearch.toLowerCase().trim();
    if (!q) return props.metals;
    return props.metals.filter(m => m.type.toLowerCase().includes(q) || m.description.toLowerCase().includes(q));
  }, [props.metals, metalSearch]);

  // Filtrovanie kontajnerov v modale
  const filteredBins = useMemo(() => {
    const q = binSearchQuery.toLowerCase().trim();
    if (!q) return props.bins;
    return props.bins.filter(b => b.name.toLowerCase().includes(q));
  }, [props.bins, binSearchQuery]);

  const selectedMetalObj = useMemo(() => props.metals.find(m => m.id === selectedMetalId), [props.metals, selectedMetalId]);
  const selectedBinObj = useMemo(() => props.bins.find(b => b.id === selectedBinId), [props.bins, selectedBinId]);

  const handleSelectMetal = (m: ScrapMetal) => {
    setSelectedMetalId(m.id);
    setIsMetalModalOpen(false);
    setMetalSearch('');
  };

  const handleSelectBin = (b: ScrapBin) => {
    setSelectedBinId(b.id);
    setTara(b.tara);
    setIsBinModalOpen(false);
    setBinSearchQuery('');
  };

  const handleStartSession = () => {
      props.onAddTask("Váženie šrotu", "Váha šrotu", "0", "pallet", "NORMAL", true, "", true);
  };

  const handleAddItem = () => {
    if (!selectedMetalId || !selectedBinId || !gross) {
      alert(t('fill_all_fields'));
      return;
    }

    const newRecord: ScrapRecord = {
      id: crypto.randomUUID(),
      metalId: selectedMetalId,
      binId: selectedBinId,
      gross: parseFloat(gross),
      tara: tara,
      netto: netto,
      timestamp: Date.now(),
      worker: props.currentUser,
      taskId: activeScrapTask?.id || ''
    };

    setSessionRecords(prev => [newRecord, ...prev]);
    setGross('');
    setSelectedBinId('');
    setSelectedMetalId('');
    setTara(0);
  };

  const handleDeleteItem = (id: string) => {
      setSessionRecords(prev => prev.filter(r => r.id !== id));
  };

  const confirmCancelSession = async () => {
    if (activeScrapTask) {
        localStorage.removeItem(`scrap_weighing_${activeScrapTask.id}`);
        await props.onDeleteTask(activeScrapTask.id);
    }
    setSessionRecords([]);
    setIsCancelModalOpen(false);
  };

  const handleFinalize = async () => {
      if (!activeScrapTask || sessionRecords.length === 0) return;

      setIsSubmitting(true);
      try {
          await props.onBulkAddScrapRecords(sessionRecords);
          await props.onUpdateTask(activeScrapTask.id, {
              isDone: true,
              status: 'completed',
              completedBy: props.currentUser,
              completedAt: Date.now(),
              quantity: sessionRecords.length.toString(),
              quantityUnit: 'pallet',
              note: `Odvážené: ${sessionRecords.length} paliet`
          });
          localStorage.removeItem(`scrap_weighing_${activeScrapTask.id}`);
          setSessionRecords([]);
          setIsFinishModalOpen(false);
          alert(language === 'sk' ? `Váženie úspešne ukončené. Položky pridané do skladu.` : `Weighing finished successfully. Items added to warehouse.`);
      } catch (err) {
          console.error(err);
          alert("Chyba pri ukladaní dát.");
      } finally {
          setIsSubmitting(false);
      }
  };

  const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-3xl p-6 shadow-2xl backdrop-blur-sm relative overflow-hidden";
  const labelClass = "block text-[10px] font-black text-slate-500 uppercase tracking-[0.25em] mb-2";
  const inputClass = "w-full h-16 bg-slate-900/80 border-2 border-slate-700 rounded-xl px-4 text-white text-lg font-black focus:outline-none focus:border-teal-500/50 transition-all font-mono uppercase text-center";
  const triggerButtonClass = "w-full h-16 bg-slate-900/80 border-2 border-slate-700 rounded-xl px-4 flex items-center justify-between group hover:border-teal-500/50 transition-all text-left";

  return (
    <div className="max-w-6xl mx-auto space-y-8 animate-fade-in pb-20">

      {!activeScrapTask ? (
        <div className="flex flex-col items-center justify-center py-20 bg-gray-800/20 rounded-[3rem] border-2 border-dashed border-slate-800 space-y-10">
            <div className="text-center">
                <h2 className="text-4xl font-black text-white uppercase tracking-widest">{t('scrap_not_started')}</h2>
                <p className="text-slate-500 text-lg mt-4 font-bold uppercase tracking-widest">{t('scrap_start_hint')}</p>
            </div>
            <button 
                onClick={handleStartSession}
                className="bg-teal-600 hover:bg-teal-500 text-white font-black py-10 px-20 rounded-[2.5rem] shadow-[0_0_50px_rgba(20,184,166,0.3)] transition-all active:scale-95 uppercase tracking-[0.3em] text-3xl border-b-8 border-teal-800"
            >
                ⚖️ {t('scrap_start_btn')}
            </button>
        </div>
      ) : (
        <>
            <div className="flex flex-col md:row justify-between items-start md:items-center gap-6">
                <div>
                    <h1 className="text-3xl font-black text-teal-400 uppercase tracking-tighter leading-none">{t('scrap_active_session')}</h1>
                    <div className="flex items-center gap-3 mt-3">
                        <span className="bg-teal-500/20 text-teal-400 text-[9px] font-black px-3 py-1 rounded-full border border-teal-500/30 animate-pulse uppercase tracking-widest">LIVE RELÁCIA</span>
                        <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">Položiek: <span className="text-white">{sessionRecords.length}</span></p>
                    </div>
                </div>
                <button 
                    onClick={() => setIsCancelModalOpen(true)}
                    className="h-12 px-6 bg-red-900/20 hover:bg-red-900/40 text-red-500 border border-red-900/30 rounded-xl font-black uppercase text-[10px] tracking-widest transition-all"
                >
                    🛑 {t('scrap_cancel_session')}
                </button>
            </div>

            <div className={cardClass}>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 items-end">
                    {/* MODAL TRIGGER: VÝBER KOVU */}
                    <div className="relative">
                        <label className={labelClass}>{t('scrap_metal_select')}</label>
                        <button 
                            onClick={() => setIsMetalModalOpen(true)}
                            className={triggerButtonClass}
                        >
                            <div className="flex flex-col min-w-0">
                                <span className={`text-sm font-black uppercase truncate ${selectedMetalId ? 'text-white' : 'text-slate-600'}`}>
                                    {selectedMetalObj ? selectedMetalObj.type : 'VÝBER MATERIÁLU'}
                                </span>
                                {selectedMetalObj && (
                                    <span className="text-[10px] font-bold text-slate-500 uppercase truncate">{selectedMetalObj.description}</span>
                                )}
                            </div>
                            <Icons.ChevronRight />
                        </button>
                    </div>

                    {/* MODAL TRIGGER: VÝBER KONTAJNERA */}
                    <div className="relative">
                        <label className={labelClass}>{t('scrap_bin_select')}</label>
                        <button 
                            onClick={() => setIsBinModalOpen(true)}
                            className={triggerButtonClass}
                        >
                            <div className="flex flex-col min-w-0">
                                <span className={`text-sm font-black uppercase truncate ${selectedBinId ? 'text-white' : 'text-slate-600'}`}>
                                    {selectedBinObj ? selectedBinObj.name : 'VÝBER KONTAJNERA'}
                                </span>
                                {selectedBinObj && (
                                    <span className="text-[10px] font-bold text-teal-500 uppercase truncate">{selectedBinObj.tara} kg tara</span>
                                )}
                            </div>
                            <Icons.ChevronRight />
                        </button>
                    </div>

                    <div className="relative">
                        <label className={labelClass}>{t('scrap_gross')}</label>
                        <input type="number" inputMode="decimal" value={gross} onChange={e => setGross(e.target.value)} className={`${inputClass} !text-3xl text-teal-400`} placeholder="0" />
                        <span className="absolute right-4 bottom-5 text-xs font-black text-slate-600">KG</span>
                    </div>

                    <div className="bg-slate-950/50 p-4 rounded-xl border border-white/5 flex flex-col items-center justify-center h-16">
                        <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest leading-none mb-1">VÝSLEDNÉ NETTO</p>
                        <p className="text-2xl font-black text-white font-mono leading-none">{netto} <span className="text-xs font-normal text-slate-600">kg</span></p>
                    </div>
                </div>

                <button 
                    onClick={handleAddItem}
                    className="w-full mt-8 h-16 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black text-lg tracking-[0.2em] shadow-xl transition-all active:scale-95 border-b-4 border-teal-800"
                >
                    ⚖️ {t('scrap_btn_weigh')}
                </button>
            </div>

            <div className={cardClass}>
                <div className="flex flex-col sm:flex-row justify-between items-center mb-8 gap-4">
                    <h3 className="text-sm font-black text-slate-400 uppercase tracking-widest flex items-center gap-3">
                        <span className="w-1.5 h-4 bg-slate-500 rounded-full"></span>
                        {t('scrap_list_title')}
                    </h3>
                    <button 
                        onClick={() => setIsFinishModalOpen(true)} 
                        disabled={sessionRecords.length === 0}
                        className="w-full sm:w-auto h-14 px-10 bg-green-700 hover:bg-green-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest border-b-4 border-green-900 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 disabled:opacity-30 disabled:cursor-not-allowed"
                    >
                        <Icons.Check /> {t('scrap_btn_export')}
                    </button>
                </div>

                <div className="overflow-x-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-950/50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b border-slate-800">
                                <th className="p-4">Čas</th>
                                <th className="p-4">Typ kovu</th>
                                <th className="p-4">Kontajner</th>
                                <th className="p-4 text-right">Brutto</th>
                                <th className="p-4 text-right">Tara</th>
                                <th className="p-4 text-right">Netto</th>
                                <th className="p-4 w-16"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-800/50">
                            {sessionRecords.length > 0 ? (
                                sessionRecords.map(r => {
                                    const metal = props.metals.find(m => m.id === r.metalId);
                                    const bin = props.bins.find(b => b.id === r.binId);
                                    return (
                                        <tr key={r.id} className="hover:bg-white/[0.02] transition-colors group text-sm">
                                            <td className="p-4 text-slate-500 font-mono">{new Date(r.timestamp).toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' })}</td>
                                            <td className="p-4 font-black text-white uppercase">{metal?.type || '?'}</td>
                                            <td className="p-4 text-slate-400 font-bold uppercase">{bin?.name || '?'}</td>
                                            <td className="p-4 text-right text-slate-500 font-mono">{r.gross} kg</td>
                                            <td className="p-4 text-right text-slate-500 font-mono">{r.tara} kg</td>
                                            <td className="p-4 text-right font-black text-teal-400 font-mono">{r.netto} kg</td>
                                            <td className="p-4 text-center">
                                                <button onClick={() => handleDeleteItem(r.id)} className="text-slate-700 hover:text-red-500 transition-colors opacity-0 group-hover:opacity-100">
                                                    <Icons.Trash />
                                                </button>
                                            </td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr><td colSpan={7} className="py-20 text-center text-slate-700 font-black uppercase tracking-[0.3em] text-xs italic">Zatiaľ žiadne váženia v tejto relácii</td></tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </>
      )}

      {/* --- METAL SELECTION MODAL --- */}
      {isMetalModalOpen && createPortal(
          <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in" onClick={() => setIsMetalModalOpen(false)}>
              <div className="bg-slate-900 border-2 border-teal-500/50 rounded-[2.5rem] shadow-[0_0_100px_rgba(20,184,166,0.2)] w-full max-w-4xl p-8 sm:p-10 relative overflow-hidden flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
                  <div className="flex justify-between items-center mb-8 border-b border-white/5 pb-6">
                      <div>
                          <h3 className="text-3xl font-black text-white uppercase tracking-tighter">VÝBER KOVU</h3>
                          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Zvoľte typ materiálu pre váženie</p>
                      </div>
                      <button onClick={() => setIsMetalModalOpen(false)} className="text-slate-500 hover:text-white transition-colors text-2xl font-black p-2">×</button>
                  </div>

                  <div className="relative mb-6">
                      <input 
                          type="text"
                          value={metalSearch}
                          onChange={e => setMetalSearch(e.target.value.toUpperCase())}
                          placeholder="FILTROVAŤ MATERIÁL..."
                          className="w-full h-14 bg-slate-950 border-2 border-slate-800 rounded-2xl px-6 pl-14 text-white font-black uppercase focus:border-teal-500 outline-none transition-all shadow-inner"
                          autoFocus
                      />
                      <div className="absolute left-6 top-5"><Icons.Search /></div>
                  </div>

                  <div className="flex-grow overflow-y-auto custom-scrollbar pr-2 mb-8">
                      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                          {filteredMetals.map(m => (
                              <button
                                  key={m.id}
                                  onClick={() => handleSelectMetal(m)}
                                  className={`p-6 rounded-3xl border-2 transition-all flex flex-col items-start text-left group active:scale-[0.97] min-h-[140px] ${selectedMetalId === m.id ? 'bg-teal-600/10 border-teal-500 shadow-lg shadow-teal-500/20' : 'bg-slate-800/40 border-slate-700 hover:border-teal-500/40 hover:bg-slate-800'}`}
                              >
                                  <span className={`text-5xl font-black uppercase tracking-tight leading-none mb-2 ${selectedMetalId === m.id ? 'text-teal-400' : 'text-white'}`}>
                                      {m.type}
                                  </span>
                                  <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest leading-relaxed">
                                      {m.description || 'Bez popisu'}
                                  </span>
                              </button>
                          ))}
                          {filteredMetals.length === 0 && (
                              <div className="col-span-full py-20 text-center text-slate-600 font-black uppercase tracking-widest italic opacity-50">
                                  Nenašli sa žiadne materiály
                              </div>
                          )}
                      </div>
                  </div>

                  <button 
                      onClick={() => setIsMetalModalOpen(false)}
                      className="w-full py-5 bg-slate-800 hover:bg-slate-700 text-slate-400 hover:text-white rounded-2xl font-black uppercase text-xs tracking-[0.2em] transition-all border border-slate-700 shadow-inner"
                  >
                      {t('btn_cancel')}
                  </button>
              </div>
          </div>,
          document.body
      )}

      {/* --- BIN SELECTION MODAL --- */}
      {isBinModalOpen && createPortal(
          <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in" onClick={() => setIsBinModalOpen(false)}>
              <div className="bg-slate-900 border-2 border-blue-500/50 rounded-[2.5rem] shadow-[0_0_100px_rgba(59,130,246,0.2)] w-full max-w-4xl p-8 sm:p-10 relative overflow-hidden flex flex-col max-h-[90vh]" onClick={e => e.stopPropagation()}>
                  <div className="flex justify-between items-center mb-8 border-b border-white/5 pb-6">
                      <div>
                          <h3 className="text-3xl font-black text-white uppercase tracking-tighter">VÝBER KONTAJNERA</h3>
                          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Zvoľte kontajner pre váženie</p>
                      </div>
                      <button onClick={() => setIsBinModalOpen(false)} className="text-slate-500 hover:text-white transition-colors text-2xl font-black p-2">×</button>
                  </div>

                  <div className="relative mb-6">
                      <input 
                          type="text"
                          value={binSearchQuery}
                          onChange={e => setBinSearchQuery(e.target.value.toUpperCase())}
                          placeholder="FILTROVAŤ KONTAJNERY..."
                          className="w-full h-14 bg-slate-950 border-2 border-slate-800 rounded-2xl px-6 pl-14 text-white font-black uppercase focus:border-blue-500 outline-none transition-all shadow-inner"
                          autoFocus
                      />
                      <div className="absolute left-6 top-5"><Icons.Search /></div>
                  </div>

                  <div className="flex-grow overflow-y-auto custom-scrollbar pr-2 mb-8">
                      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                          {filteredBins.map(b => (
                              <button
                                  key={b.id}
                                  onClick={() => handleSelectBin(b)}
                                  className={`p-6 rounded-3xl border-2 transition-all flex flex-col items-start text-left group active:scale-[0.97] min-h-[100px] ${selectedBinId === b.id ? 'bg-blue-600/10 border-blue-500 shadow-lg shadow-blue-500/20' : 'bg-slate-800/40 border-slate-700 hover:border-blue-500/40 hover:bg-slate-800'}`}
                              >
                                  <div className="flex justify-between items-start w-full mb-2">
                                      <span className={`text-3xl font-black uppercase tracking-tight leading-none ${selectedBinId === b.id ? 'text-blue-400' : 'text-white'}`}>
                                          {b.name}
                                      </span>
                                      <div className="p-2 bg-slate-950/50 rounded-lg text-teal-400">
                                          <Icons.Cube />
                                      </div>
                                  </div>
                                  <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mt-auto">
                                      Tara: <span className="text-white">{b.tara} kg</span>
                                  </span>
                              </button>
                          ))}
                          {filteredBins.length === 0 && (
                              <div className="col-span-full py-20 text-center text-slate-600 font-black uppercase tracking-widest italic opacity-50">
                                  Nenašli sa žiadne kontajnery
                              </div>
                          )}
                      </div>
                  </div>

                  <button 
                      onClick={() => setIsBinModalOpen(false)}
                      className="w-full py-5 bg-slate-800 hover:bg-slate-700 text-slate-400 hover:text-white rounded-2xl font-black uppercase text-xs tracking-[0.2em] transition-all border border-slate-700 shadow-inner"
                  >
                      {t('btn_cancel')}
                  </button>
              </div>
          </div>,
          document.body
      )}

      {/* --- FINISH CONFIRMATION MODAL --- */}
      {isFinishModalOpen && createPortal(
          <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in" onClick={() => !isSubmitting && setIsFinishModalOpen(false)}>
              <div className="bg-slate-900 border-2 border-teal-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden text-center" onClick={e => e.stopPropagation()}>
                  <div className="w-20 h-20 bg-teal-500/10 border border-teal-500/30 rounded-full flex items-center justify-center mx-auto mb-6 text-teal-500">
                      <Icons.Scale />
                  </div>
                  <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-4">
                      {language === 'sk' ? 'UKONČIŤ RELÁCIU?' : 'FINISH SESSION?'}
                  </h3>

                  <p className="text-sm text-slate-400 font-bold uppercase leading-relaxed mb-10">
                    {language === 'sk' 
                      ? `Naozaj chcete ukončiť váženie a uložiť ${sessionRecords.length} položiek do skladu šrotu?` 
                      : `Do you want to finish weighing and save ${sessionRecords.length} items to scrap warehouse?`
                    }
                  </p>

                  <div className="grid grid-cols-2 gap-4">
                      <button 
                        disabled={isSubmitting}
                        onClick={() => setIsFinishModalOpen(false)} 
                        className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all disabled:opacity-30"
                      >
                        ZRUŠIŤ
                      </button>
                      <button 
                        disabled={isSubmitting}
                        onClick={handleFinalize} 
                        className="h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 disabled:bg-slate-700 disabled:border-slate-800"
                      >
                        {isSubmitting ? 'UKLADÁM...' : <><Icons.Check /> POTVRDIŤ KONIEC</>}
                      </button>
                  </div>
              </div>
          </div>,
          document.body
      )}

      {/* --- CANCEL CONFIRMATION MODAL --- */}
      {isCancelModalOpen && createPortal(
          <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in" onClick={() => setIsCancelModalOpen(false)}>
              <div className="bg-slate-900 border-2 border-red-600 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden text-center" onClick={e => e.stopPropagation()}>
                  <div className="w-20 h-20 bg-red-600/10 border border-red-600/30 rounded-full flex items-center justify-center mx-auto mb-6 text-red-500">
                      <Icons.Alert />
                  </div>
                  <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-4">
                      {language === 'sk' ? 'ZRUŠIŤ VÁŽENIE?' : 'CANCEL WEIGHING?'}
                  </h3>

                  <div className="bg-red-900/10 border border-red-900/30 p-4 rounded-xl mb-10">
                    <p className="text-sm text-red-400 font-bold uppercase leading-relaxed">
                        {language === 'sk' 
                            ? "POZOR! Všetky doteraz odvážené položky v tejto relácii budú nenávratne vymazané z pamäte tabletu a úloha bude zrušená." 
                            : "WARNING! All items weighed in this session will be permanently deleted from tablet memory and the task will be cancelled."
                        }
                    </p>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                      <button 
                        onClick={() => setIsCancelModalOpen(false)} 
                        className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all"
                      >
                        {t('btn_cancel')}
                      </button>
                      <button 
                        onClick={confirmCancelSession} 
                        className="h-14 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-red-800 shadow-xl transition-all active:scale-95"
                      >
                        {language === 'sk' ? 'POTVRDIŤ ZMAZANIE' : 'CONFIRM DELETE'}
                      </button>
                  </div>
              </div>
          </div>,
          document.body
      )}

    </div>
  );
};

export default ScrapWeighingTab;

import React, { useState, useMemo, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { ScrapRecord, ScrapBin, ScrapMetal, ScrapPrice } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

interface ScrapWarehouseTabProps {
    currentUser: string;
    actualScrap: ScrapRecord[];
    bins: ScrapBin[];
    metals: ScrapMetal[];
    prices: ScrapPrice[];
    onDeleteRecord: (id: string) => Promise<void>;
    onUpdateRecord: (id: string, updates: Partial<ScrapRecord>) => Promise<void>;
    onExpedite: (worker: string, dispatchDate: string) => Promise<string | undefined>;
    resolveName: (username?: string | null) => string;
}

declare var jspdf: any;

const Icons = {
    Dispatch: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>,
    Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
    Edit: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>,
    Box: () => <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" /></svg>,
    FileText: () => <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>,
    Alert: () => <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>,
    Check: () => <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M5 13l4 4L19 7" /></svg>,
};

const ScrapWarehouseTab: React.FC<ScrapWarehouseTabProps> = (props) => {
    const { t, language } = useLanguage();

    // State pre modaly
    const [isExpediteModalOpen, setIsExpediteModalOpen] = useState(false);
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);
    const [isDeliveryNoteModalOpen, setIsDeliveryNoteModalOpen] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isDeliveryNoteGenerated, setIsDeliveryNoteGenerated] = useState(false);

    // State pre expedíciu
    const [dispatchDate, setDispatchDate] = useState(new Date().toISOString().split('T')[0]);

    // State pre editáciu
    const [editingItem, setEditingItem] = useState<ScrapRecord | null>(null);
    const [editGross, setEditGross] = useState('');
    const [editMetalId, setEditMetalId] = useState('');
    const [editBinId, setEditBinId] = useState('');

    // Reset stavu vygenerovaného listu pri zmene obsahu skladu
    useEffect(() => {
        setIsDeliveryNoteGenerated(false);
    }, [props.actualScrap.length]);

    // Výpočet aktuálnej hodnoty skladu
    const currentWarehouseValue = useMemo(() => {
        const now = new Date();
        const month = now.getMonth() + 1;
        const year = now.getFullYear();

        return props.actualScrap.reduce((acc, item) => {
            const priceObj = props.prices.find(p => p.metalId === item.metalId && p.month === month && p.year === year);
            const price = priceObj?.price || 0;
            return acc + (item.netto * price);
        }, 0);
    }, [props.actualScrap, props.prices]);

    const handleOpenEdit = (item: ScrapRecord) => {
        setEditingItem(item);
        setEditGross(String(item.gross ?? '0'));
        setEditMetalId(item.metalId || '');
        setEditBinId(item.binId || '');
        setIsEditModalOpen(true);
    };

    const handleSaveEdit = async () => {
        if (!editingItem || !editGross || !editMetalId || !editBinId) return;

        const bin = props.bins.find(b => b.id === editBinId);
        const grossVal = parseFloat(editGross) || 0;
        const taraVal = bin ? bin.tara : 0;

        await props.onUpdateRecord(editingItem.id, {
            metalId: editMetalId,
            binId: editBinId,
            gross: grossVal,
            tara: taraVal,
            netto: Math.max(grossVal - taraVal, 0)
        });

        setIsEditModalOpen(false);
        setEditingItem(null);
    };

    const confirmDeliveryNote = () => {
        if (props.actualScrap.length === 0 || typeof jspdf === 'undefined') return;

        const { jsPDF } = jspdf;
        const doc = new jsPDF();

        // 1. Hlavička
        doc.setFontSize(22);
        doc.setTextColor(0, 0, 0);
        doc.setFont("helvetica", "bold");
        doc.text("CLAMASON SLOVAKIA", 20, 25);

        doc.setFontSize(12);
        doc.text("DODACI LIST - KOVOVY ODPAD", 20, 32);

        // 2. Info blok
        doc.setFontSize(10);
        doc.setFont("helvetica", "normal");
        const dateStr = new Date().toLocaleDateString('sk-SK');
        const timeStr = new Date().toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' });
        doc.text(`Datum vystavenia: ${dateStr}`, 140, 25);
        doc.text(`Cas vystavenia: ${timeStr}`, 140, 30);
        doc.text(`Vystavil: ${props.resolveName(props.currentUser)}`, 140, 35);

        doc.setLineWidth(0.5);
        doc.line(20, 40, 190, 40);

        // 3. Tabuľka dát
        const tableBody = props.actualScrap.map(r => {
            const metal = props.metals.find(m => m.id === r.metalId);
            const bin = props.bins.find(b => b.id === r.binId);
            return [
                new Date(r.timestamp).toLocaleDateString('sk-SK'),
                metal?.type || '???',
                bin?.name || '???',
                r.gross.toString(),
                r.tara.toString(),
                r.netto.toString()
            ];
        });

        (doc as any).autoTable({
            startY: 50,
            head: [['Datum vazenia', 'Material', 'Kontajner', 'Brutto (kg)', 'Tara (kg)', 'Netto (kg)']],
            body: tableBody,
            theme: 'grid',
            headStyles: { fillColor: [240, 240, 240], textColor: [0, 0, 0], fontStyle: 'bold' },
            styles: { fontSize: 9, cellPadding: 3 },
            columnStyles: {
                3: { halign: 'right' },
                4: { halign: 'right' },
                5: { halign: 'right', fontStyle: 'bold' }
            }
        });

        let finalY = (doc as any).lastAutoTable.finalY || 70;

        // Kontrola pretečenia na novú stranu pre sumáre
        if (finalY > 170) { 
            doc.addPage();
            finalY = 20; 
        }

        // --- SUMÁR PODĽA MATERIÁLU ---
        const metalSummaryMap: Record<string, { weight: number, desc: string }> = {};
        props.actualScrap.forEach(r => {
            const metal = props.metals.find(m => m.id === r.metalId);
            const name = metal?.type || 'Neznamy';
            const desc = metal?.description || '';
            if (!metalSummaryMap[name]) {
                metalSummaryMap[name] = { weight: 0, desc };
            }
            metalSummaryMap[name].weight += r.netto;
        });

        doc.setFontSize(10);
        doc.setFont("helvetica", "bold");
        doc.text("SUMAR CISTEJ VAHY PODLA MATERIALU (NETTO):", 20, finalY + 12);
        doc.setFont("helvetica", "normal");

        let summaryY = finalY + 18;
        Object.entries(metalSummaryMap).forEach(([name, data]) => {
            const label = data.desc ? `${name} (${data.desc}):` : `${name}:`;
            doc.text(label, 20, summaryY);
            doc.setFont("helvetica", "bold");
            // Posunutý totál váhy na pravý okraj (190)
            doc.text(`${data.weight} kg`, 190, summaryY, { align: 'right' });
            doc.setFont("helvetica", "normal");
            summaryY += 6;
        });

        // 4. Celkové Totály
        const totalGross = props.actualScrap.reduce((acc, curr) => acc + curr.gross, 0);
        const itemCount = props.actualScrap.length;

        doc.setLineWidth(0.2);
        // Roztiahnutá čiara pod sumárom na celú šírku
        doc.line(20, summaryY + 2, 190, summaryY + 2);

        doc.setFontSize(11);
        doc.setFont("helvetica", "bold");
        doc.text(`CELKOVA HMOTNOST BRUTTO: ${totalGross} kg`, 20, summaryY + 10);
        doc.setFontSize(10);
        doc.setFont("helvetica", "normal");
        doc.text(`POCET POLOZIEK: ${itemCount}`, 20, summaryY + 16);

        // --- DOPLNKOVÉ INFORMÁCIE ---
        doc.setFontSize(9);
        doc.setFont("helvetica", "bold");
        doc.text("DOPLNKOVE INFORMACIE:", 20, summaryY + 26);
        doc.setDrawColor(200, 200, 200);
        doc.rect(20, summaryY + 28, 170, 20); // Prázdny box na poznámky

        // 5. Dátum expedície a podpisy
        doc.setFontSize(10);
        doc.setTextColor(0, 0, 0);
        doc.text(`DATUM EXPEDICIE: ...........................................`, 20, summaryY + 58);

        const signatureY = summaryY + 90;
        doc.setLineWidth(0.2);
        doc.line(20, signatureY, 80, signatureY);
        doc.line(120, signatureY, 180, signatureY);

        doc.setFontSize(8);
        doc.setFont("helvetica", "normal");
        doc.text("Odovzdal (Clamason Slovakia)", 30, signatureY + 5);
        doc.text("Prevzal (Dopravca)", 135, signatureY + 5);

        // 6. Finálna pätička s číslovaním strán
        const totalPages = doc.internal.getNumberOfPages();
        for (let i = 1; i <= totalPages; i++) {
            doc.setPage(i);
            doc.setFontSize(8);
            doc.setTextColor(150, 150, 150);
            doc.text("Vygenerovane systemom Clamason Task Manager Intelligence", 105, 285, { align: 'center' });
            doc.text(`Strana ${i} / ${totalPages}`, 190, 285, { align: 'right' });
        }

        // 7. Uloženie
        doc.save(`Dodaci_list_srot_${new Date().toISOString().split('T')[0]}.pdf`);

        setIsDeliveryNoteGenerated(true);
        setIsDeliveryNoteModalOpen(false);
    };

    const handleExpediteConfirm = async () => {
        if (!dispatchDate) {
            alert(language === 'sk' ? "Vyberte dátum expedície." : "Select dispatch date.");
            return;
        }
        setIsSubmitting(true);
        try {
            const sanonId = await props.onExpedite(props.currentUser, dispatchDate);
            if (sanonId) {
                alert(language === 'sk' ? `Expedícia úspešná. Archív: ${sanonId}` : `Expedition successful. Archive: ${sanonId}`);
                setIsExpediteModalOpen(false);
                setIsDeliveryNoteGenerated(false);
            }
        } catch (e) {
            alert("Chyba pri expedícii.");
        } finally {
            setIsSubmitting(false);
        }
    };

    const totalNetto = useMemo(() => props.actualScrap.reduce((acc, curr) => acc + curr.netto, 0), [props.actualScrap]);

    const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-3xl p-6 shadow-2xl backdrop-blur-sm relative overflow-hidden";
    const labelClass = "block text-[10px] font-black text-slate-500 uppercase tracking-[0.25em] mb-2";
    const inputClass = "w-full h-14 bg-slate-900/80 border-2 border-slate-700 rounded-xl px-4 text-white text-lg font-black focus:outline-none focus:border-teal-500/50 transition-all font-mono uppercase text-center";

    return (
        <div className="max-w-7xl mx-auto space-y-8 animate-fade-in pb-20">

            {/* UI HEADER AREA */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 no-print">
                <div>
                    <h1 className="text-3xl font-black text-white uppercase tracking-tighter leading-none">{t('scrap_warehouse_title')}</h1>
                    <div className="flex flex-wrap items-center gap-3 mt-3">
                        <span className="bg-indigo-500/20 text-indigo-400 text-[9px] font-black px-3 py-1 rounded-full border border-indigo-500/30 uppercase tracking-widest">AKTUÁLNY SKLAD</span>
                        <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">Položiek: <span className="text-white">{props.actualScrap.length}</span></p>
                        <div className="w-1 h-1 rounded-full bg-slate-700 mx-1"></div>
                        <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">Odhadovaná hodnota: <span className="text-amber-400 font-black">{currentWarehouseValue.toLocaleString('sk-SK', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} €</span></p>
                    </div>
                </div>

                <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
                    {/* BUTTON: DELIVERY NOTE (PDF) */}
                    <button 
                        disabled={props.actualScrap.length === 0}
                        onClick={() => setIsDeliveryNoteModalOpen(true)}
                        className="w-full sm:w-auto h-14 px-10 bg-emerald-600 hover:bg-emerald-500 disabled:opacity-30 disabled:cursor-not-allowed text-white rounded-2xl font-black text-sm uppercase tracking-widest border-b-4 border-emerald-900 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3"
                    >
                        <Icons.FileText /> {t('scrap_btn_delivery_note')}
                    </button>

                    {/* BUTTON: EXPEDITE */}
                    <button 
                        disabled={props.actualScrap.length === 0 || !isDeliveryNoteGenerated}
                        onClick={() => setIsExpediteModalOpen(true)}
                        className={`w-full sm:w-auto h-14 px-10 bg-indigo-600 hover:bg-indigo-500 disabled:opacity-30 disabled:cursor-not-allowed text-white rounded-2xl font-black text-sm uppercase tracking-widest border-b-4 border-indigo-900 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 ${!isDeliveryNoteGenerated && props.actualScrap.length > 0 ? 'ring-2 ring-indigo-500 ring-offset-4 ring-offset-gray-900 animate-pulse' : ''}`}
                    >
                        <Icons.Dispatch /> {t('scrap_btn_dispatch')}
                    </button>
                </div>
            </div>

            {/* LIST AREA */}
            <div className={`${cardClass} no-print`}>
                <div className="overflow-x-auto custom-scrollbar">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-slate-950/50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b border-slate-800">
                                <th className="p-4">Dátum / Čas</th>
                                <th className="p-4">Skladník</th>
                                <th className="p-4">Typ kovu</th>
                                <th className="p-4">Kontajner</th>
                                <th className="p-4 text-right">Netto (kg)</th>
                                <th className="p-4 w-24"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-800/50">
                            {props.actualScrap.length > 0 ? (
                                props.actualScrap.map(r => {
                                    const metal = props.metals.find(m => m.id === r.metalId);
                                    const bin = props.bins.find(b => b.id === r.binId);
                                    return (
                                        <tr key={r.id} className="hover:bg-white/[0.02] transition-colors group text-sm">
                                            <td className="p-4">
                                                <div className="text-white font-bold">{new Date(r.timestamp).toLocaleDateString('sk-SK')}</div>
                                                <div className="text-[10px] text-slate-500 font-mono">{new Date(r.timestamp).toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' })}</div>
                                            </td>
                                            <td className="p-4 text-slate-300 font-bold uppercase">{props.resolveName(r.worker)}</td>
                                            <td className="p-4 font-black text-white uppercase">{metal?.type || '???'}</td>
                                            <td className="p-4 text-slate-400 font-bold uppercase">{bin?.name || '???'}</td>
                                            <td className="p-4 text-right font-black text-teal-400 font-mono text-lg">{r.netto} kg</td>
                                            <td className="p-4 text-center">
                                                <div className="flex gap-2 justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button onClick={() => handleOpenEdit(r)} className="p-2 bg-slate-800 text-teal-400 hover:text-white hover:bg-teal-600 rounded-lg transition-all">
                                                        <Icons.Edit />
                                                    </button>
                                                    <button onClick={() => { if(window.confirm(t('confirm_delete_msg'))) props.onDeleteRecord(r.id); }} className="p-2 bg-slate-800 text-red-500 hover:text-white hover:bg-red-600 rounded-lg transition-all">
                                                        <Icons.Trash />
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={6} className="py-32 text-center text-slate-700">
                                        <div className="flex flex-col items-center gap-4">
                                            <Icons.Box />
                                            <p className="font-black uppercase tracking-[0.3em] text-xs italic">{t('scrap_empty_warehouse')}</p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* DELIVERY NOTE CONFIRMATION MODAL */}
            {isDeliveryNoteModalOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in no-print" onClick={() => setIsDeliveryNoteModalOpen(false)}>
                    <div className="bg-slate-900 border-2 border-emerald-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden text-center" onClick={e => e.stopPropagation()}>
                        <div className="w-20 h-20 bg-emerald-500/10 border border-emerald-500/30 rounded-full flex items-center justify-center mx-auto mb-6 text-emerald-500">
                            <Icons.FileText />
                        </div>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-4">
                            {language === 'sk' ? 'STIAHNUŤ DODACÍ LIST?' : 'DOWNLOAD DELIVERY NOTE?'}
                        </h3>

                        <p className="text-sm text-slate-400 font-bold uppercase leading-relaxed mb-10">
                            {language === 'sk' 
                                ? "Systém vygeneruje a stiahne profesionálny PDF dokument. Po stiahnutí sa odomkne možnosť finálnej expedície šrotu do archívu." 
                                : "The system will generate and download a professional PDF document. After downloading, the option for final scrap expedition to archive will be unlocked."
                            }
                        </p>

                        <div className="grid grid-cols-2 gap-4">
                            <button 
                                onClick={() => setIsDeliveryNoteModalOpen(false)} 
                                className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all"
                            >
                                {t('btn_cancel')}
                            </button>
                            <button 
                                onClick={confirmDeliveryNote} 
                                className="h-14 bg-emerald-600 hover:bg-emerald-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-emerald-800 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2"
                            >
                                <Icons.Check /> {language === 'sk' ? 'STIAHNUŤ PDF' : 'DOWNLOAD PDF'}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

            {/* EXPEDITE MODAL */}
            {isExpediteModalOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in no-print" onClick={() => !isSubmitting && setIsExpediteModalOpen(false)}>
                    <div className="bg-slate-900 border-2 border-indigo-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden text-center" onClick={e => e.stopPropagation()}>
                        <div className="w-20 h-20 bg-indigo-500/10 border border-indigo-500/30 rounded-full flex items-center justify-center mx-auto mb-6 text-indigo-500">
                            <Icons.Dispatch />
                        </div>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-4">
                            {t('scrap_dispatch_modal_title')}
                        </h3>

                        <div className="space-y-4 mb-10">
                            <p className="text-sm text-slate-400 font-bold uppercase leading-relaxed">
                                {t('scrap_dispatch_modal_desc')}
                                <br />
                                <span className="text-white text-lg font-black">{props.actualScrap.length} položiek</span>
                            </p>

                            <div className="mt-6">
                                <label className={labelClass}>{t('scrap_dispatch_date')}</label>
                                <input 
                                    type="date" 
                                    value={dispatchDate} 
                                    onChange={e => setDispatchDate(e.target.value)}
                                    className={inputClass}
                                />
                                <p className="text-[10px] text-slate-500 mt-2 font-bold uppercase italic">* Tento dátum určí názov archívneho šanónu.</p>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <button 
                                disabled={isSubmitting}
                                onClick={() => setIsExpediteModalOpen(false)} 
                                className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all disabled:opacity-30"
                            >
                                ZRUŠIŤ
                            </button>
                            <button 
                                disabled={isSubmitting}
                                onClick={handleExpediteConfirm} 
                                className="h-14 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-indigo-800 shadow-xl transition-all active:scale-95 flex items-center justify-center gap-2 disabled:bg-slate-700 disabled:border-slate-800"
                            >
                                {isSubmitting ? '...' : 'POTVRDIŤ EXPEDÍCIU'}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

            {/* EDIT MODAL */}
            {isEditModalOpen && editingItem && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in no-print" onClick={() => setIsEditModalOpen(false)}>
                    <div className="bg-slate-900 border-2 border-teal-500/50 rounded-[2.5rem] shadow-2xl w-full max-w-lg p-10 relative overflow-hidden" onClick={e => e.stopPropagation()}>
                        <h3 className="text-3xl font-black text-white uppercase tracking-tighter mb-8 flex items-center gap-3">
                            <Icons.Edit /> {t('scrap_edit_title')}
                        </h3>

                        <div className="space-y-6 mb-10">
                            <div>
                                <label className={labelClass}>{t('scrap_metal_select')}</label>
                                <select value={editMetalId} onChange={e => setEditMetalId(e.target.value)} className={inputClass}>
                                    {props.metals.map(m => <option key={m.id} value={m.id}>{m.type}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={labelClass}>{t('scrap_bin_select')}</label>
                                <select value={editBinId} onChange={e => setEditBinId(e.target.value)} className={inputClass}>
                                    {props.bins.map(b => <option key={b.id} value={b.id}>{b.name}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className={labelClass}>{t('scrap_gross')}</label>
                                <input type="number" value={editGross} onChange={e => setEditGross(e.target.value)} className={`${inputClass} !text-3xl text-teal-400`} />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => setIsEditModalOpen(false)} className="h-14 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase text-xs tracking-widest hover:text-white transition-all">ZRUŠIŤ</button>
                            <button onClick={handleSaveEdit} className="h-14 bg-teal-600 hover:bg-teal-500 text-white rounded-2xl font-black uppercase text-xs tracking-widest border-b-4 border-teal-800 shadow-xl transition-all active:scale-95">ULOŽIŤ ZMENY</button>
                        </div>
                    </div>
                </div>,
                document.body
            )}

        </div>
    );
};

export default ScrapWarehouseTab;

import React, { useState, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { ScrapRecord, ScrapBin, ScrapMetal, ScrapPrice } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

interface ScrapArchiveTabProps {
    scrapArchives: any[];
    bins: ScrapBin[];
    metals: ScrapMetal[];
    prices: ScrapPrice[];
    onUpdateArchivedItem: (sanonId: string, itemId: string, updates: Partial<ScrapRecord>) => Promise<void>;
    onUpdateScrapArchive: (sanonId: string, updates: any) => Promise<void>;
    onDeleteArchivedItem: (sanonId: string, itemId: string) => Promise<void>;
    onDeleteArchive: (id: string) => Promise<void>;
    onFetchArchives: (from: string, to: string) => Promise<any[]>;
    resolveName: (username?: string | null) => string;
    hasPermission: (perm: string) => boolean;
}

declare var XLSX: any;

const Icons = {
    Archive: () => <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" /></svg>,
    Edit: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>,
    Trash: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
    ChevronDown: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg>,
    Calendar: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>,
    Download: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>,
    Dollar: () => <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>,
    Refresh: () => <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
};

const ScrapArchiveTab: React.FC<ScrapArchiveTabProps> = (props) => {
    const { t, language } = useLanguage();

    // State pre filtre
    const [dateFrom, setDateFrom] = useState(new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0]);
    const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);
    const [isLoading, setIsLoading] = useState(false);
    const [hasLoaded, setHasLoaded] = useState(false);

    // State pre interakciu s položkami
    const [expandedSanonId, setExpandedSanonId] = useState<string | null>(null);
    const [editingItem, setEditingItem] = useState<{ sanonId: string, item: ScrapRecord } | null>(null);
    const [editGross, setEditGross] = useState('');
    const [editMetalId, setEditMetalId] = useState('');
    const [editBinId, setEditBinId] = useState('');

    // State pre úpravu ceny odberateľa
    const [isExternalValueModalOpen, setIsExternalValueModalOpen] = useState(false);
    const [targetSanonId, setTargetSanonId] = useState<string | null>(null);
    const [externalValInput, setExternalValInput] = useState('');

    const sortedArchives = useMemo(() => {
        return [...props.scrapArchives].sort((a, b) => {
            const dateA = new Date(a.dispatchDate).getTime();
            const dateB = new Date(b.dispatchDate).getTime();
            return dateB - dateA;
        });
    }, [props.scrapArchives]);

    // HANDLER: Načítanie histórie na vyžiadanie
    const handleLoadArchives = async () => {
        setIsLoading(true);
        try {
            await props.onFetchArchives(dateFrom, dateTo);
            setHasLoaded(true);
        } finally {
            setIsLoading(false);
        }
    };

    // Pomocná funkcia na výpočet hodnoty šanónu
    const calculateSanonValue = (items: ScrapRecord[], dispatchDate: string) => {
        const dateObj = new Date(dispatchDate);
        const month = dateObj.getMonth() + 1;
        const year = dateObj.getFullYear();

        return items.reduce((acc, item) => {
            const priceObj = props.prices.find(p => p.metalId === item.metalId && p.month === month && p.year === year);
            const price = priceObj?.price || 0;
            return acc + (item.netto * price);
        }, 0);
    };

    const handleOpenEdit = (sanonId: string, item: ScrapRecord) => {
        setEditingItem({ sanonId, item });
        setEditGross(String(item.gross));
        setEditMetalId(item.metalId);
        setEditBinId(item.binId);
    };

    const handleSaveEdit = async () => {
        if (!editingItem) return;
        const bin = props.bins.find(b => b.id === editBinId);
        const grossVal = parseFloat(editGross) || 0;
        const taraVal = bin ? bin.tara : 0;

        await props.onUpdateArchivedItem(editingItem.sanonId, editingItem.item.id, {
            metalId: editMetalId,
            binId: editBinId,
            gross: grossVal,
            tara: taraVal,
            netto: Math.max(grossVal - taraVal, 0)
        });
        setEditingItem(null);
    };

    const handleOpenExternalValue = (sanon: any) => {
        setTargetSanonId(sanon.id);
        setExternalValInput(String(sanon.externalValue || ''));
        setIsExternalValueModalOpen(true);
    };

    const handleSaveExternalValue = async () => {
        if (!targetSanonId) return;
        await props.onUpdateScrapArchive(targetSanonId, {
            externalValue: parseFloat(externalValInput) || 0
        });
        setIsExternalValueModalOpen(false);
        setTargetSanonId(null);
    };

    const handleExportSanon = (archive: any) => {
        if (typeof XLSX === 'undefined') return;

        const data = (archive.items || []).map((item: ScrapRecord) => {
            const metal = props.metals.find(m => m.id === item.metalId);
            const bin = props.bins.find(b => b.id === item.binId);
            return {
                "Datum expedicie": new Date(archive.dispatchDate).toLocaleDateString('sk-SK'),
                "Datum vazenia": new Date(item.timestamp).toLocaleDateString('sk-SK'),
                "Cas vazenia": new Date(item.timestamp).toLocaleTimeString('sk-SK'),
                "Material": metal?.type || '???',
                "Popis materialu": metal?.description || '-',
                "Kontajner": bin?.name || '???',
                "Brutto (kg)": item.gross,
                "Tara (kg)": item.tara,
                "Netto (kg)": item.netto,
                "Vystavil (Worker)": props.resolveName(item.worker)
            };
        });

        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Export");
        XLSX.writeFile(wb, `Srot_Export_${archive.id}_${archive.dispatchDate}.xlsx`);
    };

    const handleConfirmDeleteSanon = (id: string, date: string) => {
        const msg = language === 'sk' 
            ? `Naozaj chcete vymazať celý archívny šanón zo dňa ${date}? Táto akcia je nevratná.` 
            : `Are you sure you want to delete the entire archive from ${date}? This action is irreversible.`;
        if (window.confirm(msg)) {
            props.onDeleteArchive(id);
        }
    };

    const handleConfirmDeleteItem = (sanonId: string, itemId: string) => {
        const msg = language === 'sk' 
            ? "Naozaj chcete vymazať túto položku z archívu?" 
            : "Are you sure you want to delete this item from the archive?";
        if (window.confirm(msg)) {
            props.onDeleteArchivedItem(sanonId, itemId);
        }
    };

    const labelClass = "block text-[10px] font-black text-slate-500 uppercase tracking-[0.25em] mb-2";
    const inputClass = "w-full h-14 bg-slate-900/80 border-2 border-slate-700 rounded-xl px-4 text-white text-lg font-black focus:outline-none focus:border-teal-500/50 transition-all font-mono uppercase text-center";

    return (
        <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in">
            {/* HLAVIČKA A FILTER */}
            <div className="bg-slate-900 border border-slate-700 rounded-3xl p-6 shadow-2xl space-y-6">
                <div className="flex items-center gap-4 border-b border-slate-800 pb-4">
                    <div className="p-3 bg-indigo-500/20 rounded-2xl border border-indigo-500/30 text-indigo-400">
                        <Icons.Archive />
                    </div>
                    <div>
                        <h1 className="text-2xl font-black text-white uppercase tracking-tighter leading-none">{t('scrap_archive_title')}</h1>
                        <p className="text-slate-500 text-[10px] font-bold uppercase tracking-widest mt-1">História expedícií a vývozov</p>
                    </div>
                </div>

                <div className="flex flex-col md:flex-row items-end gap-4">
                    <div className="flex-1 grid grid-cols-2 gap-4 w-full">
                        <div>
                            <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1 mb-1 block">Dátum Od</label>
                            <input 
                                type="date" 
                                value={dateFrom} 
                                onChange={e => setDateFrom(e.target.value)} 
                                className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-2.5 text-white text-sm outline-none focus:border-indigo-500 transition-all" 
                            />
                        </div>
                        <div>
                            <label className="text-[9px] font-black text-slate-500 uppercase tracking-widest ml-1 mb-1 block">Dátum Do</label>
                            <input 
                                type="date" 
                                value={dateTo} 
                                onChange={e => setDateTo(e.target.value)} 
                                className="w-full bg-slate-800 border border-slate-700 rounded-xl px-4 py-2.5 text-white text-sm outline-none focus:border-indigo-500 transition-all" 
                            />
                        </div>
                    </div>
                    <button 
                        onClick={handleLoadArchives}
                        disabled={isLoading}
                        className={`w-full md:w-auto h-11 px-8 rounded-xl font-black text-[11px] uppercase tracking-widest transition-all border-2 flex items-center justify-center gap-3 shadow-lg active:scale-95 ${isLoading ? 'bg-slate-800 border-slate-700 text-slate-500 cursor-wait' : 'bg-indigo-600 border-indigo-500 text-white hover:bg-indigo-500 shadow-indigo-900/20'}`}
                    >
                        {isLoading ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <Icons.Refresh />}
                        {isLoading ? 'NAČÍTAVAM...' : 'NAČÍTAŤ ARCHÍV'}
                    </button>
                </div>
            </div>

            {/* ZOZNAM ARCHÍVOV */}
            <div className="space-y-4">
                {!hasLoaded ? (
                    <div className="py-32 text-center bg-slate-900/20 rounded-[3rem] border-2 border-dashed border-slate-800">
                        <div className="flex flex-col items-center gap-4">
                            <div className="p-4 bg-slate-800/50 rounded-full text-slate-600 animate-pulse"><Icons.Calendar /></div>
                            <p className="text-slate-600 font-black uppercase tracking-[0.3em] text-xs">Zvoľte obdobie a načítajte dáta</p>
                        </div>
                    </div>
                ) : sortedArchives.length > 0 ? (
                    sortedArchives.map(archive => {
                        const isExpanded = expandedSanonId === archive.id;
                        const items = archive.items || [];
                        const totalWeight = items.reduce((acc: number, curr: ScrapRecord) => acc + curr.netto, 0);
                        const totalValue = calculateSanonValue(items, archive.dispatchDate);
                        const externalValue = archive.externalValue || 0;
                        const displayDate = new Date(archive.dispatchDate).toLocaleDateString('sk-SK', { day: '2-digit', month: '2-digit', year: 'numeric' });

                        return (
                            <div key={archive.id} className="bg-slate-900/60 border border-slate-800 rounded-3xl overflow-hidden transition-all shadow-xl">
                                <div className="flex flex-col md:flex-row items-center w-full">
                                    <button 
                                        onClick={() => setExpandedSanonId(isExpanded ? null : archive.id)}
                                        className="flex-grow p-6 flex flex-col md:flex-row justify-between items-center gap-6 hover:bg-white/[0.02] transition-colors"
                                    >
                                        <div className="flex items-center gap-6">
                                            <div className="p-3 bg-slate-800 rounded-xl text-slate-400">
                                                <Icons.Calendar />
                                            </div>
                                            <div className="text-left">
                                                <p className="text-lg font-black text-white uppercase tracking-tight">{displayDate}</p>
                                                <p className="text-[10px] font-mono text-slate-500 uppercase tracking-widest">{archive.id}</p>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-10">
                                            <div className="text-center">
                                                <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-1">HMOTNOSŤ</p>
                                                <p className="text-xl font-black text-teal-400 font-mono">{totalWeight} <span className="text-xs font-normal text-slate-600">kg</span></p>
                                            </div>

                                            <div className="text-center border-l border-white/5 pl-10">
                                                <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-1">INTERNÝ ODHAD</p>
                                                <p className="text-xl font-black text-amber-400 font-mono">{totalValue.toLocaleString('sk-SK', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} <span className="text-xs font-normal text-slate-600">€</span></p>
                                            </div>

                                            <div className="text-center border-l border-white/5 pl-10">
                                                <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest mb-1">CENA ODBERATEĽA</p>
                                                <p className={`text-xl font-black font-mono ${externalValue > 0 ? 'text-green-500' : 'text-slate-700'}`}>
                                                    {externalValue > 0 ? externalValue.toLocaleString('sk-SK', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) : '---'} 
                                                    <span className="text-xs font-normal text-slate-600 ml-1">€</span>
                                                </p>
                                            </div>

                                            <div className={`transition-transform duration-300 ml-4 ${isExpanded ? 'rotate-180 text-teal-500' : 'text-slate-600'}`}>
                                                <Icons.ChevronDown />
                                            </div>
                                        </div>
                                    </button>

                                    <div className="p-4 md:border-l border-slate-800 flex justify-center items-center gap-2 w-full md:w-auto">
                                        {props.hasPermission('perm_scrap_edit') && (
                                            <button 
                                                onClick={() => handleOpenExternalValue(archive)}
                                                className="p-3 bg-amber-900/20 text-amber-500 hover:bg-amber-500 hover:text-white rounded-xl transition-all shadow-sm"
                                                title="Zadať cenu od odberateľa"
                                            >
                                                <Icons.Dollar />
                                            </button>
                                        )}
                                        <button 
                                            onClick={() => handleExportSanon(archive)}
                                            className="p-3 bg-emerald-900/20 text-emerald-500 hover:bg-emerald-500 hover:text-white rounded-xl transition-all shadow-sm"
                                            title="Export do Excelu"
                                        >
                                            <Icons.Download />
                                        </button>
                                        {props.hasPermission('perm_scrap_edit') && (
                                            <button 
                                                onClick={() => handleConfirmDeleteSanon(archive.id, displayDate)}
                                                className="p-3 bg-red-900/20 text-red-500 hover:bg-red-500 hover:text-white rounded-xl transition-all shadow-sm"
                                                title="Vymazať celý šanón"
                                            >
                                                <Icons.Trash />
                                            </button>
                                        )}
                                    </div>
                                </div>

                                {isExpanded && (
                                    <div className="p-6 pt-0 border-t border-slate-800/50 animate-fade-in bg-slate-950/20">
                                        <div className="overflow-x-auto custom-scrollbar">
                                            <table className="w-full text-left border-collapse">
                                                <thead>
                                                    <tr className="text-[9px] font-black text-slate-600 uppercase tracking-widest border-b border-slate-800">
                                                        <th className="py-4 px-4">Čas váženia</th>
                                                        <th className="py-4 px-4">Materiál</th>
                                                        <th className="py-4 px-4">Kontajner</th>
                                                        <th className="py-4 px-4 text-right">Netto (kg)</th>
                                                        {props.hasPermission('perm_scrap_edit') && <th className="py-4 px-4"></th>}
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-slate-800/30">
                                                    {(archive.items || []).map((item: ScrapRecord) => {
                                                        const metal = props.metals.find(m => m.id === item.metalId);
                                                        const bin = props.bins.find(b => b.id === item.binId);
                                                        return (
                                                            <tr key={item.id} className="text-sm hover:bg-white/[0.01] group">
                                                                <td className="py-4 px-4 text-slate-500 font-mono">{new Date(item.timestamp).toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' })}</td>
                                                                <td className="py-4 px-4 font-bold text-slate-300 uppercase">{metal?.type || '???'}</td>
                                                                <td className="py-4 px-4 text-slate-500 uppercase">{bin?.name || '???'}</td>
                                                                <td className="py-4 px-4 text-right font-black text-white font-mono">{item.netto} kg</td>
                                                                {props.hasPermission('perm_scrap_edit') && (
                                                                    <td className="py-4 px-4 text-right">
                                                                        <div className="flex gap-2 justify-end opacity-0 group-hover:opacity-100 transition-opacity">
                                                                            <button 
                                                                                onClick={() => handleOpenEdit(archive.id, item)}
                                                                                className="p-2 bg-slate-800 text-teal-500 hover:text-white hover:bg-teal-600 rounded-lg transition-all"
                                                                            >
                                                                                <Icons.Edit />
                                                                            </button>
                                                                            <button 
                                                                                onClick={() => handleConfirmDeleteItem(archive.id, item.id)}
                                                                                className="p-2 bg-slate-800 text-red-500 hover:text-white hover:bg-red-600 rounded-lg transition-all"
                                                                            >
                                                                                <Icons.Trash />
                                                                            </button>
                                                                        </div>
                                                                    </td>
                                                                )}
                                                            </tr>
                                                        );
                                                    })}
                                                </tbody>
                                            </table>
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })
                ) : (
                    <div className="py-32 text-center bg-slate-900/20 rounded-[3rem] border-2 border-dashed border-slate-800">
                        <Icons.Archive />
                        <p className="mt-4 text-slate-600 font-black uppercase tracking-[0.3em] text-sm">Žiadne záznamy pre vybraný filter.</p>
                    </div>
                )}
            </div>

            {/* MODAL: ZADANIE CENY ODBERATEĽA */}
            {isExternalValueModalOpen && createPortal(
                <div className="fixed inset-0 z-[12000] flex items-center justify-center bg-black/90 backdrop-blur-xl p-4 animate-fade-in" onClick={() => setIsExternalValueModalOpen(false)}>
